import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, X, ChevronLeft, ChevronRight, Volume2, VolumeX, ImageOff, PenTool } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'left' | 'right' | 'none'>('none');
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
    setDirection('none');
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel();
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const nextCard = useCallback(() => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setDirection('right');
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex, deck.length]);

  const prevCard = useCallback(() => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setDirection('left');
      setTimeout(() => {
        setCurrentIndex(prev => prev - 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      switch (e.key) {
        case 'ArrowRight': nextCard(); break;
        case 'ArrowLeft': prevCard(); break;
        case ' ':
        case 'Enter':
          if (document.activeElement?.tagName !== 'BUTTON') {
            e.preventDefault();
            flipCard();
          }
          break;
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [nextCard, prevCard, flipCard]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const currentCard = deck[currentIndex];

  return (
    <div className="flex flex-col max-w-5xl mx-auto w-full px-3 md:px-4 h-full focus:outline-none">

      <div className="flex-none mb-2 md:mb-4 flex justify-between items-center gap-2 md:gap-3 z-20">
        <div className="flex items-center gap-2 md:gap-3 flex-1 min-w-0">
            <div className="bg-white px-2.5 py-1.5 rounded-lg border border-slate-200 shadow-sm font-black text-slate-700 text-[10px] md:text-xs tracking-wider whitespace-nowrap">
            {deck.length > 0 ? `${currentIndex + 1} / ${deck.length}` : '0'}
            </div>

            <div className="relative flex-1 min-w-0">
                <Button 
                variant="ghost" 
                onClick={() => setIsFilterOpen(!isFilterOpen)}
                className={`flex items-center gap-1 md:gap-2 text-[10px] font-bold uppercase tracking-wider rounded-lg border h-8 px-2 md:px-3 transition-all focus:ring-2 focus:ring-blue-400 w-full md:w-auto justify-between md:justify-start ${selectedCategories.length > 0 ? 'bg-blue-50 text-blue-600 border-blue-200' : 'bg-white border-slate-200 text-slate-500'}`}
                >
                <div className="flex items-center gap-2 truncate">
                    <Filter size={12} className="shrink-0" />
                    <span className="truncate">{selectedCategories.length > 0 ? `${selectedCategories.length} Topics` : 'All Topics'}</span>
                </div>
                <ChevronDown size={10} className={`transition-transform shrink-0 ${isFilterOpen ? 'rotate-180' : ''}`} />
                </Button>

                {isFilterOpen && (
                <>
                    <div className="fixed inset-0 z-10" onClick={() => setIsFilterOpen(false)}></div>
                    <div className="absolute left-0 top-full mt-2 w-64 md:w-72 bg-white border border-slate-200 rounded-xl shadow-2xl z-50 flex flex-col max-h-[50vh] focus:outline-none">
                    <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center rounded-t-xl">
                        <span className="text-xs font-bold text-slate-500 uppercase">Select Chapters</span>
                        <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-red-500 hover:text-red-700">Reset All</button>
                    </div>
                    <div className="overflow-y-auto p-2 custom-scrollbar">
                        {categories.map(cat => (
                        <label key={cat} className="flex items-center gap-3 p-2.5 hover:bg-slate-50 rounded-lg cursor-pointer transition-colors group">
                            <div className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors ${selectedCategories.includes(cat) ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}>
                            {selectedCategories.includes(cat) && <Check size={10} className="text-white" />}
                            </div>
                            <span className="text-xs font-bold text-slate-700 leading-tight break-words">{cat}</span>
                            <input type="checkbox" className="hidden" checked={selectedCategories.includes(cat)} onChange={() => toggleCategory(cat)} />
                        </label>
                        ))}
                    </div>
                    </div>
                </>
                )}
            </div>
        </div>

        <Button 
            variant="ghost" 
            onClick={() => {
              const shuffled = [...deck].sort(() => Math.random() - 0.5);
              setDeck(shuffled);
              setCurrentIndex(0);
              setIsFlipped(false);
              setDirection('none');
            }} 
            className="h-8 px-2 md:px-3 text-[10px] font-bold text-slate-500 bg-white border border-slate-200 rounded-lg uppercase tracking-wider hover:text-blue-600 hover:border-blue-200 shrink-0"
        >
            <Shuffle size={12} className="md:mr-1" /> <span className="hidden md:inline">Shuffle</span>
        </Button>
      </div>

      <div className="flex-1 min-h-0 relative perspective-1000 z-10 group mb-4">
        {deck.length > 0 && currentCard ? (
            <div 
                key={currentCard.id}
                className={`w-full h-full relative transform-style-3d transition-all duration-500 ease-in-out cursor-pointer focus:outline-none focus:ring-4 focus:ring-blue-400/20 rounded-[2rem] ${isFlipped ? 'rotate-y-180' : ''} ${direction === 'right' ? 'animate-slide-in-right' : direction === 'left' ? 'animate-slide-in-left' : ''}`}
                onClick={flipCard}
                tabIndex={0}
            >
            <div className="absolute inset-0 w-full h-full bg-white rounded-[2rem] shadow-[0_4px_20px_rgb(0,0,0,0.05)] border-2 border-slate-100 backface-hidden flex flex-col overflow-hidden">
              <div className="px-4 py-3 md:px-6 md:pt-5 flex justify-between items-start flex-none">
                <span className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50 px-2.5 py-1 rounded-full border border-slate-100">Question</span>
                {hasSupport && (
                  <button onClick={(e) => handleAudio(e, currentCard.questionText, currentCard.id + 'q')} className={`p-1.5 md:p-2 rounded-full transition-colors ${isSpeaking && speakingId === currentCard.id + 'q' ? 'bg-red-100 text-red-600' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}>
                    {isSpeaking && speakingId === currentCard.id + 'q' ? <VolumeX size={14} /> : <Volume2 size={14} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-4 md:p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && (
                  <div className="mb-4 md:mb-6 flex-none flex flex-col items-center">
                    {!imgError ? (
                      <img 
                        src={currentCard.questionImage} 
                        className="max-h-[35vh] md:max-h-[45vh] w-auto object-contain rounded-lg mix-blend-multiply"
                        onError={() => setImgError(true)}
                        alt="Question Diagram"
                      />
                    ) : (
                      <div className="p-6 bg-red-50 rounded-2xl border-2 border-dashed border-red-200 flex flex-col items-center gap-3">
                         <ImageOff size={32} className="text-red-300" />
                         <span className="text-[10px] font-black text-red-400 uppercase">رابط الصورة معطل (Quizlet Protection)</span>
                         <button 
                          onClick={(e) => { e.stopPropagation(); if(onEdit) onEdit(currentCard.id); }}
                          className="px-4 py-2 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase flex items-center gap-2 hover:bg-red-700 transition-colors"
                         >
                           <PenTool size={12} /> إصلاح الرابط في الباني
                         </button>
                      </div>
                    )}
                  </div>
                )}
                <div className="text-base md:text-xl font-extrabold text-center text-slate-900 leading-snug" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
              </div>
            </div>

            <div className="absolute inset-0 w-full h-full bg-slate-900 rounded-[2rem] shadow-[0_20px_50px_rgb(15,23,42,0.3)] border border-slate-800 backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="px-4 py-3 md:px-6 md:pt-5 flex justify-between items-center flex-none">
                <span className="text-[9px] md:text-[10px] font-black uppercase text-emerald-400 tracking-[0.2em] bg-emerald-400/10 px-2.5 py-1 rounded-full border border-emerald-400/20">Answer</span>
                {hasSupport && (
                  <button onClick={(e) => handleAudio(e, currentCard.answerText + ". " + (currentCard.explanation || ""), currentCard.id + 'a')} className={`p-1.5 md:p-2 rounded-full transition-colors ${isSpeaking && speakingId === currentCard.id + 'a' ? 'bg-red-500/20 text-red-400' : 'bg-white/10 text-white/50 hover:bg-white/20'}`}>
                    {isSpeaking && speakingId === currentCard.id + 'a' ? <VolumeX size={14} /> : <Volume2 size={14} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-4 md:p-6 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.answerImage && (
                  <div className="mb-4 md:mb-6 flex-none flex flex-col items-center">
                    {!ansImgError ? (
                      <img 
                        src={currentCard.answerImage} 
                        className="max-h-[35vh] md:max-h-[45vh] w-auto object-contain rounded-lg"
                        onError={() => setAnsImgError(true)}
                        alt="Answer Diagram"
                      />
                    ) : (
                      <div className="p-4 bg-white/5 rounded-2xl border-2 border-dashed border-white/10 flex flex-col items-center gap-2">
                        <ImageOff size={24} className="text-white/20" />
                        <button onClick={(e) => { e.stopPropagation(); if(onEdit) onEdit(currentCard.id); }} className="text-[9px] font-black text-blue-400 uppercase hover:underline">إصلاح رابط صورة الإجابة</button>
                      </div>
                    )}
                  </div>
                )}
                <div className="text-base md:text-2xl font-bold text-center text-white leading-relaxed mb-4" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />
                {currentCard.explanation && (
                  <div className="bg-slate-800/50 p-3 md:p-4 rounded-xl border border-slate-700/50 text-slate-300 text-xs md:text-sm leading-relaxed max-w-lg text-center backdrop-blur-sm">
                    <span className="text-slate-500 font-bold uppercase text-[9px] md:text-[10px] tracking-widest block mb-1">Explanation</span>
                    <span dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                  </div>
                )}
              </div>
            </div>
          </div>
        ) : (
            <div className="w-full h-full flex flex-col items-center justify-center bg-white rounded-3xl border-2 border-dashed border-slate-300 text-slate-400 p-8 text-center">
                <Filter size={48} className="mb-4 opacity-20" />
                <p className="font-bold text-lg">No cards found in this filter.</p>
                <button onClick={() => setSelectedCategories([])} className="mt-2 text-blue-500 font-bold hover:underline">Reset Filters</button>
            </div>
        )}
      </div>

      <div className="flex-none flex items-center justify-center gap-3 md:gap-4 w-full mb-2">
        <button onClick={prevCard} disabled={currentIndex === 0} className="h-12 w-14 md:h-14 md:w-20 rounded-2xl bg-white border-2 border-slate-100 text-slate-400 hover:text-blue-600 hover:border-blue-200 hover:bg-blue-50 transition-all disabled:opacity-30 disabled:cursor-not-allowed flex items-center justify-center shrink-0 outline-none active:scale-95">
          <ChevronLeft size={24} className="md:w-7 md:h-7" />
