        <button onClick={flipCard} className="h-12 md:h-14 flex-1 max-w-xs rounded-2xl bg-slate-900 text-white font-black uppercase tracking-widest shadow-xl shadow-slate-900/20 hover:bg-blue-600 active:scale-95 transition-all flex items-center justify-center gap-3 text-[10px] md:text-xs">
          <RotateCw size={14} className={`md:w-4 md:h-4 ${isFlipped ? "-rotate-180 transition-transform duration-500" : "transition-transform duration-500"}`} />
