import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import { AppMode, Question } from './types';

// Modular Data Imports
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';

import { Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Vault Error", e);
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));
  }, [userVault]);

  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    userVault.forEach(q => {
        uniqueQuestions.push(q);
        seenIds.add(q.id);
    });

    const systemSources = [...ch1, ...ch3, ...ch4, ...ch6, ...ch7, ...ch8, ...ch9, ...ch10, ...ch11];
    systemSources.forEach(q => {
        if (!seenIds.has(q.id)) {
            uniqueQuestions.push(q);
            seenIds.add(q.id);
        }
    });
    return uniqueQuestions;
  }, [userVault]);

  const categories = useMemo(() => {
    const cats = new Set(allQuestions.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [allQuestions]);

  const exportVault = () => {
    const dataStr = JSON.stringify(userVault, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const link = document.createElement('a');
    link.setAttribute('href', dataUri);
    link.setAttribute('download', `ANATOMY_VAULT_BACKUP.json`);
    link.click();
  };

  const importVault = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = JSON.parse(e.target?.result as string) as Question[];
        if (Array.isArray(imported)) {
          setUserVault(prev => {
            const currentMap = new Map(prev.map(q => [q.id, q]));
            imported.forEach(q => currentMap.set(q.id, q));
            return Array.from(currentMap.values());
          });
          alert("Import Successful.");
        }
      } catch (err) { alert("Format Error."); }
    };
    reader.readAsText(file);
  };

  const handleEditRequest = (id: string) => {
    setEditingId(id);
    setCurrentMode(AppMode.BUILDER);
  };

  const handleSaveQuestion = (question: Question) => {
    setUserVault(prev => {
        const existingIndex = prev.findIndex(q => q.id === question.id);
        if (existingIndex >= 0) {
            const newVault = [...prev];
            newVault[existingIndex] = question;
            return newVault;
        } else return [question, ...prev];
    });
    if (editingId) {
      setEditingId(null);
      setCurrentMode(AppMode.LIST);
    } else alert("Saved successfully!");
  };

  return (
    <div className="h-[100dvh] bg-slate-50 flex flex-col font-sans text-slate-900 overflow-hidden">
      <Header currentMode={currentMode} onModeChange={(m) => { setCurrentMode(m); setEditingId(null); }} />
      <main className="flex-1 relative overflow-hidden flex flex-col">
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full py-4 md:py-6 overflow-hidden"><Flashcards data={allQuestions} onEdit={handleEditRequest} /></div>
        )}
        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full overflow-hidden"><Quiz data={allQuestions} onEdit={handleEditRequest} /></div>
        )}
        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto py-4 md:py-6">
            <QuestionList data={allQuestions} onExport={exportVault} onImport={importVault} onEdit={handleEditRequest} />
            <div className="flex justify-center mt-12 mb-8">
               <button onClick={() => confirm("Clear all edits?") && setUserVault([])} className="flex items-center gap-2 text-xs font-bold text-red-400 hover:text-red-600 uppercase tracking-widest opacity-60">
                 <Trash2 size={14} /> Factory Reset
               </button>
            </div>
          </div>
        )}
        {currentMode === AppMode.BUILDER && (
          <div className="flex-1 h-full overflow-y-auto">
            <QuestionBuilder allQuestions={allQuestions} editingId={editingId} onSave={handleSaveQuestion} onCancel={() => { setEditingId(null); setCurrentMode(AppMode.LIST); }} existingCategories={categories} />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

