  uri: string;
}

const QuestionBuilder: React.FC<QuestionBuilderProps> = ({ allQuestions, editingId, onSave, onCancel, existingCategories }) => {
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [rawInput, setRawInput] = useState('');
  const [showPreview, setShowPreview] = useState(false);
  const [isManualEdit, setIsManualEdit] = useState(false);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [loadingStep, setLoadingStep] = useState<string>('');
  const [activeTab, setActiveTab] = useState<'create' | 'repair'>('create');

  // Repair State
  const [isBatchRepairing, setIsBatchRepairing] = useState(false);
  const [batchStatus, setBatchStatus] = useState({ current: 0, total: 0 });

  const [formData, setFormData] = useState<Omit<Question, 'id'>>({
    category: '',
    questionText: '',
    answerText: '',
    explanation: '',
    questionImage: '',
    answerImage: '',
    options: []
  });

  const missingOptionsCount = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4).length;
  }, [allQuestions]);

  const questionsToRepair = useMemo(() => {
    return allQuestions.filter(q => !q.options || q.options.length < 4);
  }, [allQuestions]);

  useEffect(() => {
    if (editingId) {
      const q = allQuestions.find(item => item.id === editingId);
      if (q) {
        setFormData({
          category: q.category,
          questionText: q.questionText,
          answerText: q.answerText,
          explanation: q.explanation || '',
          questionImage: q.questionImage || '',
          answerImage: q.answerImage || '',
          options: q.options || []
        });
        setShowPreview(true);
        setActiveTab('create');
      }
    }
  }, [editingId, allQuestions]);

  const handleApiKeyCheck = async () => {
    if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  };

  const processEverythingWithAI = async () => {
    if (!rawInput.trim()) return;

    setIsAiLoading(true);
    setSources([]);
    setLoadingStep('Initializing Neural Engine...');

    try {
      const isUrl = /^(https?:\/\/[^\s]+)$/.test(rawInput.trim());

      if (isUrl) {
        setLoadingStep('Authenticating Secure API Link...');
        await handleApiKeyCheck();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const modelName = isUrl ? "gemini-3-pro-preview" : "gemini-3-flash-preview";

      setLoadingStep(isUrl ? 'Navigating Web Sources...' : 'Analyzing Anatomical Data...');

      const prompt = isUrl 
        ? `TASK: Web Content Extraction.
           URL: "${rawInput.trim()}"
           INSTRUCTION: Use Google Search to access this page. Extract or generate ONE professional anatomical quiz question based exclusively on the content of this page.

           REQUIRED OUTPUT FORMAT (JSON ONLY):
           {
             "questionText": "Clear question using <b> for key terms",
             "answerText": "Precise correct answer",
             "explanation": "Scientific rationale formatted with HTML tags",
             "options": ["Correct Answer", "Distractor 1", "Distractor 2", "Distractor 3"],
             "category": "Identify the anatomical system/chapter",
             "questionImage": "Direct URL to a relevant image on the page if found"
           }`
        : `TASK: Text/HTML Synthesis.
           INPUT: """${rawInput}"""
           INSTRUCTION: Extract one anatomical quiz question from the provided input. Provide 3 high-quality distractors that are similar to the answer.

           RETURN JSON:
           {
             "questionText": "...",
             "answerText": "...",
             "explanation": "...",
             "options": ["...", "...", "...", "..."],
             "category": "...",
             "questionImage": "..."
           }`;

      const response = await ai.models.generateContent({
        model: modelName,
        contents: prompt,
        config: {
          responseMimeType: isUrl ? undefined : "application/json",
          tools: isUrl ? [{ googleSearch: {} }] : undefined,
          responseSchema: isUrl ? undefined : {
            type: Type.OBJECT,
            properties: {
              questionText: { type: Type.STRING },
              answerText: { type: Type.STRING },
              explanation: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              category: { type: Type.STRING },
              questionImage: { type: Type.STRING }
            },
            required: ["questionText", "answerText", "explanation", "options", "category"]
          }
        }
      });

      setLoadingStep('Validating Structured Output...');

      // Extracting URLs from groundingChunks as per mandatory Gemini API guidelines
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (groundingChunks) {
        const extractedSources: GroundingSource[] = groundingChunks
          .filter((chunk: any) => chunk.web)
          .map((chunk: any) => ({
            title: chunk.web.title || 'Verified Source',
            uri: chunk.web.uri
          }));
        setSources(extractedSources);
      }

      const rawText = response.text || "";
      const jsonMatch = rawText.match(/\{[\s\S]*\}/);

      if (!jsonMatch) {
        throw new Error("No valid JSON architecture found in model response.");
      }

      const result = JSON.parse(jsonMatch[0]);

      setFormData({
        ...result,
        questionImage: result.questionImage || formData.questionImage || '',
        answerImage: formData.answerImage || '',
        options: Array.isArray(result.options) ? [...result.options].sort(() => Math.random() - 0.5) : []
      });

      setLoadingStep('Success! Rendering Preview...');
      setTimeout(() => {
        setShowPreview(true);
        setRawInput('');
        setIsAiLoading(false);
      }, 800);

    } catch (error: any) {
      console.error("Architectural Failure:", error);
      setIsAiLoading(false);
      alert("The AI Architect encountered an error. This usually happens if the URL is blocked or the content is too sparse.");
    }
  };

  const repairQuestion = async (q: Question) => {
    setIsAiLoading(true);
    setLoadingStep(`Repairing: ${q.id}...`);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `TASK: Anatomy Question Distractor Generation.
      QUESTION: "${q.questionText}"
      CORRECT ANSWER: "${q.answerText}"
      INSTRUCTION: Generate 3 medically accurate, plausible "close" distractors (wrong options) for this question. 
      Return the result as a JSON array of 4 strings (including the correct answer).

      RETURN JSON:
      {
        "options": ["Correct Answer", "Similar Wrong 1", "Similar Wrong 2", "Similar Wrong 3"]
      }`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              options: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["options"]
          }
        }
      });

      // Safely access response.text property (not a method)
      const result = JSON.parse(response.text || "{}");
      const repairedQ = { ...q, options: result.options.sort(() => Math.random() - 0.5) };
      onSave(repairedQ);
      setIsAiLoading(false);
      setLoadingStep('');
    } catch (e) {
      console.error("Repair failed", e);
      setIsAiLoading(false);
      alert("Failed to repair question.");
    }
  };

  const startBatchRepair = async () => {
    if (questionsToRepair.length === 0) return;
    if (!confirm(`Are you sure you want to attempt batch repair on ${questionsToRepair.length} questions? This will use the AI API for each.`)) return;

    setIsBatchRepairing(true);
    // Initialize batch count and total locally
    const totalCount = questionsToRepair.length;
    setBatchStatus({ current: 0, total: totalCount });

    // Initialize GoogleGenAI with environment key
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    let count = 0;
    for (const q of questionsToRepair) {
        count++;
        // Use local variables to track status
        setBatchStatus({ current: count, total: totalCount });
        setLoadingStep(`Optimizing: ${count}/${totalCount}`);

        try {
            const prompt = `TASK: Anatomy Question Distractor Generation.
            QUESTION: "${q.questionText}"
            CORRECT ANSWER: "${q.answerText}"
            RETURN JSON: { "options": ["Correct", "Wrong1", "Wrong2", "Wrong3"] }`;

            const response = await ai.models.generateContent({
                model: "gemini-3-flash-preview",
                contents: prompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            options: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["options"]
                    }
                }
            });

            // response.text is a property per current SDK guidelines
            const result = JSON.parse(response.text || "{}");
            const repairedQ = { ...q, options: result.options.sort(() => Math.random() - 0.5) };
            onSave(repairedQ);

            // Artificial delay to prevent rate limiting
            await new Promise(r => setTimeout(r, 500));
        } catch (e) {
            console.error("Batch failure for:", q.id, e);
        }
    }

    setIsBatchRepairing(false);
    alert("Batch Optimization Complete.");
  };

  const handleGlobalPublish = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.questionText || !formData.answerText) return;

    const finalQuestion: Question = {
      id: editingId || `global-q-${Date.now()}`,
      ...formData
    };
    onSave(finalQuestion);
    resetSystem();
  };

  const resetSystem = () => {
    setShowPreview(false);
    setIsManualEdit(false);
    setSources([]);
    setLoadingStep('');
    setFormData({
      category: '',
      questionText: '',
      answerText: '',
      explanation: '',
      questionImage: '',
      answerImage: '',
      options: []
    });
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-12 space-y-12 pb-48 animate-in fade-in duration-1000">

      {!showPreview && (
        <div className="flex justify-center mb-8">
          <div className="bg-slate-900/50 p-1 rounded-2xl border border-slate-800 backdrop-blur-xl flex gap-1">
             <button 
              onClick={() => setActiveTab('create')}
              className={`px-8 py-3 rounded-xl font-black text-sm uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'create' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
             >
               <Plus size={18} /> Builder
             </button>
             <button 
              onClick={() => setActiveTab('repair')}
              className={`px-8 py-3 rounded-xl font-black text-sm uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'repair' ? 'bg-purple-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
             >
               <RefreshCw size={18} /> Vault Repair 
               {missingOptionsCount > 0 && <span className="ml-1 px-1.5 py-0.5 bg-red-500 text-[10px] rounded-full">{missingOptionsCount}</span>}
             </button>
          </div>
        </div>
      )}

      {activeTab === 'repair' && !showPreview && (
        <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-bottom-4 duration-500">
           <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 p-10 md:p-16 space-y-10 shadow-3xl overflow-hidden relative">
              <div className="absolute top-0 right-0 p-12 text-purple-500/5 -rotate-12">
                 <RefreshCw size={240} />
              </div>

              <div className="relative z-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div className="space-y-4">
                  <h2 className="text-4xl md:text-5xl font-black text-white tracking-tighter">Vault <span className="text-purple-500">Optimizer</span></h2>
                  <p className="text-slate-400 font-bold uppercase tracking-[0.2em] text-xs">AI-Powered Question Enhancement Engine</p>
                </div>

                {missingOptionsCount > 0 && (
                  <button 
                    onClick={startBatchRepair}
                    disabled={isBatchRepairing}
                    className="px-8 py-4 bg-purple-600 hover:bg-purple-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 shadow-xl transition-all hover:-translate-y-1 active:scale-95 disabled:opacity-50"
                  >
                    {isBatchRepairing ? <Loader2 size={18} className="animate-spin" /> : <Zap size={18} />}
                    Start Batch Repair
                  </button>
                )}
              </div>

              {missingOptionsCount === 0 ? (
                <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-3xl p-12 text-center space-y-4">
                   <div className="w-16 h-16 bg-emerald-500 rounded-full flex items-center justify-center mx-auto shadow-lg shadow-emerald-500/20">
                      <CheckCircle2 size={32} className="text-white" />
                   </div>
                   <h3 className="text-white font-black text-xl">All Questions Fully Structured</h3>
                   <p className="text-slate-400 text-sm">Every question in your registry has 4 options and valid metadata.</p>
                </div>
              ) : (
                <div className="space-y-6">
                   {isBatchRepairing && (
                      <div className="bg-purple-600/10 border border-purple-500/30 rounded-3xl p-8 space-y-4 animate-pulse">
                         <div className="flex justify-between items-center text-purple-400 font-black text-xs uppercase tracking-widest">
                            <span>Matrix Normalization in Progress</span>
                            <span>{batchStatus.current} / {batchStatus.total}</span>
                         </div>
                         <div className="h-3 w-full bg-slate-800 rounded-full overflow-hidden">
                            <div 
                                className="h-full bg-purple-500 transition-all duration-500" 
                                style={{ width: `${(batchStatus.current / batchStatus.total) * 100}%` }}
                            ></div>
                         </div>
                      </div>
                   )}

                   <div className="bg-white/5 rounded-3xl border border-white/10 p-8 flex items-center justify-between">
                      <div className="flex items-center gap-6">
                        <div className="w-14 h-14 bg-purple-600 rounded-2xl flex items-center justify-center shadow-xl text-white">
                          <Activity size={28} />
                        </div>
                        <div>
                          <span className="block text-2xl font-black text-white">{missingOptionsCount}</span>
                          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Questions Need Repair</span>
                        </div>
                      </div>
                      <div className="text-right">
                         <span className="text-[10px] font-black text-purple-400 uppercase tracking-widest block mb-1">Structural Health</span>
                         <div className="h-2 w-32 bg-slate-800 rounded-full overflow-hidden">
                            <div 
                                className="h-full bg-purple-500" 
                                style={{ width: `${Math.max(10, 100 - (missingOptionsCount / allQuestions.length) * 100)}%` }}
                            ></div>
                         </div>
                      </div>
                   </div>

                   <div className="grid gap-4">
                      {questionsToRepair.slice(0, 10).map((q) => (
                        <div key={q.id} className="bg-slate-950/50 border border-slate-800 rounded-2xl p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 group hover:border-purple-500/30 transition-all">
                           <div className="flex-1 min-w-0">
                              <span className="text-[9px] font-black text-purple-500 uppercase tracking-[0.2em] mb-2 block">{q.category}</span>
                              <h4 className="text-slate-300 font-bold text-lg truncate" dangerouslySetInnerHTML={{ __html: q.questionText }}></h4>
                              <p className="text-slate-500 text-xs mt-1 italic">Target: {q.answerText}</p>
                           </div>
                           <button 
                             onClick={() => repairQuestion(q)}
                             disabled={isAiLoading || isBatchRepairing}
                             className="flex items-center gap-3 px-6 py-3 bg-purple-600 hover:bg-purple-500 text-white rounded-xl font-black text-xs uppercase tracking-widest transition-all shadow-lg hover:-translate-y-1 disabled:opacity-20"
                           >
                             <Wand2 size={16} /> Precision Fix
                           </button>
                        </div>
                      ))}
                   </div>

                   {missingOptionsCount > 10 && (
                     <p className="text-center text-[10px] font-bold text-slate-500 uppercase tracking-[0.3em]">Showing first 10 structural anomalies</p>
                   )}
                </div>
              )}
           </div>

           {(isAiLoading || isBatchRepairing) && (
              <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-xl flex flex-col items-center justify-center p-8 animate-in fade-in duration-300">
                <div className="relative mb-8">
                  <div className="w-24 h-24 border-4 border-purple-500/20 border-t-purple-500 rounded-full animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center">
                    <Cpu className="text-purple-400 animate-pulse" size={32} />
                  </div>
                </div>
                <h3 className="text-2xl font-black text-white tracking-tight text-center">{loadingStep}</h3>
                <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-4">Generating contextually relevant anatomical distractors...</p>
              </div>
           )}
        </div>
      )}

      {/* PHASE 1: THE INPUT COMMAND CENTER */}
      {activeTab === 'create' && !showPreview && (
        <div className="relative max-w-5xl mx-auto pt-4">
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-full bg-blue-600/10 rounded-full blur-[160px] pointer-events-none"></div>

          <div className="relative bg-slate-900 rounded-[3.5rem] shadow-[0_40px_100px_rgba(0,0,0,0.5)] border border-slate-800/80 backdrop-blur-2xl overflow-hidden">
            <div className="p-8 md:p-20 space-y-12">

              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-10">
                <div className="space-y-4">
                  <div className="flex items-center gap-5">
                    <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl shadow-2xl flex items-center justify-center text-white ring-4 ring-blue-50/20 transform rotate-3">
                      <Zap size={32} className="animate-pulse" />
                    </div>
                    <div>
                      <h2 className="text-4xl md:text-6xl font-black text-white tracking-tighter leading-none">
                        AI <span className="text-blue-500">Architect</span>
                      </h2>
                      <p className="text-slate-500 font-bold text-xs uppercase tracking-[0.4em] mt-3">Professional Data Extraction Suite</p>
                    </div>
                  </div>
                </div>

                <div className="hidden md:flex items-center gap-4 bg-slate-950/50 p-4 rounded-3xl border border-slate-800/50">
                   <div className="flex flex-col items-end">
                      <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">Neural Link: Active</span>
                      <span className="text-xs font-bold text-slate-300">Gemini 3 Pro + Search</span>
                   </div>
                   <div className="w-12 h-12 rounded-2xl border-2 border-slate-800 flex items-center justify-center bg-slate-900 shadow-inner">
                      <div className="w-3 h-3 bg-emerald-500 rounded-full shadow-[0_0_15px_rgba(16,185,129,0.5)] animate-ping"></div>
                   </div>
                </div>
              </div>

              <div className="relative group">
                {isAiLoading && (
                  <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-slate-900/90 backdrop-blur-md rounded-[2.5rem] border-2 border-blue-500/30 animate-in zoom-in-95 duration-300">
                    <div className="relative">
                      <div className="w-24 h-24 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin"></div>
                      <div className="absolute inset-0 flex items-center justify-center">
                        <Cpu className="text-blue-400 animate-pulse" size={32} />
                      </div>
                    </div>
                    <div className="mt-8 text-center space-y-3">
                      <p className="text-xl font-black text-white tracking-tight">{loadingStep}</p>
                      <div className="flex items-center gap-2 justify-center">
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce"></span>
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                      </div>
                    </div>
                  </div>
                )}

                <div className="absolute -inset-2 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-[2.5rem] blur opacity-10 group-hover:opacity-20 transition duration-1000"></div>

                <div className="relative">
                  <textarea
                    value={rawInput}
                    onChange={(e) => setRawInput(e.target.value)}
                    className="w-full h-80 p-12 bg-slate-950/60 text-blue-50 rounded-[2.5rem] border-2 border-slate-800 focus:border-blue-500 outline-none font-medium text-2xl placeholder:text-slate-700 transition-all shadow-inner resize-none custom-scrollbar"
                    placeholder="Paste URL (e.g. kenhub.com/en/skull) or copy-paste anatomy notes here..."
                  />
                  <div className="absolute bottom-6 right-8 flex items-center gap-2 text-slate-700 font-black text-[10px] uppercase tracking-widest pointer-events-none">
                    <Terminal size={14} /> Neural Input Interface v4.2
                  </div>
                </div>

                <div className="flex flex-col md:flex-row items-center justify-between gap-8 mt-10">
                  <div className="flex items-center gap-10">
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Grounding Tool</span>
                      <span className="text-sm font-bold text-white flex items-center gap-2 mt-1">
                        <Globe size={16} className="text-blue-500" /> Web-to-Vault Sync
                      </span>
                    </div>
                    <div className="w-px h-10 bg-slate-800"></div>
                    <div className="flex flex-col">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Output Logic</span>
                      <span className="text-sm font-bold text-white flex items-center gap-2 mt-1">
                        <FileCode size={16} className="text-indigo-500" /> Structural JSON
                      </span>
                    </div>
                  </div>

                  <button 
                    onClick={processEverythingWithAI}
                    disabled={isAiLoading || !rawInput.trim()}
                    className="w-full md:w-auto flex items-center justify-center gap-5 px-16 py-8 bg-blue-600 text-white rounded-[2.5rem] font-black text-3xl hover:bg-blue-500 hover:-translate-y-2 transition-all shadow-[0_20px_60px_rgba(37,99,235,0.4)] disabled:opacity-20 active:scale-95 group relative overflow-hidden"
                  >
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                    <Wand2 size={36} className="group-hover:rotate-12 transition-transform" />
                    <span>Generate Question</span>
                  </button>
                </div>
              </div>
            </div>

            <div className="h-2.5 bg-gradient-to-r from-blue-600 via-indigo-600 to-blue-600"></div>
          </div>
        </div>
      )}

      {/* PHASE 2: THE PUBLISHING AND REVIEW STAGE */}
      {showPreview && (
        <div className="max-w-6xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom-20 duration-1000">

          <div className="flex flex-col md:flex-row justify-between items-center gap-8 bg-white p-8 rounded-[3rem] border border-slate-200 shadow-2xl">
            <div className="flex items-center gap-6">
              <button 
                onClick={resetSystem} 
                className="w-16 h-16 rounded-2xl bg-slate-50 text-slate-400 hover:text-red-500 hover:bg-red-50 transition-all flex items-center justify-center shadow-inner"
                title="Discard Blueprint"
              >
                <RotateCcw size={28} />
              </button>
              <div className="h-12 w-px bg-slate-100"></div>
              <div>
                <h3 className="text-2xl font-black text-slate-900 leading-tight">Blueprint Review</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Staging Area: Pending Vault Publish</p>
              </div>
            </div>

            <div className="flex items-center gap-5 w-full md:w-auto">
              <button 
                onClick={() => setIsManualEdit(!isManualEdit)} 
                className={`flex-1 md:flex-none px-10 py-5 rounded-[1.5rem] font-black text-base transition-all flex items-center justify-center gap-3 border-2 ${isManualEdit ? 'bg-slate-900 text-white border-slate-900 shadow-xl' : 'bg-white text-slate-600 border-slate-200 hover:border-blue-500'}`}
              >
                {isManualEdit ? <Eye size={22} /> : <Edit3 size={22} />}
                {isManualEdit ? 'Render View' : 'Manual Overrides'}
              </button>

              <button 
