import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, X, ChevronLeft, ChevronRight, Volume2, VolumeX, ImageOff, PenTool } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [direction, setDirection] = useState<'left' | 'right' | 'none'>('none');
  const [imgError, setImgError] = useState(false);
  const [ansImgError, setAnsImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    setAnsImgError(false);
    cancel();
  }, [currentIndex, deck, cancel]);

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const nextCard = useCallback(() => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setDirection('right');
      setTimeout(() => {
        setCurrentIndex(prev => prev + 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex, deck.length]);

  const prevCard = useCallback(() => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setDirection('left');
      setTimeout(() => {
        setCurrentIndex(prev => prev - 1);
        setDirection('none');
      }, 150);
    }
  }, [currentIndex]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) cancel();
    else speak(text, id);
  };

  const currentCard = deck[currentIndex];

  return (
    <div className="flex flex-col h-full w-full max-w-4xl mx-auto px-2 pb-2 overflow-hidden">

      {/* Controls Bar */}
      <div className="flex justify-between items-center gap-2 mb-2 pt-2 shrink-0">
        <div className="flex items-center gap-2 flex-1">
          <div className="bg-white border px-2 py-1 rounded-lg font-black text-[10px] text-slate-500">
            {currentIndex + 1}/{deck.length}
          </div>
          <button 
            onClick={() => setIsFilterOpen(!isFilterOpen)}
            className="flex items-center gap-1.5 px-3 py-1 bg-white border rounded-lg text-[10px] font-bold uppercase text-slate-600 overflow-hidden"
          >
            <Filter size={12} />
            <span className="truncate max-w-[80px]">
              {selectedCategories.length > 0 ? `${selectedCategories.length} Topics` : 'All'}
            </span>
          </button>
        </div>

        <button 
          onClick={() => setDeck([...deck].sort(() => Math.random() - 0.5))}
          className="p-1.5 bg-white border rounded-lg text-slate-500"
        >
          <Shuffle size={14} />
        </button>
      </div>

      {/* Filters Modal */}
      {isFilterOpen && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-300">
            <div className="p-4 border-b flex justify-between items-center bg-slate-50">
              <span className="font-black text-xs uppercase text-slate-500">Filter Library</span>
              <button onClick={() => setIsFilterOpen(false)} className="p-1 hover:bg-slate-200 rounded-full"><X size={20} /></button>
            </div>
            <div className="p-2 max-h-[60vh] overflow-y-auto">
              {categories.map(cat => (
                <label key={cat} className="flex items-center gap-3 p-3 hover:bg-blue-50 rounded-xl cursor-pointer">
                  <input 
                    type="checkbox" 
                    className="w-5 h-5 rounded border-slate-300 text-blue-600 focus:ring-blue-500" 
                    checked={selectedCategories.includes(cat)}
                    onChange={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
                  />
                  <span className="text-sm font-bold text-slate-700">{cat}</span>
                </label>
              ))}
            </div>
            <div className="p-4 bg-slate-50">
              <button onClick={() => setIsFilterOpen(false)} className="w-full py-3 bg-slate-900 text-white rounded-xl font-black uppercase text-xs">Apply Filters</button>
            </div>
          </div>
        </div>
      )}

      {/* The Card Container - Height Adjusted for Mobile */}
      <div className="flex-1 relative perspective-1000 group mb-3">
        {deck.length > 0 && currentCard ? (
          <div 
            className={`w-full h-full relative transform-style-3d transition-all duration-500 ease-out cursor-pointer ${isFlipped ? 'rotate-y-180' : ''} ${direction === 'right' ? 'animate-slide-in-right' : direction === 'left' ? 'animate-slide-in-left' : ''}`}
            onClick={flipCard}
          >
            {/* Front Side */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-[2rem] shadow-sm border-2 border-slate-100 backface-hidden flex flex-col overflow-hidden">
              <div className="p-4 flex justify-between items-center shrink-0 border-b border-slate-50 bg-slate-50/50">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Question</span>
                {hasSupport && (
                  <button onClick={(e) => handleAudio(e, currentCard.questionText, currentCard.id + 'q')} className="p-1.5 rounded-full bg-white border text-slate-400">
                    {isSpeaking && speakingId === currentCard.id + 'q' ? <VolumeX size={14} /> : <Volume2 size={14} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-5 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && (
                  <div className="mb-4 w-full flex flex-col items-center shrink-0">
                    {!imgError ? (
                      <img 
                        src={currentCard.questionImage} 
                        className="max-h-[30vh] w-auto object-contain rounded-xl mix-blend-multiply"
                        onError={() => setImgError(true)}
                      />
                    ) : (
                      <div className="w-full max-w-[240px] p-4 bg-rose-50 rounded-2xl border border-dashed border-rose-200 flex flex-col items-center gap-2">
                         <ImageOff size={24} className="text-rose-300" />
                         <span className="text-[9px] font-black text-rose-400 uppercase text-center leading-tight">Image Blocked by Quizlet</span>
                         <button onClick={(e) => { e.stopPropagation(); onEdit?.(currentCard.id); }} className="text-[9px] font-black text-blue-600 uppercase underline">Replace in Builder</button>
                      </div>
                    )}
                  </div>
                )}
                <div className="text-base md:text-xl font-extrabold text-center text-slate-800 leading-snug px-2" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
              </div>
            </div>

            {/* Back Side */}
            <div className="absolute inset-0 w-full h-full bg-slate-900 rounded-[2rem] shadow-2xl border border-slate-800 backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="p-4 flex justify-between items-center shrink-0 bg-slate-800/50">
                <span className="text-[9px] font-black uppercase text-emerald-400 tracking-widest">Correct Response</span>
                {hasSupport && (
                  <button onClick={(e) => handleAudio(e, currentCard.answerText, currentCard.id + 'a')} className="p-1.5 rounded-full bg-white/10 text-white/50">
                    {isSpeaking && speakingId === currentCard.id + 'a' ? <VolumeX size={14} /> : <Volume2 size={14} />}
                  </button>
                )}
              </div>

              <div className="flex-1 p-5 flex flex-col items-center justify-center overflow-y-auto custom-scrollbar">
                <div className="text-lg md:text-2xl font-bold text-center text-white leading-tight mb-4" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />
                {currentCard.explanation && (
                  <div className="bg-white/5 p-4 rounded-2xl border border-white/10 text-slate-400 text-xs text-center max-w-sm" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                )}
              </div>
            </div>
          </div>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center bg-white rounded-[2.5rem] border-2 border-dashed border-slate-200">
             <ImageOff className="text-slate-200 mb-4" size={48} />
             <p className="font-bold text-slate-400">No cards matched your filter.</p>
          </div>
        )}
      </div>

      {/* Navigation Buttons - Oversized for Touch */}
      <div className="flex items-center justify-center gap-3 shrink-0">
        <button onClick={prevCard} disabled={currentIndex === 0} className="h-14 w-16 rounded-2xl bg-white border shadow-sm flex items-center justify-center disabled:opacity-20 active:bg-slate-100">
          <ChevronLeft size={28} />
        </button>
        <button onClick={flipCard} className="h-14 flex-1 rounded-2xl bg-slate-900 text-white font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl active:scale-95">
          <RotateCw size={16} /> {isFlipped ? 'Question' : 'Show Answer'}
        </button>
        <button onClick={nextCard} disabled={currentIndex === deck.length - 1} className="h-14 w-16 rounded-2xl bg-white border shadow-sm flex items-center justify-center disabled:opacity-20 active:bg-slate-100">
          <ChevronRight size={28} />
        </button>
      </div>
    </div>
  );
};

export default Flashcards;

