const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes' | 'flashcard'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [imgError, setImgError] = useState(false);

  const [questionCount, setQuestionCount] = useState(25);
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [shuffleQuestions, setShuffleQuestions] = useState(true);
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);

  useEffect(() => {
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) setMistakesHistory(JSON.parse(savedMistakes));
  }, []);

  useEffect(() => { setImgError(false); setIsFlipped(false); }, [currentQIndex]);

  const maxPossibleQuestions = useMemo(() => {
    return data.filter(q => {
      if (showImagesOnly && !q.questionImage) return false;
      if (selectedGroups.length > 0 && !selectedGroups.includes(q.category)) return false;
      return true;
    }).length;
  }, [data, selectedGroups, showImagesOnly]);

  const startQuiz = () => {
    let pool = data.filter(q => (!showImagesOnly || q.questionImage));
    if (selectedGroups.length > 0) pool = pool.filter(q => selectedGroups.includes(q.category));
    if (pool.length === 0) return alert("No questions found.");

    const count = Math.min(questionCount, pool.length);
    let selected = [...pool].sort(() => shuffleQuestions ? Math.random() - 0.5 : 0).slice(0, count);

    const generated = selected.map(q => {
      const correct = q.answerText;
      let options = [...(q.options || []), correct];
      options = Array.from(new Set(options)).sort(() => Math.random() - 0.5).slice(0, 4);
      while(options.length < 4) options.push(`Distractor ${options.length}`);
      return { id: q.id, data: q, options, correctOption: correct, userAnswer: null, isFlagged: false } as QuizQuestion;
    });

    setQuestions(generated);
    setCurrentQIndex(0);
    setTimeLeft(count * 60);
    setView('playing');
  };

  const handleAnswer = (option: string) => {
    if (view === 'review' || questions[currentQIndex].userAnswer) return;
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-50 overflow-y-auto p-3 md:p-8 flex flex-col items-center">
        <div className="w-full max-w-2xl bg-white rounded-3xl shadow-xl border overflow-hidden">
          <div className="bg-slate-900 p-5 text-white flex justify-between items-center">
            <h1 className="text-xl font-black flex items-center gap-2"><BrainCircuit className="text-blue-500" /> Exam Setup</h1>
            <span className="text-[10px] font-bold bg-white/10 px-2 py-1 rounded-lg">{maxPossibleQuestions} Ready</span>
          </div>

          <div className="p-5 space-y-6">
            <div className="grid grid-cols-2 gap-2">
              {['exam', 'practice'].map(m => (
                <button 
                  key={m} 
                  onClick={() => setMode(m as any)}
                  className={`py-4 rounded-2xl border-2 font-black uppercase text-[10px] tracking-widest transition-all ${mode === m ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-400'}`}
                >
                  {m} Mode
                </button>
              ))}
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <label className="text-[10px] font-black uppercase text-slate-400">Questions: {questionCount}</label>
              </div>
              <input type="range" min="1" max={Math.max(1, maxPossibleQuestions)} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-blue-600" />
            </div>

            <div className="flex gap-2">
              <button onClick={() => setShowImagesOnly(!showImagesOnly)} className={`flex-1 p-3 rounded-xl border text-[10px] font-black uppercase transition-all ${showImagesOnly ? 'bg-blue-600 text-white' : 'bg-slate-50 text-slate-500'}`}>Images Only</button>
              <button onClick={() => setShuffleQuestions(!shuffleQuestions)} className={`flex-1 p-3 rounded-xl border text-[10px] font-black uppercase transition-all ${shuffleQuestions ? 'bg-purple-600 text-white' : 'bg-slate-50 text-slate-500'}`}>Shuffle</button>
            </div>

            <button onClick={startQuiz} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all">Start Session</button>
          </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-slate-50 overflow-hidden">
      {/* Header Bar */}
      <div className="bg-white border-b p-3 flex justify-between items-center shrink-0">
         <div className="flex items-center gap-2">
            <span className="bg-slate-900 text-white text-[10px] px-2 py-1 rounded font-black">Q {currentQIndex+1}</span>
            <span className="text-[10px] font-bold text-slate-400 uppercase hidden xs:block">{mode}</span>
         </div>
         <div className="flex items-center gap-3">
            <span className="font-mono font-black text-sm">{formatTime(timeLeft)}</span>
            <button onClick={() => setView('setup')} className="p-1.5 bg-rose-50 text-rose-500 rounded-lg"><X size={18} /></button>
         </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-y-auto p-3 md:p-6 flex flex-col items-center">
         <div className="w-full max-w-3xl space-y-6">
            <div className="text-base md:text-xl font-bold text-slate-800 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

            {currentQ.data.questionImage && (
              <div className="w-full flex justify-center bg-white p-4 rounded-3xl border">
                 {!imgError ? (
                   <img src={currentQ.data.questionImage} className="max-h-[30vh] object-contain mix-blend-multiply" onError={() => setImgError(true)} />
                 ) : (
                   <div className="p-6 bg-rose-50 rounded-2xl border border-dashed border-rose-200 flex flex-col items-center gap-2">
                      <ImageOff size={24} className="text-rose-300" />
                      <button onClick={() => onEdit?.(currentQ.id)} className="text-[10px] font-black text-blue-600 underline uppercase">Repair Link</button>
                   </div>
                 )}
              </div>
            )}

            <div className="grid gap-2">
               {currentQ.options.map((opt, i) => {
                 const isSelected = currentQ.userAnswer === opt;
                 const isCorrect = opt === currentQ.correctOption;
                 const showResult = mode === 'practice' && !!currentQ.userAnswer;

                 let style = "bg-white border-2 border-slate-100 text-slate-700";
                 if (isSelected) style = "border-blue-600 bg-blue-50 ring-2 ring-blue-600 ring-offset-1";
                 if (showResult) {
                   if (isCorrect) style = "border-emerald-500 bg-emerald-50 ring-2 ring-emerald-500";
                   else if (isSelected) style = "border-rose-500 bg-rose-50 ring-2 ring-rose-500";
                 }

                 return (
                   <button 
                    key={i} 
                    onClick={() => handleAnswer(opt)}
                    className={`w-full p-4 rounded-2xl text-left font-bold text-sm transition-all flex items-start gap-3 active:scale-[0.98] ${style}`}
                   >
                     <div className="w-6 h-6 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] shrink-0 font-black">{String.fromCharCode(65 + i)}</div>
                     <span dangerouslySetInnerHTML={{ __html: opt }} />
                   </button>
                 );
               })}
            </div>
         </div>
      </div>

      {/* Footer Controls */}
      <div className="bg-white border-t p-4 flex justify-between items-center gap-4 shrink-0">
         <button onClick={() => setCurrentQIndex(prev => prev - 1)} disabled={currentQIndex === 0} className="p-3 text-slate-400 disabled:opacity-20"><ChevronLeft size={32} /></button>

         <div className="flex-1 flex justify-center">
            <button 
              onClick={() => { if(confirm("Submit Exam?")) setView('results'); }}
              className="px-8 py-3 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest active:scale-95"
            >
              Finish Session
            </button>
         </div>

         <button onClick={() => setCurrentQIndex(prev => prev + 1)} disabled={currentQIndex === questions.length-1} className="p-3 text-slate-400 disabled:opacity-20"><ChevronRight size={32} /></button>
      </div>

      {/* Results View - Height Responsive */}
      {view === 'results' && (
        <div className="fixed inset-0 z-[100] bg-slate-50 flex items-center justify-center p-4">
           <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl overflow-hidden text-center flex flex-col">
              <div className="bg-slate-900 p-10 text-white">
                 <div className="w-20 h-20 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-4"><Trophy size={40} /></div>
                 <h2 className="text-5xl font-black">{(questions.filter(q => q.userAnswer === q.correctOption).length / questions.length * 100).toFixed(1)}%</h2>
              </div>
              <div className="p-10 space-y-4">
                 <button onClick={() => setView('setup')} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest">Done</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import { AppMode, Question } from './types';

// Modular Data Imports
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';

import { Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));
  }, [userVault]);

  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    userVault.forEach(q => {
        uniqueQuestions.push(q);
        seenIds.add(q.id);
    });

    const systemSources = [...ch1, ...ch3, ...ch4, ...ch6, ...ch7, ...ch8, ...ch9, ...ch10, ...ch11];
    systemSources.forEach(q => {
        if (!seenIds.has(q.id)) {
            uniqueQuestions.push(q);
            seenIds.add(q.id);
        }
    });
    return uniqueQuestions;
  }, [userVault]);

  const categories = useMemo(() => {
    const cats = new Set(allQuestions.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [allQuestions]);

  const handleEditRequest = (id: string) => {
    setEditingId(id);
    setCurrentMode(AppMode.BUILDER);
  };

  const handleSaveQuestion = (question: Question) => {
    setUserVault(prev => {
        const existingIndex = prev.findIndex(q => q.id === question.id);
        if (existingIndex >= 0) {
            const newVault = [...prev];
            newVault[existingIndex] = question;
            return newVault;
        } else return [question, ...prev];
    });
    setEditingId(null);
    setCurrentMode(AppMode.LIST);
  };

  return (
    <div className="fixed inset-0 bg-slate-50 flex flex-col font-sans text-slate-900 overflow-hidden">
      <Header currentMode={currentMode} onModeChange={(m) => { setCurrentMode(m); setEditingId(null); }} />
      <main className="flex-1 relative overflow-hidden flex flex-col">
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full"><Flashcards data={allQuestions} onEdit={handleEditRequest} /></div>
        )}
        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full"><Quiz data={allQuestions} onEdit={handleEditRequest} /></div>
        )}
        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto px-2 py-4">
            <QuestionList 
              data={allQuestions} 
              onExport={() => {}} 
              onImport={() => {}} 
              onEdit={handleEditRequest} 
            />
            <div className="flex justify-center p-10">
               <button onClick={() => confirm("Reset?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest">
                 <Trash2 size={12} className="inline mr-1" /> Factory Reset
               </button>
            </div>
          </div>
        )}
        {currentMode === AppMode.BUILDER && (
          <div className="flex-1 h-full overflow-y-auto">
            <QuestionBuilder allQuestions={allQuestions} editingId={editingId} onSave={handleSaveQuestion} onCancel={() => { setEditingId(null); setCurrentMode(AppMode.LIST); }} existingCategories={categories} />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, ChevronDown, RotateCw, Check, X, ChevronLeft, ChevronRight, Volume2, VolumeX, ImageOff, PenTool } from 'lucide-react';
import Button from './Button';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

// دالة ذكية لإصلاح روابط الصور المحمية
const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    // استخدام بروكسي عالمي لتجاوز حماية Quizlet وتصغير الحجم للأداء
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=600&fit=contain`;
  }
  return url;
};

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    cancel();
  }, [currentIndex, deck, cancel]);

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const nextCard = () => {
    if (currentIndex < deck.length - 1) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev + 1), 100);
    }
  };

  const prevCard = () => {
    if (currentIndex > 0) {
      setIsFlipped(false);
      setTimeout(() => setCurrentIndex(prev => prev - 1), 100);
    }
  };

  const currentCard = deck[currentIndex];

  return (
    <div className="flex flex-col h-full w-full max-w-2xl mx-auto px-2 pb-safe overflow-hidden bg-slate-50">

      {/* Top Status Bar */}
      <div className="flex justify-between items-center px-1 py-2 shrink-0">
        <div className="flex items-center gap-2">
          <div className="bg-white border shadow-sm px-3 py-1 rounded-full font-black text-[10px] text-blue-600">
            {currentIndex + 1} / {deck.length}
          </div>
          <button 
            onClick={() => setIsFilterOpen(true)}
            className="bg-white border shadow-sm px-3 py-1 rounded-full font-bold text-[10px] text-slate-500 uppercase flex items-center gap-1"
          >
            <Filter size={10} /> {selectedCategories.length || 'All'}
          </button>
        </div>
        <button onClick={() => setDeck([...deck].sort(() => Math.random() - 0.5))} className="p-2 bg-white border shadow-sm rounded-full text-slate-400">
          <Shuffle size={14} />
        </button>
      </div>

      {/* Card Content - Dynamic Height */}
      <div className="flex-1 relative perspective-1000 my-2">
        {deck.length > 0 && currentCard ? (
          <div 
            className={`w-full h-full relative transform-style-3d transition-transform duration-500 ${isFlipped ? 'rotate-y-180' : ''}`}
            onClick={flipCard}
          >
            {/* Front */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-[2.5rem] shadow-sm border border-slate-200 backface-hidden flex flex-col overflow-hidden">
              <div className="flex-1 p-6 flex flex-col items-center justify-center text-center overflow-y-auto">
                {currentCard.questionImage && !imgError && (
                  <div className="mb-6 w-full flex justify-center">
                    <img 
                      src={getProxiedImageUrl(currentCard.questionImage)} 
                      className="max-h-[40vh] w-auto object-contain rounded-2xl"
                      onError={() => setImgError(true)}
                      alt="Scientific Diagram"
                    />
                  </div>
                )}
                {imgError && (
                  <div className="mb-4 p-4 bg-rose-50 rounded-2xl border border-dashed border-rose-200 flex flex-col items-center">
                    <ImageOff size={20} className="text-rose-300 mb-1" />
                    <button onClick={(e) => { e.stopPropagation(); onEdit?.(currentCard.id); }} className="text-[10px] font-black text-blue-500 underline">IMAGE BLOCKED - REPAIR LINK</button>
                  </div>
                )}
                <h2 className="text-lg md:text-2xl font-black text-slate-800 leading-tight" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
                <span className="mt-8 text-[9px] font-bold text-slate-300 uppercase tracking-[0.3em]">Tap to Flip</span>
              </div>
            </div>

            {/* Back */}
            <div className="absolute inset-0 w-full h-full bg-slate-900 rounded-[2.5rem] shadow-2xl backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="flex-1 p-8 flex flex-col items-center justify-center text-center overflow-y-auto">
                <div className="text-2xl md:text-4xl font-black text-white leading-tight mb-6" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />
                {currentCard.explanation && (
                  <div className="bg-white/5 p-4 rounded-2xl border border-white/10 text-slate-400 text-xs leading-relaxed max-w-sm" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                )}
                <div className="mt-8 flex gap-4">
                   {hasSupport && (
                     <button onClick={(e) => { e.stopPropagation(); speak(currentCard.answerText, 'a'); }} className="p-3 bg-white/10 rounded-full text-white">
                       <Volume2 size={20} />
                     </button>
                   )}
                </div>
              </div>
            </div>
          </div>
        ) : null}
      </div>

      {/* Modern Bottom Controls */}
      <div className="flex items-center gap-3 p-2 shrink-0">
        <button onClick={prevCard} disabled={currentIndex === 0} className="h-16 w-16 rounded-3xl bg-white border border-slate-200 shadow-sm flex items-center justify-center text-slate-400 active:scale-90 disabled:opacity-20 transition-transform">
          <ChevronLeft size={32} />
        </button>

        <button onClick={flipCard} className="flex-1 h-16 rounded-3xl bg-blue-600 text-white font-black uppercase text-xs tracking-widest shadow-lg shadow-blue-200 active:scale-95 transition-all flex items-center justify-center gap-2">
          <RotateCw size={18} /> {isFlipped ? 'Show Question' : 'Reveal Answer'}
        </button>

        <button onClick={nextCard} disabled={currentIndex === deck.length - 1} className="h-16 w-16 rounded-3xl bg-white border border-slate-200 shadow-sm flex items-center justify-center text-slate-400 active:scale-90 disabled:opacity-20 transition-transform">
          <ChevronRight size={32} />
        </button>
      </div>

      {/* Filter Modal */}
      {isFilterOpen && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-black/40 backdrop-blur-sm animate-in fade-in">
           <div className="w-full max-w-md bg-white rounded-t-[2.5rem] sm:rounded-[2.5rem] shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-300">
              <div className="p-6 border-b flex justify-between items-center">
                 <h3 className="font-black text-slate-800">Select Topics</h3>
                 <button onClick={() => setIsFilterOpen(false)} className="p-2 bg-slate-100 rounded-full"><X size={20} /></button>
              </div>
              <div className="p-4 max-h-[50vh] overflow-y-auto">
                 {categories.map(cat => (
                   <label key={cat} className="flex items-center gap-4 p-4 hover:bg-slate-50 rounded-2xl cursor-pointer mb-1 transition-colors">
                      <input 
                        type="checkbox" 
                        className="w-6 h-6 rounded-lg text-blue-600 border-slate-300 focus:ring-blue-500"
                        checked={selectedCategories.includes(cat)}
                        onChange={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
                      />
                      <span className="text-sm font-bold text-slate-700">{cat}</span>
                   </label>
                 ))}
              </div>
              <div className="p-6 bg-slate-50">
                 <button onClick={() => setIsFilterOpen(false)} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl">Start Studying</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  X, Clock, Flag, ChevronLeft, ChevronRight, 
  LayoutGrid, Image as ImageIcon, Zap, Filter, CheckCircle2, 
  Trophy, RotateCw, ImageOff, PenTool 
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=600&fit=contain`;
  }
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'practice'>('practice');
  const [imgError, setImgError] = useState(false);

  useEffect(() => { setImgError(false); }, [currentQIndex]);

  const startQuiz = (count: number) => {
    let pool = [...data].sort(() => Math.random() - 0.5).slice(0, count);
    const generated = pool.map(q => {
      const correct = q.answerText;
      let options = Array.from(new Set([...(q.options || []), correct])).sort(() => Math.random() - 0.5).slice(0, 4);
      while(options.length < 4) options.push(`Option ${options.length + 1}`);
      return { id: q.id, data: q, options, correctOption: correct, userAnswer: null, isFlagged: false } as QuizQuestion;
    });
    setQuestions(generated);
    setCurrentQIndex(0);
    setTimeLeft(generated.length * 60);
    setView('playing');
  };

  const handleAnswer = (option: string) => {
    if (questions[currentQIndex].userAnswer) return;
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-50 flex flex-col items-center p-4 justify-center">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-xl border p-8 space-y-8">
           <div className="text-center">
              <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
                 <LayoutGrid size={32} />
              </div>
              <h2 className="text-2xl font-black text-slate-800">Quiz Generator</h2>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Ready for Assessment</p>
           </div>

           <div className="grid grid-cols-2 gap-3">
              <button onClick={() => setMode('exam')} className={`py-4 rounded-2xl border-2 font-black text-[10px] uppercase transition-all ${mode === 'exam' ? 'border-blue-600 bg-blue-50 text-blue-600 shadow-md' : 'border-slate-100 text-slate-400'}`}>Exam Mode</button>
              <button onClick={() => setMode('practice')} className={`py-4 rounded-2xl border-2 font-black text-[10px] uppercase transition-all ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-600 shadow-md' : 'border-slate-100 text-slate-400'}`}>Practice Mode</button>
           </div>

           <div className="space-y-3">
              <button onClick={() => startQuiz(10)} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-blue-600 transition-colors">Quick Quiz (10 Qs)</button>
              <button onClick={() => startQuiz(25)} className="w-full py-4 bg-white border border-slate-200 text-slate-800 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-slate-50 transition-colors">Standard (25 Qs)</button>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-slate-50 overflow-hidden">
      {/* Quiz Header */}
      <div className="bg-white border-b px-4 py-3 flex justify-between items-center shrink-0 shadow-sm">
         <div className="flex items-center gap-2">
            <span className="bg-slate-900 text-white text-[10px] px-3 py-1 rounded-full font-black">Q {currentQIndex+1}</span>
         </div>
         <div className="flex items-center gap-3 font-mono font-black text-sm text-slate-600">
            {mode === 'exam' ? formatTime(timeLeft) : 'Practice'}
            <button onClick={() => confirm("Exit quiz?") && setView('setup')} className="p-1.5 bg-slate-100 rounded-full ml-2"><X size={16} /></button>
         </div>
      </div>

      {/* Question Area */}
      <div className="flex-1 overflow-y-auto p-4 flex flex-col items-center">
         <div className="w-full max-w-xl space-y-6">
            <h3 className="text-lg md:text-xl font-black text-slate-800 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

            {currentQ.data.questionImage && !imgError && (
              <div className="w-full bg-white p-4 rounded-3xl border shadow-sm flex justify-center">
                 <img 
                    src={getProxiedImageUrl(currentQ.data.questionImage)} 
                    className="max-h-[35vh] object-contain rounded-xl"
                    onError={() => setImgError(true)}
                 />
              </div>
            )}

            <div className="grid gap-3">
               {currentQ.options.map((opt, i) => {
                 const isSelected = currentQ.userAnswer === opt;
                 const isCorrect = opt === currentQ.correctOption;
                 const showResult = (mode === 'practice' && !!currentQ.userAnswer) || view === 'review';

                 let style = "bg-white border border-slate-200 text-slate-700 shadow-sm";
                 if (isSelected) style = "border-blue-600 bg-blue-50 ring-2 ring-blue-500 ring-offset-1";
                 if (showResult) {
                   if (isCorrect) style = "border-emerald-500 bg-emerald-50 ring-2 ring-emerald-500";
                   else if (isSelected) style = "border-rose-500 bg-rose-50 ring-2 ring-rose-500 opacity-100";
                   else style = "opacity-40 bg-slate-50";
                 }

                 return (
                   <button 
                    key={i} 
                    onClick={() => handleAnswer(opt)}
                    disabled={showResult}
                    className={`w-full p-5 rounded-2xl text-left font-bold text-sm transition-all flex items-start gap-4 active:scale-[0.98] ${style}`}
                   >
                     <div className="w-6 h-6 rounded-lg bg-slate-100 flex items-center justify-center text-[10px] shrink-0 font-black">{String.fromCharCode(65 + i)}</div>
                     <span dangerouslySetInnerHTML={{ __html: opt }} />
                   </button>
                 );
               })}
            </div>
         </div>
      </div>

      {/* Quiz Footer */}
      <div className="bg-white border-t p-4 flex justify-between items-center gap-4 shrink-0 shadow-[0_-4px_10px_rgba(0,0,0,0.02)]">
         <button onClick={() => setCurrentQIndex(prev => prev - 1)} disabled={currentQIndex === 0} className="p-4 text-slate-300 disabled:opacity-10 active:bg-slate-100 rounded-full transition-colors"><ChevronLeft size={32} /></button>

         <button 
            onClick={() => currentQIndex === questions.length-1 ? setView('results') : setCurrentQIndex(prev => prev+1)}
            className={`flex-1 h-14 rounded-2xl font-black uppercase text-xs tracking-widest active:scale-95 transition-all ${currentQIndex === questions.length-1 ? 'bg-emerald-600 text-white shadow-emerald-200 shadow-lg' : 'bg-slate-900 text-white shadow-xl'}`}
         >
            {currentQIndex === questions.length-1 ? 'Finish Quiz' : 'Next Question'}
         </button>

         <button onClick={() => setCurrentQIndex(prev => prev + 1)} disabled={currentQIndex === questions.length-1} className="p-4 text-slate-300 disabled:opacity-10 active:bg-slate-100 rounded-full transition-colors"><ChevronRight size={32} /></button>
      </div>

      {/* Results */}
      {view === 'results' && (
        <div className="fixed inset-0 z-[200] bg-slate-50 flex items-center justify-center p-4 animate-in fade-in">
           <div className="w-full max-w-sm bg-white rounded-[3rem] shadow-2xl overflow-hidden text-center flex flex-col border border-slate-200">
              <div className="bg-slate-900 p-12 text-white">
                 <div className="w-24 h-24 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-xl"><Trophy size={48} className="text-white" /></div>
                 <h2 className="text-6xl font-black mb-1">{(questions.filter(q => q.userAnswer === q.correctOption).length / questions.length * 100).toFixed(1)}%</h2>
                 <p className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em]">Evaluation Complete</p>
              </div>
              <div className="p-10 space-y-4">
                 <div className="flex justify-around mb-8">
                    <div><div className="text-xl font-black text-emerald-500">{questions.filter(q => q.userAnswer === q.correctOption).length}</div><div className="text-[8px] font-black text-slate-400 uppercase">Correct</div></div>
                    <div><div className="text-xl font-black text-rose-500">{questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</div><div className="text-[8px] font-black text-slate-400 uppercase">Mistakes</div></div>
                 </div>
                 <button onClick={() => setView('setup')} className="w-full py-5 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all">Back to Lab</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import { AppMode, Question } from './types';

// Modular Data Imports
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';

import { Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));
  }, [userVault]);

  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    userVault.forEach(q => {
        uniqueQuestions.push(q);
        seenIds.add(q.id);
    });

    const systemSources = [...ch1, ...ch3, ...ch4, ...ch6, ...ch7, ...ch8, ...ch9, ...ch10, ...ch11];
    systemSources.forEach(q => {
        if (!seenIds.has(q.id)) {
            uniqueQuestions.push(q);
            seenIds.add(q.id);
        }
    });
    return uniqueQuestions;
  }, [userVault]);

  const categories = useMemo(() => {
    const cats = new Set(allQuestions.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [allQuestions]);

  const handleEditRequest = (id: string) => {
    setEditingId(id);
    setCurrentMode(AppMode.BUILDER);
  };

  const handleSaveQuestion = (question: Question) => {
    setUserVault(prev => {
        const existingIndex = prev.findIndex(q => q.id === question.id);
        if (existingIndex >= 0) {
            const newVault = [...prev];
            newVault[existingIndex] = question;
            return newVault;
        } else return [question, ...prev];
    });
    setEditingId(null);
    setCurrentMode(AppMode.LIST);
  };

  return (
    // استخدام h-[100dvh] لضمان ملء الشاشة تماماً على الهواتف
    <div className="h-[100dvh] w-full flex flex-col bg-slate-50 font-sans text-slate-900 overflow-hidden fixed inset-0">
      <Header currentMode={currentMode} onModeChange={(m) => { setCurrentMode(m); setEditingId(null); }} />

      <main className="flex-1 relative overflow-hidden flex flex-col w-full max-w-5xl mx-auto">
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full"><Flashcards data={allQuestions} onEdit={handleEditRequest} /></div>
        )}
        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full"><Quiz data={allQuestions} onEdit={handleEditRequest} /></div>
        )}
        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto px-3 py-4 custom-scrollbar">
            <QuestionList 
              data={allQuestions} 
              onExport={() => {}} 
              onImport={() => {}} 
              onEdit={handleEditRequest} 
            />
            <div className="flex justify-center p-12">
               <button onClick={() => confirm("Reset all changes?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors">
                 <Trash2 size={12} className="inline mr-1" /> Factory Reset Vault
               </button>
            </div>
          </div>
        )}
        {currentMode === AppMode.BUILDER && (
          <div className="flex-1 h-full overflow-y-auto custom-scrollbar">
            <QuestionBuilder allQuestions={allQuestions} editingId={editingId} onSave={handleSaveQuestion} onCancel={() => { setEditingId(null); setCurrentMode(AppMode.LIST); }} existingCategories={categories} />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, Download, Upload, ShieldCheck, Database, 
  Filter, ArrowUpDown, X, ChevronDown, Check, Highlighter,
  Volume2, VolumeX, Edit3
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
  onImport: (e: React.ChangeEvent<HTMLInputElement>) => void;
  // Fix: Added missing onEdit prop to satisfy TypeScript error in App.tsx
  onEdit?: (id: string) => void;
}

const ITEMS_PER_PAGE = 20;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport, onImport, onEdit }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');
  const [isFilterMenuOpen, setIsFilterMenuOpen] = useState(false);

  // Audio Hook
  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  // Helper to remove HTML tags for searching and sorting (still used for search)
  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  // Helper to escape regex characters
  const escapeRegExp = (string: string) => {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  };

  // Helper to highlight matched terms
  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;

    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;

    terms.forEach(term => {
      const regex = new RegExp(`(${escapeRegExp(term)})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-yellow-300 text-slate-900 rounded-sm px-0.5 font-bold">$1</mark>');
    });

    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'Uncategorized'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;

    if (selectedCategory !== 'All') {
      result = result.filter(q => (q.category || 'Uncategorized') === selectedCategory);
    }

    if (search.trim()) {
      const terms = search.toLowerCase().split(/\s+/).filter(Boolean);

      result = result.filter(q => {
        const qText = stripHtml(q.questionText).toLowerCase();
        const aText = stripHtml(q.answerText).toLowerCase();
        return terms.every(term => qText.includes(term) || aText.includes(term));
      });
    }

    if (sortOrder === 'asc') {
      result = [...result].sort((a, b) => stripHtml(a.questionText).localeCompare(stripHtml(b.questionText)));
    } else if (sortOrder === 'desc') {
      result = [...result].sort((a, b) => stripHtml(b.questionText).localeCompare(stripHtml(a.questionText)));
    }

    return result;
  }, [data, selectedCategory, search, sortOrder]);

  useEffect(() => {
    setCurrentPage(1);
  }, [search, selectedCategory, sortOrder]);

  useEffect(() => {
    return () => cancel();
  }, [currentPage, cancel]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) {
      cancel();
    } else {
      speak(text, id);
    }
  };

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  const handlePageChange = (newPage: number) => {
    cancel();
    setCurrentPage(newPage);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="max-w-7xl mx-auto w-full px-3 md:px-4 pb-32">
      <div className="bg-white rounded-3xl p-4 md:p-8 border border-slate-200 shadow-xl overflow-hidden relative group mb-4">
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
          <Database size={100} className="md:w-[200px] md:h-[200px]" />
        </div>

        <div className="flex flex-col md:flex-row justify-between gap-4 md:gap-6 relative z-10">
          <div className="space-y-1 md:space-y-2">
            <h2 className="text-xl md:text-3xl font-black text-slate-900 tracking-tight">
              Knowledge <span className="text-blue-600">Index</span>
            </h2>
            <div className="flex flex-wrap items-center gap-3 md:gap-4 text-[10px] md:text-xs font-bold text-slate-500 uppercase tracking-widest">
              <span className="flex items-center gap-1"><Database size={14} className="text-blue-500" /> {data.length.toLocaleString()} Total</span>
              <span className="flex items-center gap-1"><Highlighter size={14} className="text-amber-500" /> {processedData.length.toLocaleString()} Found</span>
            </div>
          </div>

          <div className="flex gap-2 w-full md:w-auto">
            <button 
              onClick={onExport}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-2 md:px-4 md:py-3 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider transition-all"
            >
              <Download size={14} className="md:w-4 md:h-4" /> Backup
            </button>
            <label className="flex-1 md:flex-none flex items-center justify-center gap-2 px-3 py-2 md:px-4 md:py-3 bg-slate-900 hover:bg-slate-800 text-white rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider cursor-pointer transition-all shadow-lg">
              <Upload size={14} className="md:w-4 md:h-4" /> Restore
              <input type="file" className="hidden" accept=".json" onChange={onImport} />
            </label>
          </div>
        </div>
      </div>

      <div className="sticky top-0 pt-2 pb-2 z-30 bg-slate-50/95 backdrop-blur-sm space-y-2 transition-all">
        <div className={`relative shadow-md rounded-2xl transition-all ${search ? 'ring-2 ring-blue-400' : ''}`}>
          <input 
            type="text" 
            placeholder="Search definitions, muscles..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-10 md:pl-12 md:pr-12 py-3 md:py-3.5 rounded-2xl border-2 border-slate-200 bg-white text-sm md:text-base font-semibold text-slate-800 focus:border-blue-500 focus:ring-0 outline-none transition-all placeholder:text-slate-400"
          />
          <Search className={`absolute left-3 md:left-4 top-1/2 -translate-y-1/2 transition-colors ${search ? 'text-blue-500' : 'text-slate-400'}`} size={18} />
          {search && (
            <button onClick={() => setSearch('')} className="absolute right-3 md:right-4 top-1/2 -translate-y-1/2 p-1 bg-slate-100 hover:bg-red-100 text-slate-400 hover:text-red-500 rounded-full transition-colors">
              <X size={14} />
            </button>
          )}
        </div>

        <div className="flex gap-2">
          <div className="relative flex-1">
            <button 
              onClick={() => setIsFilterMenuOpen(!isFilterMenuOpen)}
              className={`w-full flex items-center justify-between px-3 py-2.5 md:px-4 md:py-3 bg-white border rounded-xl font-bold text-xs md:text-sm shadow-sm transition-all ${selectedCategory !== 'All' ? 'border-blue-300 text-blue-700 bg-blue-50' : 'border-slate-200 text-slate-700 hover:border-blue-300'}`}
            >
              <span className="flex items-center gap-2 truncate">
                <Filter size={14} className={selectedCategory !== 'All' ? "text-blue-600" : "text-blue-500"} />
                <span className="truncate">{selectedCategory}</span>
              </span>
              <ChevronDown size={14} className={`text-slate-400 transition-transform ${isFilterMenuOpen ? 'rotate-180' : ''}`} />
            </button>

            {isFilterMenuOpen && (
              <>
                <div className="fixed inset-0 z-10" onClick={() => setIsFilterMenuOpen(false)}></div>
                <div className="absolute top-full left-0 mt-2 w-full bg-white border border-slate-200 rounded-xl shadow-2xl z-20 max-h-[60vh] overflow-y-auto custom-scrollbar p-2">
                  {categories.map(cat => (
                    <button
                      key={cat}
                      onClick={() => { setSelectedCategory(cat); setIsFilterMenuOpen(false); }}
                      className={`w-full text-left px-3 py-2.5 rounded-lg text-xs md:text-sm font-bold transition-colors flex items-center justify-between ${selectedCategory === cat ? 'bg-blue-50 text-blue-700' : 'text-slate-600 hover:bg-slate-50'}`}
                    >
                      {cat}
                      {selectedCategory === cat && <Check size={14} />}
                    </button>
                  ))}
                </div>
              </>
            )}
          </div>

          <button 
            onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
            className={`flex items-center justify-center gap-2 px-3 py-2.5 md:px-4 md:py-3 rounded-xl font-bold text-xs md:text-sm border transition-all shadow-sm shrink-0 ${sortOrder !== 'default' ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-50'}`}
          >
            <ArrowUpDown size={14} />
            <span className="hidden md:inline">{sortOrder === 'default' ? 'Sort' : sortOrder === 'asc' ? 'A-Z' : 'Z-A'}</span>
          </button>
        </div>
      </div>

      <div className="space-y-3 md:space-y-4">
        {processedData.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-slate-300">
            <Search size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-slate-400 font-bold">No results found.</p>
          </div>
        ) : (
          currentData.map((q) => (
            <div key={q.id} className="bg-white rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-all duration-300 overflow-hidden flex flex-col md:flex-row group">
              {q.questionImage && (
                <div className="w-full md:w-48 h-40 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0">
                  <img src={q.questionImage} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg mix-blend-multiply" loading="lazy" />
                </div>
              )}

              <div className="p-4 md:p-6 flex-1 flex flex-col gap-2 md:gap-3">
                <div className="flex items-start justify-between gap-4">
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] md:text-[10px] font-black uppercase text-blue-500 bg-blue-50 px-2 py-1 rounded border border-blue-100 tracking-wider">
                        {q.category || 'General'}
                    </span>
                    {hasSupport && (
                        <button 
                          onClick={(e) => handleAudio(e, `Question: ${q.questionText}. Answer: ${q.answerText}. ${q.explanation ? 'Explanation: ' + q.explanation : ''}`, q.id)}
                          className={`p-1.5 md:p-2 rounded-full transition-all ${isSpeaking && speakingId === q.id ? 'bg-red-100 text-red-600 ring-2 ring-red-200' : 'bg-slate-50 text-slate-400 hover:bg-blue-50 hover:text-blue-600 shadow-sm'}`}
                          title="Read Question & Answer"
                        >
                          {isSpeaking && speakingId === q.id ? <VolumeX size={14} /> : <Volume2 size={14} />}
                        </button>
                    )}
                    {/* Fix: Added Edit Button to trigger onEdit and allow user to repair or modify questions */}
                    {onEdit && (
                        <button 
                          onClick={(e) => { e.stopPropagation(); onEdit(q.id); }}
                          className="p-1.5 md:p-2 rounded-full bg-slate-50 text-slate-400 hover:bg-blue-50 hover:text-blue-600 shadow-sm transition-all"
                          title="Edit Question"
                        >
                          <Edit3 size={14} />
                        </button>
                    )}
                  </div>
                </div>

                <div>
                  <h3 
                    className="text-sm md:text-lg font-bold text-slate-900 leading-snug mb-1 md:mb-2"
                    dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, search) }}
                  />
                  <div className="pl-3 md:pl-4 border-l-4 border-blue-500 py-1 transition-all group-hover:border-blue-600">
                    <p 
                      className="text-xs md:text-base font-medium text-slate-600 leading-relaxed"
                      dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, search) }}
                    />
                  </div>
                </div>

                {q.explanation && (
                  <div className="mt-1 md:mt-2 bg-slate-50 p-2 md:p-3 rounded-lg border border-slate-100 text-[10px] md:text-sm text-slate-500">
                    <span className="font-bold text-slate-400 text-[9px] md:text-[10px] uppercase mr-2">Note:</span>
                    <span dangerouslySetInnerHTML={{ __html: highlightText(q.explanation, search) }} />
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>

      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-2 md:gap-3 pt-4 md:pt-6">
          <button 
            onClick={() => handlePageChange(currentPage - 1)}
            disabled={currentPage === 1}
            className="px-3 py-1.5 md:px-4 md:py-2 rounded-xl bg-white border border-slate-200 text-slate-600 font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors shadow-sm text-xs md:text-sm"
          >
            Prev
          </button>

          <div className="px-3 py-1.5 md:px-4 md:py-2 bg-slate-800 text-white rounded-xl font-bold text-xs md:text-sm shadow-lg">
            Page {currentPage} / {totalPages}
          </div>

          <button 
            onClick={() => handlePageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
            className="px-3 py-1.5 md:px-4 md:py-2 rounded-xl bg-white border border-slate-200 text-slate-600 font-bold disabled:opacity-50 disabled:cursor-not-allowed hover:bg-slate-50 transition-colors shadow-sm text-xs md:text-sm"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

export default QuestionList;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, Flag, ChevronLeft, ChevronRight, 
  LayoutGrid, Trophy, RotateCw, ImageOff, 
  CheckCircle2, AlertCircle, ListRestart, 
  Eye, BarChart3, Timer, Hash
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=800&fit=contain`;
  }
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'practice'>('practice');
  const [imgError, setImgError] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  // Timer logic
  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            setView('results');
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  useEffect(() => { setImgError(false); }, [currentQIndex]);

  const startQuiz = (count: number) => {
    let pool = data;
    if (selectedCategory !== 'All') {
      pool = data.filter(q => q.category === selectedCategory);
    }

    const shuffledPool = [...pool].sort(() => Math.random() - 0.5);
    const selected = shuffledPool.slice(0, Math.min(count, shuffledPool.length));

    const generated = selected.map(q => {
      const correct = q.answerText;
      let options = Array.from(new Set([...(q.options || []), correct]))
        .sort(() => Math.random() - 0.5)
        .slice(0, 4);

      while(options.length < 4) {
        options.push(`Alternative Option ${options.length + 1}`);
      }

      return { 
        id: q.id, 
        data: q, 
        options, 
        correctOption: correct, 
        userAnswer: null, 
        isFlagged: false 
      } as QuizQuestion;
    });

    setQuestions(generated);
    setCurrentQIndex(0);
    setTimeLeft(generated.length * 60); // 1 minute per question
    setView('playing');
  };

  const handleAnswer = (option: string) => {
    if (view === 'review' || questions[currentQIndex].userAnswer) return;
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });

    // Auto-advance in practice mode after a short delay
    if (mode === 'practice' && currentQIndex < questions.length - 1) {
      setTimeout(() => setCurrentQIndex(prev => prev + 1), 600);
    }
  };

  const score = useMemo(() => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return {
      correct,
      total: questions.length,
      percent: questions.length ? (correct / questions.length * 100).toFixed(1) : "0"
    };
  }, [questions]);

  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-50 flex flex-col items-center p-4 justify-center animate-fade-up">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl border-t-4 border-blue-600 p-8 space-y-8">
           <div className="text-center space-y-2">
              <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center mx-auto shadow-inner">
                 <Timer size={40} strokeWidth={2.5} />
              </div>
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">System Boot</h2>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Select Examination Parameters</p>
           </div>

           <div className="space-y-4">
              <div className="flex gap-2">
                <button 
                  onClick={() => setMode('exam')} 
                  className={`flex-1 py-4 rounded-2xl border-2 font-black text-xs uppercase transition-all flex flex-col items-center gap-1 ${mode === 'exam' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-400 bg-slate-50/50'}`}
                >
                  <Timer size={16} /> Exam
                </button>
                <button 
                  onClick={() => setMode('practice')} 
                  className={`flex-1 py-4 rounded-2xl border-2 font-black text-xs uppercase transition-all flex flex-col items-center gap-1 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-400 bg-slate-50/50'}`}
                >
                  <Eye size={16} /> Practice
                </button>
              </div>

              <div className="relative">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-2 mb-1 block">Chapter/System Filter</label>
                <select 
                  value={selectedCategory}
                  onChange={(e) => setSelectedCategory(e.target.value)}
                  className="w-full p-4 bg-slate-100 border-none rounded-2xl font-bold text-sm text-slate-700 appearance-none outline-none focus:ring-2 ring-blue-500"
                >
                  {categories.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-3 gap-2">
                {[10, 25, 50].map(n => (
                  <button 
                    key={n}
                    onClick={() => startQuiz(n)}
                    className="py-4 bg-slate-900 text-white rounded-2xl font-black text-sm hover:bg-blue-600 active:scale-95 transition-all shadow-lg"
                  >
                    {n} Qs
                  </button>
                ))}
              </div>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-slate-50 overflow-hidden select-none">
      {/* Quiz Control Header */}
      <div className="bg-white border-b px-4 h-14 flex justify-between items-center shrink-0 z-10 shadow-sm">
         <div className="flex items-center gap-3">
            <div className="bg-slate-900 text-white text-[11px] px-3 py-1 rounded-lg font-black shadow-sm">
              {currentQIndex + 1} OF {questions.length}
            </div>
            {mode === 'exam' && (
              <div className={`flex items-center gap-1.5 font-mono font-black text-sm ${timeLeft < 60 ? 'text-red-500 animate-pulse' : 'text-slate-600'}`}>
                <Clock size={16} />
                {formatTime(timeLeft)}
              </div>
            )}
         </div>
         <button 
          onClick={() => confirm("Exit session? Progress will be lost.") && setView('setup')} 
          className="p-2 bg-slate-100 hover:bg-rose-50 hover:text-rose-600 text-slate-400 rounded-xl transition-colors"
         >
           <X size={20} />
         </button>
      </div>

      {/* Question Engine */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 custom-scrollbar">
         <div className="w-full max-w-2xl mx-auto space-y-6">
            <div className="bg-white p-6 md:p-8 rounded-[2rem] shadow-sm border border-slate-200">
              <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-4 block">{currentQ.data.category}</span>
              <h3 className="text-xl md:text-2xl font-black text-slate-800 leading-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
            </div>

            {currentQ.data.questionImage && !imgError && (
              <div className="w-full bg-white p-4 rounded-[2rem] border border-slate-200 shadow-sm flex justify-center group overflow-hidden">
                 <img 
                    src={getProxiedImageUrl(currentQ.data.questionImage)} 
                    className="max-h-[30vh] md:max-h-[40vh] object-contain transition-transform duration-500 hover:scale-110"
                    onError={() => setImgError(true)}
                    alt="Diagram"
                 />
              </div>
            )}

            <div className="grid gap-3">
               {currentQ.options.map((opt, i) => {
                 const isSelected = currentQ.userAnswer === opt;
                 const isCorrect = opt === currentQ.correctOption;
                 const showFeedback = (mode === 'practice' && !!currentQ.userAnswer) || view === 'review';

                 let variantStyles = "bg-white border-2 border-slate-100 text-slate-700 shadow-sm";

                 if (isSelected) variantStyles = "border-blue-600 bg-blue-50/50 ring-2 ring-blue-500";

                 if (showFeedback) {
                   if (isCorrect) variantStyles = "border-emerald-500 bg-emerald-50 text-emerald-900 ring-2 ring-emerald-500 shadow-emerald-100";
                   else if (isSelected) variantStyles = "border-rose-500 bg-rose-50 text-rose-900 ring-2 ring-rose-500 opacity-100";
                   else variantStyles = "opacity-40 bg-slate-50 border-slate-100 grayscale-[0.5]";
                 }

                 return (
                   <button 
                    key={i} 
                    onClick={() => handleAnswer(opt)}
                    disabled={showFeedback}
                    className={`w-full p-5 rounded-2xl text-left font-bold text-sm transition-all flex items-start gap-4 active:scale-[0.98] ${variantStyles}`}
                   >
                     <div className={`w-7 h-7 rounded-xl flex items-center justify-center text-xs shrink-0 font-black shadow-sm ${isSelected ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'}`}>
                       {String.fromCharCode(65 + i)}
                     </div>
                     <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                     {showFeedback && isCorrect && <CheckCircle2 size={18} className="ml-auto text-emerald-500 shrink-0" />}
                     {showFeedback && isSelected && !isCorrect && <AlertCircle size={18} className="ml-auto text-rose-500 shrink-0" />}
                   </button>
                 );
               })}
            </div>

            {((mode === 'practice' && !!currentQ.userAnswer) || view === 'review') && currentQ.data.explanation && (
              <div className="bg-blue-600/5 border-2 border-blue-100 p-6 rounded-[2rem] space-y-2 animate-fade-up">
                <div className="flex items-center gap-2 text-blue-600 font-black text-[10px] uppercase tracking-widest">
                  <BarChart3 size={14} /> Rational Engine
                </div>
                <p className="text-sm font-medium text-slate-600 leading-relaxed" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
              </div>
            )}
         </div>
      </div>

      {/* Footer Navigation - Phone Optimized */}
      <div className="bg-white border-t p-4 h-24 flex justify-between items-center gap-4 shrink-0 shadow-[0_-4px_10px_rgba(0,0,0,0.03)] pb-safe">
         <button 
            onClick={() => setCurrentQIndex(prev => prev - 1)} 
            disabled={currentQIndex === 0} 
            className="h-14 w-14 rounded-2xl bg-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-10 active:bg-slate-200 transition-colors shadow-inner"
         >
           <ChevronLeft size={32} />
         </button>

         <button 
            onClick={() => {
              if (currentQIndex === questions.length - 1) {
                if (view === 'review') setView('results');
                else setView('results');
              } else {
                setCurrentQIndex(prev => prev + 1);
              }
            }}
            className="flex-1 h-14 rounded-2xl bg-slate-900 text-white font-black uppercase text-xs tracking-[0.2em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2"
         >
            {currentQIndex === questions.length - 1 ? (view === 'review' ? 'Close Review' : 'Finalize Exam') : 'Forward'}
            <ChevronRight size={18} />
         </button>

         <button 
            onClick={() => setCurrentQIndex(prev => prev + 1)} 
            disabled={currentQIndex === questions.length - 1} 
            className="h-14 w-14 rounded-2xl bg-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-10 active:bg-slate-200 transition-colors shadow-inner"
         >
           <ChevronRight size={32} />
         </button>
      </div>

      {/* Dynamic Results System */}
      {view === 'results' && (
        <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4 animate-fade-up">
           <div className="w-full max-w-sm bg-white rounded-[3rem] shadow-3xl overflow-hidden text-center flex flex-col border border-white/20">
              <div className="bg-slate-900 p-12 text-white relative">
                 <div className="absolute top-4 right-6 opacity-10">
                   <Trophy size={120} />
                 </div>
                 <div className="w-24 h-24 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-2xl ring-4 ring-white/10">
                    <Trophy size={48} className="text-white" />
                 </div>
                 <h2 className="text-6xl font-black mb-1 tabular-nums">{score.percent}%</h2>
                 <p className="text-[10px] font-black uppercase text-blue-400 tracking-[0.4em]">Efficiency Rating</p>
              </div>

              <div className="p-8 space-y-6">
                 <div className="flex justify-around bg-slate-50 p-6 rounded-3xl border border-slate-100">
                    <div className="space-y-1">
                      <div className="text-2xl font-black text-emerald-500">{score.correct}</div>
                      <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Valid</div>
                    </div>
                    <div className="w-px h-10 bg-slate-200 mt-2"></div>
                    <div className="space-y-1">
                      <div className="text-2xl font-black text-rose-500">{score.total - score.correct}</div>
                      <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Invalid</div>
                    </div>
                 </div>

                 <div className="grid grid-cols-2 gap-3">
                    <button 
                      onClick={() => { setView('review'); setCurrentQIndex(0); }} 
                      className="py-5 bg-white border-2 border-slate-900 text-slate-900 rounded-3xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 hover:bg-slate-50 active:scale-95 transition-all"
                    >
                      <Eye size={16} /> Review
                    </button>
                    <button 
                      onClick={() => setView('setup')} 
                      className="py-5 bg-slate-900 text-white rounded-3xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 shadow-xl active:scale-95 transition-all"
                    >
                      <ListRestart size={16} /> Restart
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, RotateCw, X, ChevronLeft, ChevronRight, Volume2, ImageOff, Check, CheckSquare, Square } from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=800&fit=contain`;
  }
  return url;
};

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);

  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories]);

  useEffect(() => {
    setImgError(false);
    cancel();
  }, [currentIndex, deck, cancel]);

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const currentCard = deck[currentIndex];

  return (
    <div className="flex flex-col h-full w-full max-w-2xl mx-auto px-2 pb-safe overflow-hidden bg-slate-50">

      {/* Controls Bar */}
      <div className="flex justify-between items-center px-1 py-2 shrink-0">
        <div className="flex items-center gap-2">
          <div className="bg-white border shadow-sm px-3 py-1 rounded-full font-black text-[10px] text-blue-600">
            {currentIndex + 1} / {deck.length}
          </div>
          <button 
            onClick={() => setIsFilterOpen(true)}
            className={`px-3 py-1 rounded-full font-bold text-[10px] uppercase flex items-center gap-1.5 transition-all ${selectedCategories.length > 0 ? 'bg-blue-600 text-white shadow-blue-200' : 'bg-white border text-slate-500 shadow-sm'}`}
          >
            <Filter size={10} /> {selectedCategories.length === 0 ? 'All Systems' : `${selectedCategories.length} Selected`}
          </button>
        </div>
        <button 
          onClick={() => setDeck([...deck].sort(() => Math.random() - 0.5))} 
          className="p-2 bg-white border shadow-sm rounded-full text-slate-400 active:rotate-180 transition-transform duration-500"
        >
          <Shuffle size={14} />
        </button>
      </div>

      {/* Card Body */}
      <div className="flex-1 relative perspective-1000 my-2">
        {deck.length > 0 && currentCard ? (
          <div 
            className={`w-full h-full relative transform-style-3d transition-transform duration-500 ${isFlipped ? 'rotate-y-180' : ''}`}
            onClick={flipCard}
          >
            <div className="absolute inset-0 w-full h-full bg-white rounded-[2.5rem] shadow-sm border border-slate-200 backface-hidden flex flex-col overflow-hidden">
              <div className="flex-1 p-6 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <div className="mb-4 w-full flex justify-center shrink-0">
                    <img 
                      src={getProxiedImageUrl(currentCard.questionImage)} 
                      className="max-h-[35vh] w-auto object-contain rounded-2xl mix-blend-multiply"
                      onError={() => setImgError(true)}
                    />
                  </div>
                )}
                {imgError && (
                  <div className="mb-4 p-4 bg-rose-50 rounded-2xl border border-dashed border-rose-200 flex flex-col items-center gap-1">
                    <ImageOff size={20} className="text-rose-300" />
                    <button onClick={(e) => { e.stopPropagation(); onEdit?.(currentCard.id); }} className="text-[10px] font-black text-blue-500 underline uppercase">Repair Link</button>
                  </div>
                )}
                <h2 className="text-lg md:text-2xl font-black text-slate-800 leading-tight" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
              </div>
              <div className="h-10 bg-slate-50 flex items-center justify-center text-[8px] font-black text-slate-300 uppercase tracking-[0.3em]">Question Phase</div>
            </div>

            <div className="absolute inset-0 w-full h-full bg-slate-900 rounded-[2.5rem] shadow-2xl backface-hidden rotate-y-180 flex flex-col overflow-hidden">
              <div className="flex-1 p-8 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                <div className="text-2xl md:text-3xl font-black text-white leading-tight mb-6" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />
                {currentCard.explanation && (
                  <div className="bg-white/5 p-5 rounded-2xl border border-white/10 text-slate-400 text-xs leading-relaxed max-w-sm text-center" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                )}
                <div className="mt-8 flex gap-4">
                   {hasSupport && (
                     <button onClick={(e) => { e.stopPropagation(); speak(currentCard.answerText, 'a'); }} className="p-4 bg-blue-600 rounded-full text-white shadow-lg shadow-blue-900/20 active:scale-90">
                       <Volume2 size={24} />
                     </button>
                   )}
                </div>
              </div>
              <div className="h-10 bg-black/20 flex items-center justify-center text-[8px] font-black text-emerald-500/50 uppercase tracking-[0.3em]">Scientific Validation</div>
            </div>
          </div>
        ) : (
          <div className="w-full h-full bg-white rounded-[2.5rem] border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400 p-10 text-center">
            <Filter size={48} className="mb-4 opacity-20" />
            <p className="font-black uppercase text-sm">No data in current filter</p>
            <button onClick={() => setSelectedCategories([])} className="mt-4 text-blue-600 font-bold underline">Reset Filters</button>
          </div>
        )}
      </div>

      {/* Navigation */}
      <div className="flex items-center gap-3 p-2 shrink-0">
        <button onClick={() => setCurrentIndex(prev => Math.max(0, prev - 1))} disabled={currentIndex === 0} className="h-16 w-16 rounded-3xl bg-white border border-slate-200 shadow-sm flex items-center justify-center text-slate-400 active:scale-90 disabled:opacity-20 transition-all">
          <ChevronLeft size={32} />
