        <button onClick={flipCard} className="flex-1 h-16 rounded-3xl bg-slate-900 text-white font-black uppercase text-xs tracking-widest shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2">
          <RotateCw size={18} /> {isFlipped ? 'Question' : 'Show Answer'}
        </button>
        <button onClick={() => setCurrentIndex(prev => Math.min(deck.length - 1, prev + 1))} disabled={currentIndex === deck.length - 1} className="h-16 w-16 rounded-3xl bg-white border border-slate-200 shadow-sm flex items-center justify-center text-slate-400 active:scale-90 disabled:opacity-20 transition-all">
          <ChevronRight size={32} />
        </button>
      </div>

      {/* Filter Modal */}
      {isFilterOpen && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-slate-950/60 backdrop-blur-sm animate-in fade-in duration-200">
           <div className="w-full max-w-md bg-white rounded-t-[2.5rem] sm:rounded-[2.5rem] shadow-2xl overflow-hidden animate-in slide-in-from-bottom duration-300">
              <div className="p-6 border-b flex justify-between items-center bg-slate-50">
                 <h3 className="font-black text-slate-800 uppercase text-sm tracking-tight">Library Categories</h3>
                 <button onClick={() => setIsFilterOpen(false)} className="p-2 hover:bg-slate-200 rounded-full transition-colors"><X size={20} /></button>
              </div>
              <div className="p-2 max-h-[60vh] overflow-y-auto custom-scrollbar">
                 <div className="grid gap-1">
                    <button 
                      onClick={() => setSelectedCategories([])}
                      className="flex items-center gap-3 p-4 hover:bg-slate-50 rounded-2xl transition-colors text-left"
                    >
                      <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center ${selectedCategories.length === 0 ? 'bg-blue-600 border-blue-600 text-white' : 'border-slate-200'}`}>
                        {selectedCategories.length === 0 && <Check size={14} strokeWidth={4} />}
                      </div>
                      <span className="text-sm font-black text-slate-700 uppercase">All Systems</span>
                    </button>
                    <div className="h-px bg-slate-100 my-1 mx-4"></div>
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => toggleCategory(cat)}
                        className="flex items-center gap-3 p-4 hover:bg-slate-50 rounded-2xl transition-colors text-left"
                      >
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${selectedCategories.includes(cat) ? 'bg-blue-600 border-blue-600 text-white' : 'border-slate-200'}`}>
                          {selectedCategories.includes(cat) && <Check size={14} strokeWidth={4} />}
                        </div>
                        <span className="text-sm font-bold text-slate-600">{cat}</span>
                      </button>
                    ))}
                 </div>
              </div>
              <div className="p-6 bg-slate-50 border-t">
                 <button onClick={() => setIsFilterOpen(false)} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-lg shadow-blue-200">Apply Filter</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Trophy, RotateCw, ImageOff, 
  CheckCircle2, AlertCircle, ListRestart, 
  Eye, BarChart3, Timer, Hash, Layers, Check, Filter, Zap, Sliders
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=800&fit=contain`;
  }
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // --- Restore Advanced Settings ---
  const [mode, setMode] = useState<'exam' | 'practice'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [shuffleOptions, setShuffleOptions] = useState(true);

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    if (showImagesOnly) pool = pool.filter(q => !!q.questionImage);
    return pool.length;
  }, [data, selectedCategories, showImagesOnly]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
  }, [maxPossible, questionCount]);

  // Timer logic
  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            setView('results');
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  useEffect(() => { setImgError(false); }, [currentQIndex]);

  const startQuiz = () => {
    let pool = data;
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    if (showImagesOnly) pool = pool.filter(q => !!q.questionImage);

    const shuffledPool = [...pool].sort(() => Math.random() - 0.5);
    const selected = shuffledPool.slice(0, Math.min(questionCount, shuffledPool.length));

    const generated = selected.map(q => {
      const correct = q.answerText;
      let options = Array.from(new Set([...(q.options || []), correct]));

      if (shuffleOptions) options = options.sort(() => Math.random() - 0.5);

      options = options.slice(0, 4);
      while(options.length < 4) options.push(`Option ${options.length + 1}`);

      return { 
        id: q.id, 
        data: q, 
        options, 
        correctOption: correct, 
        userAnswer: null, 
        isFlagged: false 
      } as QuizQuestion;
    });

    setQuestions(generated);
    setCurrentQIndex(0);
    setTimeLeft(generated.length * 60);
    setView('playing');
  };

  const handleAnswer = (option: string) => {
    if (view === 'review' || questions[currentQIndex].userAnswer) return;
    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });

    if (mode === 'practice' && currentQIndex < questions.length - 1) {
      setTimeout(() => setCurrentQIndex(prev => prev + 1), 800);
    }
  };

  const toggleCategory = (cat: string) => {
    setSelectedCategories(prev => 
      prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]
    );
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-50 flex flex-col items-center p-4 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl bg-white rounded-[2.5rem] shadow-2xl border border-slate-200 overflow-hidden my-4">
           {/* Header */}
           <div className="bg-slate-900 p-10 text-white relative">
              <div className="relative z-10">
                <h2 className="text-4xl font-black tracking-tighter">Exam <span className="text-blue-500">Dashboard</span></h2>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mt-2">Precision Medical Assessment</p>
              </div>
              <Sliders className="absolute top-8 right-8 text-white/5" size={120} />
           </div>

           <div className="p-8 space-y-10">
              {/* Modes */}
              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Session Protocol</label>
                <div className="grid grid-cols-2 gap-3">
                  <button onClick={() => setMode('exam')} className={`py-5 rounded-2xl border-2 font-black text-xs uppercase transition-all flex flex-col items-center gap-2 ${mode === 'exam' ? 'border-blue-600 bg-blue-50 text-blue-700 shadow-md scale-[1.02]' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={18} /> Exam Mode
                  </button>
                  <button onClick={() => setMode('practice')} className={`py-5 rounded-2xl border-2 font-black text-xs uppercase transition-all flex flex-col items-center gap-2 ${mode === 'practice' ? 'border-blue-600 bg-blue-50 text-blue-700 shadow-md scale-[1.02]' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={18} /> Practice Mode
                  </button>
                </div>
              </div>

              {/* Multi-Category Selector */}
              <div className="space-y-4">
                <div className="flex justify-between items-center px-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Target Systems</label>
                  <button onClick={() => setSelectedCategories([])} className="text-[9px] font-black text-blue-600 uppercase underline">Select All</button>
                </div>
                <div className="bg-slate-50 rounded-3xl border p-4 max-h-[200px] overflow-y-auto custom-scrollbar grid gap-2">
                   {categories.map(cat => (
                     <button key={cat} onClick={() => toggleCategory(cat)} className={`flex items-center gap-3 p-3 rounded-xl transition-all text-left border ${selectedCategories.includes(cat) ? 'bg-white border-blue-200 text-blue-700 shadow-sm' : 'border-transparent text-slate-500 opacity-60'}`}>
                       <div className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${selectedCategories.includes(cat) ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white'}`}>
                         {selectedCategories.includes(cat) && <Check size={12} strokeWidth={4} />}
                       </div>
                       <span className="text-xs font-bold truncate">{cat}</span>
                     </button>
                   ))}
                </div>
              </div>

              {/* Toggles & Count */}
              <div className="grid md:grid-cols-2 gap-8">
                 <div className="space-y-4">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Question Volume: {questionCount}</label>
                    <input 
                      type="range" min="1" max={maxPossible || 1} 
                      value={questionCount} 
                      onChange={e => setQuestionCount(parseInt(e.target.value))} 
                      className="w-full accent-blue-600 h-2 bg-slate-100 rounded-full appearance-none"
                    />
                    <div className="flex justify-between text-[8px] font-black text-slate-300 uppercase">
                      <span>1 UNIT</span>
                      <span>MAX {maxPossible} UNITS</span>
                    </div>
                 </div>
                 <div className="space-y-3">
                    <button 
                      onClick={() => setShowImagesOnly(!showImagesOnly)}
                      className={`w-full p-4 rounded-2xl border-2 flex items-center justify-between transition-all ${showImagesOnly ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-400'}`}
                    >
                      <span className="text-[10px] font-black uppercase">Atlas Images Only</span>
                      <Zap size={14} className={showImagesOnly ? 'text-blue-600' : 'text-slate-200'} />
                    </button>
                    <button 
                      onClick={() => setShuffleOptions(!shuffleOptions)}
                      className={`w-full p-4 rounded-2xl border-2 flex items-center justify-between transition-all ${shuffleOptions ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-100 text-slate-400'}`}
                    >
                      <span className="text-[10px] font-black uppercase">Randomize Matrix</span>
                      <RotateCw size={14} className={shuffleOptions ? 'text-blue-600' : 'text-slate-200'} />
                    </button>
                 </div>
              </div>

              <button 
                onClick={startQuiz} 
                disabled={maxPossible === 0}
                className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-sm tracking-[0.3em] shadow-2xl shadow-slate-200 hover:bg-blue-600 active:scale-95 transition-all disabled:opacity-20"
              >
                Initiate Session
              </button>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-slate-50 overflow-hidden select-none">
      {/* Quiz Header */}
      <div className="bg-white border-b px-4 h-14 flex justify-between items-center shrink-0 z-10 shadow-sm">
         <div className="flex items-center gap-3">
            <div className="bg-slate-900 text-white text-[11px] px-3 py-1 rounded-lg font-black shadow-sm uppercase tracking-tighter">
              Item {currentQIndex + 1} / {questions.length}
            </div>
            {mode === 'exam' && (
              <div className={`flex items-center gap-1.5 font-mono font-black text-sm ${timeLeft < 60 ? 'text-red-500 animate-pulse' : 'text-slate-600'}`}>
                <Clock size={16} />
                {formatTime(timeLeft)}
              </div>
            )}
         </div>
         <button 
          onClick={() => confirm("Exit session?") && setView('setup')} 
          className="p-2 bg-slate-100 text-slate-400 rounded-xl transition-colors hover:bg-rose-50 hover:text-rose-500"
         >
           <X size={20} />
         </button>
      </div>

      {/* Main Content */}
      <div className="flex-1 overflow-y-auto p-4 md:p-6 custom-scrollbar">
         <div className="w-full max-w-2xl mx-auto space-y-6">
            <div className="bg-white p-6 md:p-10 rounded-[2.5rem] shadow-sm border border-slate-200 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-1.5 h-full bg-blue-600"></div>
              <span className="text-[9px] font-black text-blue-500 uppercase tracking-[0.2em] mb-4 block">{currentQ.data.category}</span>
              <h3 className="text-xl md:text-2xl font-black text-slate-800 leading-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
            </div>

            {currentQ.data.questionImage && !imgError && (
              <div className="w-full bg-white p-4 rounded-[2.5rem] border border-slate-200 shadow-sm flex justify-center group overflow-hidden">
                 <img 
                    src={getProxiedImageUrl(currentQ.data.questionImage)} 
                    className="max-h-[35vh] md:max-h-[45vh] object-contain transition-transform duration-700 hover:scale-110"
                    onError={() => setImgError(true)}
                 />
              </div>
            )}

            <div className="grid gap-3">
               {currentQ.options.map((opt, i) => {
                 const isSelected = currentQ.userAnswer === opt;
                 const isCorrect = opt === currentQ.correctOption;
                 const showFeedback = (mode === 'practice' && !!currentQ.userAnswer) || view === 'review';

                 let style = "bg-white border-2 border-slate-100 text-slate-700 shadow-sm";
                 if (isSelected) style = "border-blue-600 bg-blue-50/50 ring-2 ring-blue-500";

                 if (showFeedback) {
                   if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 ring-2 ring-emerald-500 shadow-emerald-100";
                   else if (isSelected) style = "border-rose-500 bg-rose-50 text-rose-900 ring-2 ring-rose-500 opacity-100";
                   else style = "opacity-40 bg-slate-50 border-slate-100 grayscale-[0.5]";
                 }

                 return (
                   <button 
                    key={i} 
                    onClick={() => handleAnswer(opt)}
                    disabled={showFeedback}
                    className={`w-full p-5 rounded-2xl text-left font-bold text-sm transition-all flex items-start gap-4 active:scale-[0.98] ${style}`}
                   >
                     <div className={`w-7 h-7 rounded-xl flex items-center justify-center text-xs shrink-0 font-black shadow-sm ${isSelected ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'}`}>
                       {String.fromCharCode(65 + i)}
                     </div>
                     <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                     {showFeedback && isCorrect && <CheckCircle2 size={18} className="ml-auto text-emerald-500 shrink-0" />}
                     {showFeedback && isSelected && !isCorrect && <AlertCircle size={18} className="ml-auto text-rose-500 shrink-0" />}
                   </button>
                 );
               })}
            </div>

            {((mode === 'practice' && !!currentQ.userAnswer) || view === 'review') && currentQ.data.explanation && (
              <div className="bg-white border-2 border-slate-100 p-8 rounded-[2.5rem] space-y-4 animate-fade-up">
                <div className="flex items-center gap-2 text-slate-400 font-black text-[10px] uppercase tracking-widest border-b pb-2">
                  <Zap size={14} className="text-blue-500" /> Medical Rationale
                </div>
                <p className="text-sm font-medium text-slate-600 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
              </div>
            )}
         </div>
      </div>

      {/* Footer */}
      <div className="bg-white border-t p-4 h-24 flex justify-between items-center gap-4 shrink-0 shadow-sm pb-safe px-6">
         <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="h-14 w-14 rounded-2xl bg-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-10 active:bg-slate-200 transition-colors">
           <ChevronLeft size={32} />
         </button>

         <button 
            onClick={() => currentQIndex === questions.length - 1 ? setView('results') : setCurrentQIndex(prev => prev + 1)}
            className={`flex-1 h-14 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 text-white shadow-emerald-200' : 'bg-slate-900 text-white shadow-slate-200'}`}
         >
            {currentQIndex === questions.length - 1 ? 'Terminate Exam' : 'Next Item'}
            <ChevronRight size={18} />
         </button>

         <button onClick={() => setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1))} disabled={currentQIndex === questions.length - 1} className="h-14 w-14 rounded-2xl bg-slate-100 flex items-center justify-center text-slate-400 disabled:opacity-10 active:bg-slate-200 transition-colors">
           <ChevronRight size={32} />
         </button>
      </div>

      {/* Results View */}
      {view === 'results' && (
        <div className="fixed inset-0 z-[200] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 animate-in zoom-in-95 duration-300">
           <div className="w-full max-w-sm bg-white rounded-[3rem] shadow-3xl overflow-hidden text-center flex flex-col">
              <div className="bg-slate-900 p-12 text-white relative overflow-hidden">
                 <div className="relative z-10">
                   <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl rotate-3">
                      <Trophy size={40} className="text-white" />
                   </div>
                   <h2 className="text-6xl font-black mb-1">{(questions.filter(q => q.userAnswer === q.correctOption).length / questions.length * 100).toFixed(0)}%</h2>
                   <p className="text-[9px] font-black uppercase text-blue-400 tracking-[0.4em]">Final Score</p>
                 </div>
                 <Zap className="absolute -bottom-10 -right-10 text-white/5 rotate-12" size={200} />
              </div>

              <div className="p-8 space-y-6 bg-white">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
                      <div className="text-xl font-black text-emerald-600">{questions.filter(q => q.userAnswer === q.correctOption).length}</div>
                      <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Correct</div>
                    </div>
                    <div className="bg-rose-50 p-4 rounded-2xl border border-rose-100">
                      <div className="text-xl font-black text-rose-600">{questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</div>
                      <div className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Mistakes</div>
                    </div>
                 </div>

                 <div className="grid grid-cols-2 gap-3">
                    <button onClick={() => { setView('review'); setCurrentQIndex(0); }} className="py-5 bg-white border-2 border-slate-900 text-slate-900 rounded-3xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 hover:bg-slate-50 active:scale-95 transition-all">
                      <Eye size={16} /> Review
                    </button>
                    <button onClick={() => setView('setup')} className="py-5 bg-slate-900 text-white rounded-3xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 shadow-xl active:scale-95 transition-all">
                      <ListRestart size={16} /> Re-Take
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

