                  : "text-slate-400 hover:text-white"
              }`}
            >
              <List size={14} />
              <span className="hidden sm:inline">Index</span>
            </button>
          </nav>

          <button 
            onClick={() => window.location.reload()}
            className="p-2.5 rounded-xl bg-white/5 border border-white/10 text-slate-500 hover:text-sky-400 transition-colors"
          >
            <RefreshCw size={16} />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, RotateCw, X, ChevronLeft, ChevronRight, Volume2, ImageOff, Check, CheckSquare, Square, BookOpen } from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=1000&fit=contain`;
  }
  return url;
};

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, hasSupport } = useSpeech();

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return Array.from(cats).sort();
  }, [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories]);

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const currentCard = deck[currentIndex];

  return (
    <div className="flex flex-col h-full w-full max-w-2xl mx-auto px-2 pb-safe bg-[#020617] overflow-hidden">

      {/* Top Status */}
      <div className="flex justify-between items-center px-2 py-4 shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-white/5 border border-white/10 px-4 py-1.5 rounded-full font-black text-[10px] text-sky-400 tracking-widest">
            {currentIndex + 1} / {deck.length}
          </div>
          <button 
            onClick={() => setIsFilterOpen(true)}
            className={`px-4 py-1.5 rounded-full font-black text-[10px] uppercase tracking-widest transition-all ${selectedCategories.length > 0 ? 'bg-[#d4af37] text-white' : 'bg-white/5 border border-white/10 text-slate-500'}`}
          >
            SYSTEMS: {selectedCategories.length || 'ALL'}
          </button>
        </div>
        <button 
          onClick={() => setDeck([...deck].sort(() => Math.random() - 0.5))} 
          className="p-2.5 bg-white/5 border border-white/10 rounded-xl text-slate-500 active:text-sky-400 transition-all"
        >
          <Shuffle size={16} />
        </button>
      </div>

      {/* Main Flashcard Body */}
      <div className="flex-1 relative perspective-1000 my-4 group">
        {deck.length > 0 && currentCard ? (
          <div 
            className={`w-full h-full relative transform-style-3d transition-transform duration-700 ease-out ${isFlipped ? 'rotate-y-180' : ''}`}
            onClick={flipCard}
          >
            {/* Front: Question Side */}
            <div className="absolute inset-0 w-full h-full bg-[#0f172a] rounded-[3rem] shadow-2xl border border-white/5 backface-hidden flex flex-col overflow-hidden">
              <div className="flex-1 p-8 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <div className="mb-6 w-full flex justify-center bg-white/5 p-4 rounded-3xl border border-white/5 shadow-inner">
                    <img 
                      src={getProxiedImageUrl(currentCard.questionImage)} 
                      className="max-h-[38vh] w-auto object-contain rounded-xl"
                      onError={() => setImgError(true)}
                    />
                  </div>
                )}
                <span className="text-[9px] font-black text-sky-500 uppercase tracking-[0.4em] mb-4">Scientific Inquiry</span>
                <h2 className="text-xl md:text-3xl font-black text-white leading-tight" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
              </div>
              <div className="h-12 bg-white/5 flex items-center justify-center gap-2">
                 <div className="w-1 h-1 bg-sky-500 rounded-full animate-ping"></div>
                 <span className="text-[8px] font-black text-slate-500 uppercase tracking-[0.4em]">Tap to analyze answer</span>
              </div>
            </div>

            {/* Back: Answer Side */}
            <div className="absolute inset-0 w-full h-full bg-gradient-to-br from-slate-900 to-black rounded-[3rem] shadow-[0_0_50px_rgba(212,175,55,0.1)] backface-hidden rotate-y-180 border border-[#d4af37]/30 flex flex-col overflow-hidden">
              <div className="flex-1 p-10 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                <span className="text-[9px] font-black text-[#d4af37] uppercase tracking-[0.4em] mb-6">Validated Rationale</span>
                <div className="text-2xl md:text-4xl font-black text-white leading-tight mb-8" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />

                {currentCard.explanation && (
                  <div className="bg-[#d4af37]/5 p-6 rounded-3xl border border-[#d4af37]/10 text-slate-300 text-xs md:text-sm leading-relaxed max-w-md italic" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                )}

                <div className="mt-10">
                   {hasSupport && (
                     <button onClick={(e) => { e.stopPropagation(); speak(currentCard.answerText, 'a'); }} className="p-5 bg-[#d4af37] hover:bg-[#b8952d] rounded-full text-white shadow-xl shadow-yellow-900/20 active:scale-90 transition-all">
                       <Volume2 size={28} />
                     </button>
                   )}
                </div>
              </div>
              <div className="h-12 bg-black/40 flex items-center justify-center">
                 <span className="text-[8px] font-black text-[#d4af37]/60 uppercase tracking-[0.4em]">Medical Knowledge Index v.25</span>
              </div>
            </div>
          </div>
        ) : null}
      </div>

      {/* Pro Controls */}
      <div className="flex items-center gap-4 p-4 shrink-0 pb-10">
        <button onClick={() => { setIsFlipped(false); setTimeout(() => setCurrentIndex(prev => Math.max(0, prev - 1)), 100); }} disabled={currentIndex === 0} className="h-16 w-16 rounded-3xl bg-white/5 border border-white/10 flex items-center justify-center text-slate-500 active:text-sky-400 disabled:opacity-10 transition-all">
          <ChevronLeft size={32} />
        </button>
        <button onClick={flipCard} className="flex-1 h-16 rounded-3xl bg-white text-slate-900 font-black uppercase text-xs tracking-[0.3em] shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-2">
          {isFlipped ? <BookOpen size={18} /> : <RotateCw size={18} />} {isFlipped ? 'Analyze Question' : 'Reveal Core'}
        </button>
        <button onClick={() => { setIsFlipped(false); setTimeout(() => setCurrentIndex(prev => Math.min(deck.length - 1, prev + 1)), 100); }} disabled={currentIndex === deck.length - 1} className="h-16 w-16 rounded-3xl bg-white/5 border border-white/10 flex items-center justify-center text-slate-500 active:text-sky-400 disabled:opacity-10 transition-all">
          <ChevronRight size={32} />
        </button>
      </div>

      {/* Filter Modal - Tortora Styled */}
      {isFilterOpen && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
           <div className="w-full max-w-md bg-[#0f172a] rounded-t-[3rem] sm:rounded-[3rem] shadow-[0_-20px_50px_rgba(0,0,0,0.5)] border-t border-white/10 overflow-hidden animate-in slide-in-from-bottom duration-500">
              <div className="p-8 border-b border-white/5 flex justify-between items-center bg-black/20">
                 <h3 className="font-black text-white uppercase text-sm tracking-[0.2em]">Select Medical System</h3>
                 <button onClick={() => setIsFilterOpen(false)} className="p-2 hover:bg-white/5 rounded-full text-slate-500"><X size={24} /></button>
              </div>
              <div className="p-4 max-h-[55vh] overflow-y-auto custom-scrollbar">
                 <div className="grid gap-2">
                    <button 
                      onClick={() => setSelectedCategories([])}
                      className={`flex items-center gap-4 p-5 rounded-2xl transition-all text-left ${selectedCategories.length === 0 ? 'bg-sky-500/10 border border-sky-500/20' : 'hover:bg-white/5 border border-transparent'}`}
                    >
                      <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center ${selectedCategories.length === 0 ? 'bg-sky-500 border-sky-500 text-white' : 'border-slate-700'}`}>
                        {selectedCategories.length === 0 && <Check size={14} strokeWidth={4} />}
                      </div>
                      <span className="text-sm font-black text-white uppercase tracking-wider">Comprehensive Access</span>
                    </button>
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
                        className={`flex items-center gap-4 p-5 rounded-2xl transition-all text-left border ${selectedCategories.includes(cat) ? 'bg-sky-500/10 border-sky-500/20' : 'border-transparent hover:bg-white/5'}`}
                      >
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${selectedCategories.includes(cat) ? 'bg-sky-500 border-sky-500 text-white' : 'border-slate-700'}`}>
                          {selectedCategories.includes(cat) && <Check size={14} strokeWidth={4} />}
                        </div>
                        <span className="text-sm font-bold text-slate-300">{cat}</span>
                      </button>
                    ))}
                 </div>
              </div>
              <div className="p-8 bg-black/40 border-t border-white/5">
                 <button onClick={() => setIsFilterOpen(false)} className="w-full py-5 bg-[#d4af37] text-white rounded-[1.5rem] font-black uppercase tracking-[0.3em] shadow-2xl shadow-yellow-900/20 active:scale-95 transition-all">Apply Filter</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  Trophy, RotateCw, ImageOff, 
  CheckCircle2, AlertCircle, ListRestart, 
  Eye, BarChart3, Timer, Check, Zap, Sliders, Activity, ShieldCheck
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=1000&fit=contain`;
  }
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    return pool.length;
  }, [data, selectedCategories]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
  }, [maxPossible, questionCount]);

  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(prev => prev <= 1 ? (setView('results'), 0) : prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  useEffect(() => { setImgError(false); }, [currentQIndex]);

  const startQuiz = () => {
    let pool = selectedCategories.length > 0 ? data.filter(q => selectedCategories.includes(q.category)) : data;
    const shuffled = [...pool].sort(() => Math.random() - 0.5).slice(0, Math.min(questionCount, pool.length));
    setQuestions(shuffled.map(q => ({
      id: q.id, data: q, options: Array.from(new Set([...(q.options || []), q.answerText])).sort(() => Math.random() - 0.5).slice(0, 4),
      correctOption: q.answerText, userAnswer: null, isFlagged: false
    } as QuizQuestion)));
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-[#020617] flex flex-col items-center p-4 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl bg-[#0f172a] rounded-[3.5rem] shadow-2xl border border-white/5 overflow-hidden my-8">
           <div className="bg-gradient-to-br from-slate-900 to-black p-12 text-white relative">
              <div className="relative z-10 space-y-2">
                <h2 className="text-5xl font-black tracking-tighter leading-none">PROFESSIONAL<br/><span className="text-sky-400">ASSESSMENT</span></h2>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.4em]">Validation Protocol v.4.2</p>
              </div>
              <Activity className="absolute top-10 right-10 text-sky-500/10" size={150} />
           </div>

           <div className="p-10 space-y-12">
              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`py-6 rounded-3xl border-2 font-black text-xs uppercase tracking-widest transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-sky-500 bg-sky-500/10 text-white' : 'border-slate-800 text-slate-500 bg-white/5'}`}>
                    <Timer size={20} /> Exam Mode
                  </button>
                  <button onClick={() => setMode('practice')} className={`py-6 rounded-3xl border-2 font-black text-xs uppercase tracking-widest transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-[#d4af37] bg-[#d4af37]/10 text-white' : 'border-slate-800 text-slate-500 bg-white/5'}`}>
                    <Eye size={20} /> Training
                  </button>
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] px-2">Target Registry Units: {questionCount}</label>
                <input type="range" min="1" max={maxPossible || 1} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-sky-500 h-2 bg-slate-800 rounded-full appearance-none" />
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] px-2">Anatomical System Select</label>
                <div className="bg-black/20 rounded-[2rem] border border-white/5 p-4 max-h-[220px] overflow-y-auto custom-scrollbar grid gap-2">
                   {categories.map(cat => (
                     <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`flex items-center gap-4 p-4 rounded-2xl transition-all text-left border ${selectedCategories.includes(cat) ? 'bg-sky-500/10 border-sky-500/20 text-white' : 'border-transparent text-slate-500 hover:bg-white/5'}`}>
                       <div className={`w-5 h-5 rounded border-2 flex items-center justify-center ${selectedCategories.includes(cat) ? 'bg-sky-500 border-sky-500' : 'border-slate-700'}`}>
                         {selectedCategories.includes(cat) && <Check size={12} strokeWidth={4} />}
                       </div>
                       <span className="text-xs font-bold truncate">{cat}</span>
                     </button>
                   ))}
                </div>
              </div>

              <button onClick={startQuiz} className="w-full py-7 bg-white text-slate-900 rounded-[2rem] font-black uppercase text-sm tracking-[0.4em] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">Initialize Exam</button>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-[#020617] overflow-hidden select-none">
      <div className="bg-[#0f172a] border-b border-white/5 px-6 h-16 flex justify-between items-center shrink-0 z-10 shadow-xl">
         <div className="flex items-center gap-4">
            <div className="bg-sky-500 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase">Unit {currentQIndex + 1} OF {questions.length}</div>
            {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
         </div>
         <button onClick={() => confirm("Exit protocol?") && setView('setup')} className="p-2 bg-white/5 text-slate-500 rounded-xl hover:text-rose-500"><X size={24} /></button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-gradient-to-b from-[#020617] to-[#0f172a]">
         <div className="w-full max-w-2xl mx-auto space-y-8">
            <div className="bg-white/5 p-8 md:p-12 rounded-[3.5rem] border border-white/5 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-1.5 h-full bg-sky-500"></div>
              <span className="text-[9px] font-black text-sky-400 uppercase tracking-[0.4em] mb-6 block">{currentQ.data.category}</span>
              <h3 className="text-2xl md:text-4xl font-black text-white leading-tight tracking-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
            </div>

            {currentQ.data.questionImage && !imgError && (
              <div className="w-full bg-white rounded-[3.5rem] p-6 border border-white/5 shadow-inner flex justify-center group overflow-hidden">
                 <img src={getProxiedImageUrl(currentQ.data.questionImage)} className="max-h-[35vh] md:max-h-[45vh] object-contain transition-transform duration-700 hover:scale-105" onError={() => setImgError(true)} />
              </div>
            )}

            <div className="grid gap-4">
               {currentQ.options.map((opt, i) => {
                 const isSelected = currentQ.userAnswer === opt;
                 const isCorrect = opt === currentQ.correctOption;
                 const showFeedback = (mode === 'practice' && !!currentQ.userAnswer) || view === 'review';
                 let style = "bg-white/5 border-2 border-white/5 text-slate-300";
                 if (isSelected) style = "border-sky-500 bg-sky-500/10 text-white shadow-[0_0_20px_rgba(14,165,233,0.1)]";
                 if (showFeedback) {
                   if (isCorrect) style = "border-emerald-500 bg-emerald-500/20 text-white";
                   else if (isSelected) style = "border-rose-500 bg-rose-500/20 text-white";
                   else style = "opacity-20 grayscale";
                 }
                 return (
                   <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-6 rounded-3xl text-left font-bold text-lg transition-all flex items-start gap-6 active:scale-[0.98] ${style}`}>
                     <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs shrink-0 font-black ${isSelected ? 'bg-sky-500 text-white' : 'bg-white/5 text-slate-500'}`}>{String.fromCharCode(65 + i)}</div>
                     <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                   </button>
                 );
               })}
            </div>

            {((mode === 'practice' && !!currentQ.userAnswer) || view === 'review') && currentQ.data.explanation && (
              <div className="bg-[#d4af37]/5 border border-[#d4af37]/20 p-8 rounded-[3.5rem] space-y-4 animate-fade-up">
                <div className="flex items-center gap-3 text-[#d4af37] font-black text-[10px] uppercase tracking-[0.4em] border-b border-[#d4af37]/10 pb-4">
                  <ShieldCheck size={16} /> Clinical Rationale
                </div>
                <p className="text-base text-slate-300 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
              </div>
            )}
         </div>
      </div>

      <div className="bg-[#0f172a] border-t border-white/5 p-6 h-28 flex justify-between items-center gap-6 shrink-0 shadow-2xl pb-safe">
         <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="h-16 w-16 rounded-3xl bg-white/5 border border-white/10 flex items-center justify-center text-slate-500 active:text-sky-400 disabled:opacity-5 transition-all"><ChevronLeft size={32} /></button>
         <button onClick={() => currentQIndex === questions.length - 1 ? setView('results') : setCurrentQIndex(prev => prev + 1)} className={`flex-1 h-16 rounded-3xl font-black uppercase text-xs tracking-[0.4em] shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-[#d4af37] text-white shadow-[#d4af37]/20' : 'bg-white text-slate-900'}`}>{currentQIndex === questions.length - 1 ? 'Terminate Protocol' : 'Forward Analysis'}</button>
         <button onClick={() => setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1))} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-3xl bg-white/5 border border-white/10 flex items-center justify-center text-slate-500 active:text-sky-400 disabled:opacity-5 transition-all"><ChevronRight size={32} /></button>
      </div>

      {view === 'results' && (
        <div className="fixed inset-0 z-[200] bg-black/95 backdrop-blur-2xl flex items-center justify-center p-4 animate-in zoom-in-95 duration-500">
           <div className="w-full max-w-sm bg-[#0f172a] rounded-[4rem] shadow-3xl overflow-hidden text-center flex flex-col border border-white/10">
              <div className="bg-gradient-to-br from-slate-900 to-black p-14 text-white relative">
                 <div className="w-24 h-24 bg-sky-500 rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-3xl rotate-3 border border-sky-400">
                    <Trophy size={48} className="text-white" />
                 </div>
                 <h2 className="text-7xl font-black mb-2">{(questions.filter(q => q.userAnswer === q.correctOption).length / questions.length * 100).toFixed(0)}%</h2>
                 <p className="text-[10px] font-black uppercase text-sky-400 tracking-[0.5em]">Score Reliability</p>
              </div>
              <div className="p-10 space-y-8">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="bg-emerald-500/10 p-5 rounded-3xl border border-emerald-500/20">
                      <div className="text-2xl font-black text-emerald-400">{questions.filter(q => q.userAnswer === q.correctOption).length}</div>
                      <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Validated</div>
                    </div>
                    <div className="bg-rose-500/10 p-5 rounded-3xl border border-rose-500/20">
                      <div className="text-2xl font-black text-rose-400">{questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</div>
                      <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Anomalies</div>
                    </div>
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => { setView('review'); setCurrentQIndex(0); }} className="py-6 bg-white/5 border border-white/10 text-white rounded-[2rem] font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 active:scale-95 transition-all">Review</button>
                    <button onClick={() => setView('setup')} className="py-6 bg-white text-slate-900 rounded-[2rem] font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 shadow-2xl active:scale-95 transition-all">Restart</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

