import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, RotateCw, X, ChevronLeft, ChevronRight, Volume2, BookOpen, Check } from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=1000&fit=contain`;
  }
  return url;
};

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);

  const { speak, cancel, hasSupport } = useSpeech();

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories]);

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const currentCard = deck[currentIndex];

  return (
    <div className="flex flex-col h-full w-full max-w-2xl mx-auto px-2 pb-safe bg-white overflow-hidden">

      {/* Selection Status */}
      <div className="flex justify-between items-center px-2 py-4 shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-slate-50 border border-slate-100 px-4 py-1.5 rounded-full font-black text-[10px] text-slate-400 tracking-widest uppercase">
            UNIT {currentIndex + 1} OF {deck.length}
          </div>
          <button 
            onClick={() => setIsFilterOpen(true)}
            className={`px-4 py-1.5 rounded-full font-black text-[10px] uppercase tracking-widest transition-all border ${selectedCategories.length > 0 ? 'bg-[#d4af37] text-white border-[#d4af37]' : 'bg-white border-slate-200 text-slate-500'}`}
          >
            FILTERS: {selectedCategories.length || 'ALL'}
          </button>
        </div>
        <button 
          onClick={() => setDeck([...deck].sort(() => Math.random() - 0.5))} 
          className="p-2.5 bg-slate-50 border border-slate-100 rounded-xl text-slate-400 hover:text-sky-500 transition-all"
        >
          <Shuffle size={16} />
        </button>
      </div>

      {/* Card Arena */}
      <div className="flex-1 relative perspective-1000 my-4 group">
        {deck.length > 0 && currentCard ? (
          <div 
            className={`w-full h-full relative transform-style-3d transition-transform duration-700 ease-out ${isFlipped ? 'rotate-y-180' : ''}`}
            onClick={flipCard}
          >
            {/* Front: Clinical Question */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-[3rem] shadow-2xl border border-slate-100 backface-hidden flex flex-col overflow-hidden">
              <div className="flex-1 p-8 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <div className="mb-6 w-full flex justify-center bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
                    <img 
                      src={getProxiedImageUrl(currentCard.questionImage)} 
                      className="max-h-[35vh] w-auto object-contain rounded-xl mix-blend-multiply"
                      onError={() => setImgError(true)}
                      alt="Anatomy"
                    />
                  </div>
                )}
                <span className="text-[9px] font-black text-sky-500 uppercase tracking-[0.3em] mb-4">Scientific Query</span>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 leading-snug" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
              </div>
              <div className="h-14 bg-slate-50 flex items-center justify-center gap-3">
                 <div className="w-1.5 h-1.5 bg-[#d4af37] rounded-full animate-pulse"></div>
                 <span className="text-[8px] font-black text-slate-400 uppercase tracking-[0.4em]">Tap for Rationale Analysis</span>
              </div>
            </div>

            {/* Back: Validated Answer */}
            <div className="absolute inset-0 w-full h-full bg-slate-50 rounded-[3rem] shadow-inner backface-hidden rotate-y-180 border border-slate-200 flex flex-col overflow-hidden">
              <div className="flex-1 p-10 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                <span className="text-[9px] font-black text-[#d4af37] uppercase tracking-[0.4em] mb-6">Medical Validation</span>
                <div className="text-2xl md:text-3xl font-black text-slate-900 leading-tight mb-8" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />

                {currentCard.explanation && (
                  <div className="bg-white p-6 rounded-[2rem] border border-slate-100 text-slate-500 text-xs md:text-sm leading-relaxed max-w-md shadow-sm italic" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                )}

                <div className="mt-8">
                   {hasSupport && (
                     <button onClick={(e) => { e.stopPropagation(); speak(currentCard.answerText, 'a'); }} className="p-5 bg-sky-500 hover:bg-sky-600 rounded-full text-white shadow-xl shadow-sky-100 active:scale-90 transition-all border-4 border-white">
                       <Volume2 size={24} />
                     </button>
                   )}
                </div>
              </div>
              <div className="h-14 bg-white border-t border-slate-100 flex items-center justify-center">
                 <span className="text-[8px] font-black text-[#d4af37] uppercase tracking-[0.3em]">Knowledge Index v.2025</span>
              </div>
            </div>
          </div>
        ) : null}
      </div>

      {/* Navigation Controls */}
      <div className="flex items-center gap-4 p-4 shrink-0 pb-12">
        <button onClick={() => { setIsFlipped(false); setTimeout(() => setCurrentIndex(prev => Math.max(0, prev - 1)), 50); }} disabled={currentIndex === 0} className="h-16 w-16 rounded-3xl bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-sky-500 active:scale-95 disabled:opacity-30 transition-all shadow-sm">
          <ChevronLeft size={32} />
        </button>
        <button onClick={flipCard} className="flex-1 h-16 rounded-3xl bg-slate-900 text-white font-black uppercase text-xs tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3">
          {isFlipped ? <BookOpen size={18} /> : <RotateCw size={18} />} {isFlipped ? 'Show Query' : 'Analyze'}
        </button>
        <button onClick={() => { setIsFlipped(false); setTimeout(() => setCurrentIndex(prev => Math.min(deck.length - 1, prev + 1)), 50); }} disabled={currentIndex === deck.length - 1} className="h-16 w-16 rounded-3xl bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-sky-500 active:scale-95 disabled:opacity-30 transition-all shadow-sm">
          <ChevronRight size={32} />
        </button>
      </div>

      {/* Filter Modal - Clinical Style */}
      {isFilterOpen && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="w-full max-w-md bg-white rounded-t-[3rem] sm:rounded-[3rem] shadow-3xl border-t border-slate-100 overflow-hidden animate-in slide-in-from-bottom duration-400">
              <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
                 <h3 className="font-black text-slate-800 uppercase text-xs tracking-[0.3em]">System Classification</h3>
                 <button onClick={() => setIsFilterOpen(false)} className="p-2 hover:bg-slate-100 rounded-full text-slate-400"><X size={20} /></button>
              </div>
              <div className="p-4 max-h-[50vh] overflow-y-auto custom-scrollbar">
                 <div className="grid gap-2">
                    <button 
                      onClick={() => setSelectedCategories([])}
                      className={`flex items-center gap-4 p-5 rounded-2xl transition-all text-left ${selectedCategories.length === 0 ? 'bg-sky-50 border border-sky-100' : 'hover:bg-slate-50 border border-transparent'}`}
                    >
                      <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center ${selectedCategories.length === 0 ? 'bg-sky-500 border-sky-500 text-white' : 'border-slate-200'}`}>
                        {selectedCategories.length === 0 && <Check size={14} strokeWidth={4} />}
                      </div>
                      <span className="text-xs font-black text-slate-700 uppercase tracking-widest">Full Library Access</span>
                    </button>
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
                        className={`flex items-center gap-4 p-5 rounded-2xl transition-all text-left border ${selectedCategories.includes(cat) ? 'bg-sky-50 border-sky-100 text-sky-700' : 'border-transparent hover:bg-slate-50'}`}
                      >
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${selectedCategories.includes(cat) ? 'bg-sky-500 border-sky-500 text-white' : 'border-slate-200'}`}>
                          {selectedCategories.includes(cat) && <Check size={14} strokeWidth={4} />}
                        </div>
                        <span className="text-xs font-bold text-slate-600">{cat}</span>
                      </button>
                    ))}
                 </div>
              </div>
              <div className="p-8 bg-slate-50 border-t border-slate-100">
                 <button onClick={() => setIsFilterOpen(false)} className="w-full py-5 bg-[#d4af37] text-white rounded-[1.5rem] font-black uppercase tracking-[0.25em] shadow-lg shadow-yellow-100 active:scale-95 transition-all">Confirm Selections</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  Trophy, RotateCw, CheckCircle2, AlertCircle, 
  Eye, Timer, Check, Activity, ShieldCheck, Sliders
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=1000&fit=contain`;
  }
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    return pool.length;
  }, [data, selectedCategories]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
  }, [maxPossible, questionCount]);

  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(prev => prev <= 1 ? (setView('results'), 0) : prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  const startQuiz = () => {
    let pool = selectedCategories.length > 0 ? data.filter(q => selectedCategories.includes(q.category)) : data;
    const shuffled = [...pool].sort(() => Math.random() - 0.5).slice(0, Math.min(questionCount, pool.length));
    setQuestions(shuffled.map(q => ({
      id: q.id, data: q, options: Array.from(new Set([...(q.options || []), q.answerText])).sort(() => Math.random() - 0.5).slice(0, 4),
      correctOption: q.answerText, userAnswer: null, isFlagged: false
    } as QuizQuestion)));
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-white flex flex-col items-center p-4 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl bg-white rounded-[3.5rem] shadow-2xl shadow-slate-100 border border-slate-100 overflow-hidden my-8">
           <div className="bg-slate-900 p-12 text-white relative">
              <div className="relative z-10 space-y-2">
                <h2 className="text-4xl font-black tracking-tighter leading-none uppercase">Academic <br/><span className="text-sky-400">Assessment</span></h2>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.5em]">Board Certification Protocol</p>
              </div>
              <Activity className="absolute top-10 right-10 text-white/5" size={150} />
           </div>

           <div className="p-10 space-y-12">
              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`py-6 rounded-3xl border-2 font-black text-xs uppercase tracking-widest transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-sky-500 bg-sky-50 text-sky-600 shadow-sm' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={20} /> Exam Mode
                  </button>
                  <button onClick={() => setMode('practice')} className={`py-6 rounded-3xl border-2 font-black text-xs uppercase tracking-widest transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-[#d4af37] bg-yellow-50/50 text-[#d4af37] shadow-sm' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={20} /> Practice
                  </button>
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-2 flex justify-between">
                   <span>Unit Volume</span>
                   <span className="text-sky-600">{questionCount} Qs</span>
                </label>
                <input type="range" min="1" max={maxPossible || 1} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-sky-500 h-1.5 bg-slate-100 rounded-full appearance-none" />
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-2">System Selection</label>
                <div className="bg-slate-50/50 rounded-[2rem] border border-slate-100 p-4 max-h-[220px] overflow-y-auto custom-scrollbar grid gap-2">
                   {categories.map(cat => (
                     <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`flex items-center gap-4 p-4 rounded-2xl transition-all text-left border ${selectedCategories.includes(cat) ? 'bg-white border-sky-100 text-sky-600 shadow-sm' : 'border-transparent text-slate-400 hover:bg-white'}`}>
                       <div className={`w-5 h-5 rounded border-2 flex items-center justify-center ${selectedCategories.includes(cat) ? 'bg-sky-500 border-sky-500 text-white' : 'border-slate-200'}`}>
                         {selectedCategories.includes(cat) && <Check size={12} strokeWidth={4} />}
                       </div>
                       <span className="text-xs font-bold truncate">{cat}</span>
                     </button>
                   ))}
                </div>
              </div>

              <button onClick={startQuiz} className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-sm tracking-[0.4em] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">Start Protocol</button>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden select-none">
      {/* Quiz Runner Header */}
      <div className="bg-white border-b border-slate-100 px-6 h-16 flex justify-between items-center shrink-0 z-10">
         <div className="flex items-center gap-4">
            <div className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase shadow-sm">ITEM {currentQIndex + 1} / {questions.length}</div>
            {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
         </div>
         <button onClick={() => confirm("Exit protocol?") && setView('setup')} className="p-2 bg-slate-50 text-slate-300 rounded-xl hover:text-rose-500 transition-colors"><X size={24} /></button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar">
         <div className="w-full max-w-2xl mx-auto space-y-8">
            <div className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-slate-100 shadow-xl shadow-slate-50 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-1.5 h-full bg-sky-500"></div>
              <span className="text-[9px] font-black text-sky-500 uppercase tracking-[0.3em] mb-6 block">{currentQ.data.category}</span>
              <h3 className="text-xl md:text-3xl font-black text-slate-900 leading-snug tracking-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
            </div>

            {currentQ.data.questionImage && !imgError && (
              <div className="w-full bg-slate-50 rounded-[3rem] p-6 border border-slate-100 flex justify-center group overflow-hidden">
                 <img src={getProxiedImageUrl(currentQ.data.questionImage)} className="max-h-[35vh] md:max-h-[45vh] object-contain mix-blend-multiply transition-transform duration-700 hover:scale-105" onError={() => setImgError(true)} />
              </div>
            )}

            <div className="grid gap-4">
               {currentQ.options.map((opt, i) => {
                 const isSelected = currentQ.userAnswer === opt;
                 const isCorrect = opt === currentQ.correctOption;
                 const showFeedback = (mode === 'practice' && !!currentQ.userAnswer) || view === 'review';

                 let style = "bg-white border-2 border-slate-50 text-slate-600 shadow-sm";
                 if (isSelected) style = "border-sky-500 bg-sky-50/30 text-slate-900 shadow-md";

                 if (showFeedback) {
                   if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-emerald-50";
                   else if (isSelected) style = "border-rose-500 bg-rose-50 text-rose-900 shadow-rose-50";
                   else style = "opacity-30 grayscale";
                 }
                 return (
                   <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-6 rounded-3xl text-left font-bold text-lg transition-all flex items-start gap-6 active:scale-[0.98] ${style}`}>
                     <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs shrink-0 font-black ${isSelected ? 'bg-sky-500 text-white' : 'bg-slate-50 text-slate-400'}`}>{String.fromCharCode(65 + i)}</div>
                     <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                   </button>
                 );
               })}
            </div>

            {((mode === 'practice' && !!currentQ.userAnswer) || view === 'review') && currentQ.data.explanation && (
              <div className="bg-slate-50 border border-slate-200 p-8 rounded-[3.5rem] space-y-4 animate-fade-up">
                <div className="flex items-center gap-3 text-[#d4af37] font-black text-[10px] uppercase tracking-[0.4em] border-b border-slate-200 pb-4">
