export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  Trophy, RotateCw, CheckCircle2, AlertCircle, 
  Eye, Timer, Check, Activity, ShieldCheck, Sliders
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=1000&fit=contain`;
  }
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

// Fix: Added missing QuizProps interface to satisfy React.FC type parameter and ensure proper type inference for props
interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    return pool.length;
  }, [data, selectedCategories]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
  }, [maxPossible, questionCount]);

  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(prev => prev <= 1 ? (setView('results'), 0) : prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  const startQuiz = () => {
    let pool = selectedCategories.length > 0 ? data.filter(q => selectedCategories.includes(q.category)) : data;
    const shuffled = [...pool].sort(() => Math.random() - 0.5).slice(0, Math.min(questionCount, pool.length));
    setQuestions(shuffled.map(q => ({
      id: q.id, data: q, options: Array.from(new Set([...(q.options || []), q.answerText])).sort(() => Math.random() - 0.5).slice(0, 4),
      correctOption: q.answerText, userAnswer: null, isFlagged: false
    } as QuizQuestion)));
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-white flex flex-col items-center p-4 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-xl bg-white rounded-[3.5rem] shadow-2xl shadow-slate-100 border border-slate-100 overflow-hidden my-8">
           <div className="bg-slate-900 p-12 text-white relative">
              <div className="relative z-10 space-y-2">
                <h2 className="text-4xl font-black tracking-tighter leading-none uppercase">Academic <br/><span className="text-sky-400">Assessment</span></h2>
                <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.5em]">Board Certification Protocol</p>
              </div>
              <Activity className="absolute top-10 right-10 text-white/5" size={150} />
           </div>

           <div className="p-10 space-y-12">
              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`py-6 rounded-3xl border-2 font-black text-xs uppercase tracking-widest transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-sky-500 bg-sky-50 text-sky-600 shadow-sm' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={20} /> Exam Mode
                  </button>
                  <button onClick={() => setMode('practice')} className={`py-6 rounded-3xl border-2 font-black text-xs uppercase tracking-widest transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-[#d4af37] bg-yellow-50/50 text-[#d4af37] shadow-sm' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={20} /> Practice
                  </button>
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-2 flex justify-between">
                   <span>Unit Volume</span>
                   <span className="text-sky-600">{questionCount} Qs</span>
                </label>
                <input type="range" min="1" max={maxPossible || 1} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-sky-500 h-1.5 bg-slate-100 rounded-full appearance-none" />
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-2">System Selection</label>
                <div className="bg-slate-50/50 rounded-[2rem] border border-slate-100 p-4 max-h-[220px] overflow-y-auto custom-scrollbar grid gap-2">
                   {/* Fix: Explicitly typed 'cat' as string to resolve 'unknown' type errors and ensure correct SetStateAction behavior */}
                   {categories.map((cat: string) => (
                     <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`flex items-center gap-4 p-4 rounded-2xl transition-all text-left border ${selectedCategories.includes(cat) ? 'bg-white border-sky-100 text-sky-600 shadow-sm' : 'border-transparent text-slate-400 hover:bg-white'}`}>
                       <div className={`w-5 h-5 rounded border-2 flex items-center justify-center ${selectedCategories.includes(cat) ? 'bg-sky-500 border-sky-500 text-white' : 'border-slate-200'}`}>
                         {selectedCategories.includes(cat) && <Check size={12} strokeWidth={4} />}
                       </div>
                       <span className="text-xs font-bold truncate">{cat}</span>
                     </button>
                   ))}
                </div>
              </div>

              <button onClick={startQuiz} className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-sm tracking-[0.4em] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">Start Protocol</button>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden select-none">
      {/* Quiz Runner Header */}
      <div className="bg-white border-b border-slate-100 px-6 h-16 flex justify-between items-center shrink-0 z-10">
         <div className="flex items-center gap-4">
            <div className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase shadow-sm">ITEM {currentQIndex + 1} / {questions.length}</div>
            {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
         </div>
         <button onClick={() => confirm("Exit protocol?") && setView('setup')} className="p-2 bg-slate-50 text-slate-300 rounded-xl hover:text-rose-500 transition-colors"><X size={24} /></button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar">
         {currentQ && (
         <div className="w-full max-w-2xl mx-auto space-y-8">
            <div className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-slate-100 shadow-xl shadow-slate-50 relative overflow-hidden">
              <div className="absolute top-0 left-0 w-1.5 h-full bg-sky-500"></div>
              <span className="text-[9px] font-black text-sky-500 uppercase tracking-[0.3em] mb-6 block">{currentQ.data.category}</span>
              <h3 className="text-xl md:text-3xl font-black text-slate-900 leading-snug tracking-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
            </div>

            {currentQ.data.questionImage && !imgError && (
              <div className="w-full bg-slate-50 rounded-[3rem] p-6 border border-slate-100 flex justify-center group overflow-hidden">
                 <img src={getProxiedImageUrl(currentQ.data.questionImage)} className="max-h-[35vh] md:max-h-[45vh] object-contain mix-blend-multiply transition-transform duration-700 hover:scale-105" onError={() => setImgError(true)} alt="Anatomical diagram" />
              </div>
            )}

            <div className="grid gap-4">
               {currentQ.options.map((opt, i) => {
                 const isSelected = currentQ.userAnswer === opt;
                 const isCorrect = opt === currentQ.correctOption;
                 const showFeedback = (mode === 'practice' && !!currentQ.userAnswer) || view === 'review';

                 let style = "bg-white border-2 border-slate-50 text-slate-600 shadow-sm";
                 if (isSelected) style = "border-sky-500 bg-sky-50/30 text-slate-900 shadow-md";

                 if (showFeedback) {
                   if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-emerald-50";
                   else if (isSelected) style = "border-rose-500 bg-rose-50 text-rose-900 shadow-rose-50";
                   else style = "opacity-30 grayscale";
                 }
                 return (
                   <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-6 rounded-3xl text-left font-bold text-lg transition-all flex items-start gap-6 active:scale-[0.98] ${style}`}>
                     <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs shrink-0 font-black ${isSelected ? 'bg-sky-500 text-white' : 'bg-slate-50 text-slate-400'}`}>{String.fromCharCode(65 + i)}</div>
                     <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                   </button>
                 );
               })}
            </div>

            {((mode === 'practice' && !!currentQ.userAnswer) || view === 'review') && currentQ.data.explanation && (
              <div className="bg-slate-50 border border-slate-200 p-8 rounded-[3.5rem] space-y-4 animate-fade-up">
                <div className="flex items-center gap-3 text-[#d4af37] font-black text-[10px] uppercase tracking-[0.4em] border-b border-slate-200 pb-4">
                  <ShieldCheck size={16} /> Clinical Rationale
                </div>
                <p className="text-base text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
              </div>
            )}
         </div>
         )}
      </div>

      {/* Footer Navigation */}
      <div className="bg-white border-t border-slate-100 p-6 h-28 flex justify-between items-center gap-6 shrink-0 shadow-[0_-10px_30px_rgba(0,0,0,0.02)] pb-safe px-8">
         <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="h-16 w-16 rounded-3xl bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-sky-500 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronLeft size={32} /></button>
         <button onClick={() => currentQIndex === questions.length - 1 ? setView('results') : setCurrentQIndex(prev => prev + 1)} className={`flex-1 h-16 rounded-3xl font-black uppercase text-xs tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-[#d4af37] text-white shadow-yellow-100' : 'bg-slate-900 text-white shadow-slate-100'}`}>{currentQIndex === questions.length - 1 ? 'Terminate Session' : 'Continue'}</button>
         <button onClick={() => setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1))} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-3xl bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-sky-500 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronRight size={32} /></button>
      </div>

      {/* Results Overlay */}
      {view === 'results' && (
        <div className="fixed inset-0 z-[200] bg-white/90 backdrop-blur-xl flex items-center justify-center p-4 animate-in zoom-in-95 duration-500">
           <div className="w-full max-w-sm bg-white rounded-[4rem] shadow-3xl overflow-hidden text-center flex flex-col border border-slate-100">
              <div className="bg-slate-900 p-14 text-white relative">
                 <div className="w-24 h-24 bg-sky-500 rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-2xl rotate-3 border-4 border-white/20">
                    <Trophy size={48} className="text-white" />
                 </div>
                 <h2 className="text-7xl font-black mb-2">{questions.length > 0 ? (questions.filter(q => q.userAnswer === q.correctOption).length / questions.length * 100).toFixed(0) : 0}%</h2>
                 <p className="text-[10px] font-black uppercase text-sky-400 tracking-[0.5em]">Score Reliability</p>
              </div>
              <div className="p-10 space-y-8 bg-white">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="bg-emerald-50 p-5 rounded-3xl border border-emerald-100">
                      <div className="text-2xl font-black text-emerald-600">{questions.filter(q => q.userAnswer === q.correctOption).length}</div>
                      <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Validated</div>
                    </div>
                    <div className="bg-rose-50 p-5 rounded-3xl border border-rose-100">
