              </div>
              <div className="p-8 bg-slate-50/50 border-t border-slate-100">
                 <button onClick={() => setIsFilterOpen(false)} className="w-full py-5 bg-slate-900 text-white rounded-[2rem] font-black uppercase tracking-[0.3em] shadow-xl active:scale-95 transition-all">Apply Analysis Filter</button>
