};

export default Flashcards;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  Trophy, RotateCw, CheckCircle2, AlertCircle, 
  Eye, Timer, Check, Activity, ShieldCheck, Sliders, LayoutGrid, Zap, Info, ChevronUp
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('quizlet.com')) {
    return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=1000&fit=contain`;
  }
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isMatrixOpen, setIsMatrixOpen] = useState(false);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    return pool.length;
  }, [data, selectedCategories]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
  }, [maxPossible, questionCount]);

  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(prev => prev <= 1 ? (setView('results'), 0) : prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  const startQuiz = () => {
    let pool = selectedCategories.length > 0 ? data.filter(q => selectedCategories.includes(q.category)) : data;
    const shuffled = [...pool].sort(() => Math.random() - 0.5).slice(0, Math.min(questionCount, pool.length));
    setQuestions(shuffled.map(q => ({
      id: q.id, data: q, options: Array.from(new Set([...(q.options || []), q.answerText])).sort(() => Math.random() - 0.5).slice(0, 4),
      correctOption: q.answerText, userAnswer: null, isFlagged: false
    } as QuizQuestion)));
    setCurrentQIndex(0);
    setTimeLeft(shuffled.length * 60);
    setView('playing');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-white flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-4xl grid lg:grid-cols-5 gap-8 my-8">

           {/* Left Controls */}
           <div className="lg:col-span-3 space-y-8 animate-in slide-in-from-left duration-700">
              <div className="bg-slate-900 rounded-[3rem] p-10 text-white relative overflow-hidden shadow-2xl">
                 <div className="relative z-10 space-y-2">
                   <h2 className="text-4xl font-black tracking-tighter uppercase leading-none italic">EXAM<br/><span className="text-sky-400 not-italic">OS v.4</span></h2>
                   <p className="text-[9px] font-black text-slate-500 uppercase tracking-[0.5em]">Tortora Principles Edition</p>
                 </div>
                 <Activity className="absolute -top-10 -right-10 text-white/5" size={240} />
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-sky-500 bg-sky-50 text-sky-600 ring-8 ring-sky-50' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Board Exam</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-[#d4af37] bg-yellow-50 text-[#d4af37] ring-8 ring-yellow-50' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Training</span>
                  </button>
              </div>

              <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-xl space-y-8">
                 <div className="flex justify-between items-center px-2">
                    <div className="flex flex-col">
                       <span className="text-xs font-black text-slate-800 uppercase tracking-widest">Anatomy Systems</span>
                       <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Select focus areas</span>
                    </div>
                    <button onClick={() => setSelectedCategories([])} className="text-[10px] font-black text-sky-500 uppercase underline">Select All</button>
                 </div>
                 <div className="grid sm:grid-cols-2 gap-3 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                    {categories.map(cat => (
                      <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`flex items-center gap-4 p-4 rounded-2xl transition-all text-left border-2 ${selectedCategories.includes(cat) ? 'bg-sky-50 border-sky-200 text-sky-700' : 'bg-white border-slate-50 hover:border-slate-200'}`}>
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${selectedCategories.includes(cat) ? 'bg-sky-500 border-sky-500 text-white shadow-md' : 'bg-white border-slate-200'}`}>
                          {selectedCategories.includes(cat) && <Check size={12} strokeWidth={4} />}
                        </div>
                        <span className="text-[11px] font-bold truncate uppercase">{cat}</span>
                      </button>
                    ))}
                 </div>
              </div>
           </div>

           {/* Right Preview/Start */}
           <div className="lg:col-span-2 space-y-8 animate-in slide-in-from-right duration-700">
              <div className="bg-slate-50 rounded-[3rem] p-10 border border-slate-200 shadow-inner flex flex-col gap-10 sticky top-10">
                 <div className="space-y-6">
                    <div className="flex justify-between items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                       <span>Volume Selection</span>
                       <span className="text-sky-600 bg-white px-3 py-1 rounded-full shadow-sm">{questionCount} UNITS</span>
                    </div>
                    <input type="range" min="1" max={maxPossible || 1} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-sky-500 h-2 bg-white border border-slate-200 rounded-full appearance-none shadow-sm cursor-pointer" />
                    <div className="flex justify-between text-[8px] font-black text-slate-300">
                       <span>MIN (1)</span>
                       <span>MAX ({maxPossible})</span>
                    </div>
                 </div>

                 <div className="bg-white rounded-[2rem] p-8 border border-slate-200 shadow-sm space-y-6">
                    <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest border-b pb-4">Session Briefing</h4>
                    <div className="space-y-4">
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-400">MODE:</span>
                          <span className="text-[10px] font-black text-slate-700 uppercase bg-slate-100 px-3 py-1 rounded-lg">{mode}</span>
                       </div>
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-400">FOCUS:</span>
                          <span className="text-[10px] font-black text-slate-700 uppercase bg-slate-100 px-3 py-1 rounded-lg">{selectedCategories.length || 'ALL'} SYSTEMS</span>
                       </div>
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-400">EST. TIME:</span>
                          <span className="text-[10px] font-black text-slate-700 uppercase bg-slate-100 px-3 py-1 rounded-lg">{questionCount} MINUTES</span>
                       </div>
                    </div>
                 </div>

                 <button onClick={startQuiz} className="w-full py-8 bg-sky-500 text-white rounded-[2.5rem] font-black uppercase text-base tracking-[0.4em] shadow-2xl shadow-sky-100 hover:bg-sky-600 hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-4">
                    <Zap size={24} /> INITIALIZE
                 </button>
              </div>
           </div>

        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden select-none lg:flex-row">

      {/* Side Navigation Matrix (Desktop) */}
      <aside className="hidden lg:flex flex-col w-72 bg-slate-50 border-r border-slate-100 shrink-0 p-6 overflow-y-auto custom-scrollbar">
         <div className="space-y-6">
            <div className="flex items-center justify-between border-b border-slate-200 pb-4">
               <h3 className="font-black text-[10px] uppercase text-slate-400 tracking-[0.2em] flex items-center gap-2">
                  <LayoutGrid size={14} /> Item Matrix
               </h3>
               <span className="text-[10px] font-black text-sky-600 bg-white border border-slate-200 px-3 py-1 rounded-lg shadow-sm">{questions.length} Total</span>
            </div>

            <div className="grid grid-cols-4 gap-2">
               {questions.map((_, i) => (
                 <button 
                  key={i} 
                  onClick={() => setCurrentQIndex(i)}
                  className={`h-12 rounded-xl text-xs font-black transition-all flex items-center justify-center border-2 shadow-sm ${
                    currentQIndex === i 
                      ? 'bg-sky-500 border-sky-400 text-white ring-4 ring-sky-50' 
                      : questions[i].userAnswer 
                        ? 'bg-slate-100 border-slate-200 text-slate-400 opacity-60' 
                        : 'bg-white border-white text-slate-400 hover:border-sky-100'
                  }`}
                 >
                   {i + 1}
                 </button>
               ))}
            </div>
         </div>
      </aside>

      {/* Main Container */}
      <div className="flex-1 flex flex-col min-w-0 relative">
        {/* Header */}
        <div className="bg-white border-b border-slate-100 px-6 h-16 flex justify-between items-center shrink-0 z-10">
           <div className="flex items-center gap-4">
              <button 
                onClick={() => setIsMatrixOpen(!isMatrixOpen)} 
                className="lg:hidden p-2 bg-slate-50 text-slate-400 rounded-xl"
              >
                <LayoutGrid size={20} />
              </button>
              <div className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase shadow-sm">ITEM {currentQIndex + 1} / {questions.length}</div>
              {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
           </div>
           <button onClick={() => confirm("Exit protocol?") && setView('setup')} className="p-2 bg-slate-50 text-slate-300 rounded-xl hover:text-rose-500 transition-colors"><X size={24} /></button>
        </div>

        {/* Question Area */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/30">
           {currentQ && (
           <div className="w-full max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-slate-100 shadow-xl shadow-slate-100 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-sky-500 shadow-[0_0_15px_rgba(14,165,233,0.5)]"></div>
