           <button onClick={() => setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1))} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-sky-500 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronRight size={32} /></button>
        </div>
      </div>

      {/* Mobile Matrix Drawer */}
      {isMatrixOpen && (
        <div className="fixed inset-0 z-[150] lg:hidden animate-in fade-in duration-300">
