              </div>
              <div className="grid grid-cols-5 gap-3 pb-20">
                 {questions.map((_, i) => (
                   <button 
                    key={i} 
                    onClick={() => { setCurrentQIndex(i); setIsMatrixOpen(false); }}
                    className={`h-14 rounded-2xl text-xs font-black border-2 transition-all flex items-center justify-center ${currentQIndex === i ? 'bg-sky-500 border-sky-400 text-white shadow-lg' : questions[i].userAnswer ? 'bg-slate-50 border-slate-100 text-slate-300' : 'bg-white border-slate-50 text-slate-500'}`}
                   >
