import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  Trophy, RotateCw, CheckCircle2, AlertCircle, 
  Eye, Timer, Check, Activity, ShieldCheck, Sliders, LayoutGrid, Zap, Info, ChevronUp, Image as ImageIcon
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=800&fit=contain&n=-1`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isMatrixOpen, setIsMatrixOpen] = useState(false);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    if (showImagesOnly) pool = pool.filter(q => q.questionImage || q.answerImage);
    return pool.length;
  }, [data, selectedCategories, showImagesOnly]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
  }, [maxPossible, questionCount]);

  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(prev => prev <= 1 ? (setView('results'), 0) : prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  // نظام الخيارات الذكية: توليد مشتتات من نفس القسم في حال نقص الخيارات
  const startQuiz = () => {
    let pool = data;
    if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
    if (showImagesOnly) pool = pool.filter(q => q.questionImage || q.answerImage);

    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, Math.min(questionCount, pool.length));

    const preparedQuestions = shuffledPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // إذا لم تتوفر خيارات كافية، نسحب خيارات "ذكية" من نفس القسم
      if (finalOptions.length < 4) {
        const categoryPool = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText);

        const smartDistractors = Array.from(new Set(categoryPool))
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...smartDistractors])).slice(0, 4);

        // إذا استمر النقص (قسم صغير جداً)، نسحب من أي مكان
        if (finalOptions.length < 4) {
           const fallbackDistractors = data
             .filter(item => item.answerText !== q.answerText)
             .map(item => item.answerText)
             .sort(() => Math.random() - 0.5)
             .slice(0, 4 - finalOptions.length);
           finalOptions = [...finalOptions, ...fallbackDistractors];
        }
      }

      return {
        id: q.id,
        data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60);
    setView('playing');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-white flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-4xl grid lg:grid-cols-5 gap-8 my-8 animate-in fade-in duration-700">

           {/* Left Controls */}
           <div className="lg:col-span-3 space-y-8">
              <div className="bg-slate-900 rounded-[3rem] p-10 text-white relative overflow-hidden shadow-2xl">
                 <div className="relative z-10 space-y-2">
                   <h2 className="text-4xl font-black tracking-tighter uppercase leading-none italic">BOARD<br/><span className="text-sky-400 not-italic">CERTIFICATION</span></h2>
                   <p className="text-[9px] font-black text-slate-500 uppercase tracking-[0.5em]">Global Medical Registry v.4.5</p>
                 </div>
                 <Activity className="absolute -top-10 -right-10 text-white/5" size={240} />
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-sky-500 bg-sky-50 text-sky-600 ring-8 ring-sky-50 shadow-lg' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Formal Exam</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-[#d4af37] bg-yellow-50 text-[#d4af37] ring-8 ring-yellow-50 shadow-lg' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Training Mode</span>
                  </button>
              </div>

              <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-xl space-y-8">
                 <div className="flex justify-between items-center px-2">
                    <div className="flex flex-col">
                       <span className="text-xs font-black text-slate-800 uppercase tracking-widest">Anatomy Systems</span>
                       <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Select focus areas</span>
                    </div>
                    <button 
                      onClick={() => setShowImagesOnly(!showImagesOnly)}
                      className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all flex items-center gap-2 border ${showImagesOnly ? 'bg-sky-500 text-white border-sky-500 shadow-md shadow-sky-100' : 'bg-slate-50 text-slate-400 border-transparent hover:bg-slate-100'}`}
                    >
                      <ImageIcon size={14} /> Atlas Mode
                    </button>
                 </div>
                 <div className="grid sm:grid-cols-2 gap-3 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                    {categories.map(cat => (
                      <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`flex items-center gap-4 p-4 rounded-2xl transition-all text-left border-2 ${selectedCategories.includes(cat) ? 'bg-sky-50 border-sky-200 text-sky-700' : 'bg-white border-slate-50 hover:border-slate-200'}`}>
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${selectedCategories.includes(cat) ? 'bg-sky-500 border-sky-500 text-white shadow-md' : 'bg-white border-slate-200'}`}>
                          {selectedCategories.includes(cat) && <Check size={12} strokeWidth={4} />}
                        </div>
                        <span className="text-[11px] font-bold truncate uppercase">{cat}</span>
                      </button>
                    ))}
                 </div>
              </div>
           </div>

           {/* Right Preview/Start */}
           <div className="lg:col-span-2 space-y-8">
              <div className="bg-slate-50 rounded-[3rem] p-10 border border-slate-200 shadow-inner flex flex-col gap-10 sticky top-10">
                 <div className="space-y-6">
                    <div className="flex justify-between items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
