                    </div>
                    <input type="range" min="1" max={maxPossible || 1} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-sky-500 h-2 bg-white border border-slate-200 rounded-full appearance-none shadow-sm cursor-pointer" />
                 </div>

                 <div className="bg-white rounded-[2rem] p-8 border border-slate-200 shadow-sm space-y-6">
                    <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest border-b pb-4">Session Briefing</h4>
                    <div className="space-y-4">
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-400 uppercase">Mode:</span>
                          <span className="text-[10px] font-black text-slate-700 uppercase bg-slate-100 px-3 py-1 rounded-lg">{mode}</span>
                       </div>
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-400 uppercase">Content:</span>
                          <span className="text-[10px] font-black text-slate-700 uppercase bg-slate-100 px-3 py-1 rounded-lg">{showImagesOnly ? 'Visuals' : 'Comprehensive'}</span>
                       </div>
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-400 uppercase">Batch Size:</span>
                          <span className="text-[10px] font-black text-sky-600 bg-sky-50 px-3 py-1 rounded-lg">{questionCount} items</span>
                       </div>
                    </div>
                 </div>

                 <button onClick={startQuiz} className="w-full py-8 bg-sky-500 text-white rounded-[2.5rem] font-black uppercase text-base tracking-[0.4em] shadow-2xl shadow-sky-100 hover:bg-sky-600 hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-4">
                    <Zap size={24} /> INITIALIZE
                 </button>
              </div>
           </div>

        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden select-none lg:flex-row">

      {/* Side Navigation Matrix (Question Blocks) */}
      <aside className="hidden lg:flex flex-col w-72 bg-slate-50 border-r border-slate-100 shrink-0 p-6 overflow-y-auto custom-scrollbar">
         <div className="space-y-6">
            <div className="flex items-center justify-between border-b border-slate-200 pb-4">
               <h3 className="font-black text-[10px] uppercase text-slate-400 tracking-[0.2em] flex items-center gap-2">
                  <LayoutGrid size={14} /> Item Registry
               </h3>
               <span className="text-[10px] font-black text-sky-600 bg-white border border-slate-200 px-3 py-1 rounded-lg shadow-sm">{questions.length} Items</span>
            </div>

            <div className="grid grid-cols-4 gap-2">
               {questions.map((_, i) => (
                 <button 
                  key={i} 
                  onClick={() => setCurrentQIndex(i)}
                  className={`h-12 rounded-xl text-xs font-black transition-all flex items-center justify-center border-2 shadow-sm ${
                    currentQIndex === i 
                      ? 'bg-sky-500 border-sky-400 text-white ring-4 ring-sky-50 z-10 scale-110 shadow-lg' 
                      : questions[i].userAnswer 
                        ? 'bg-slate-200 border-slate-300 text-slate-500 opacity-80' 
                        : 'bg-white border-white text-slate-300 hover:border-sky-100 hover:text-sky-500'
                  }`}
                 >
                   {i + 1}
                 </button>
               ))}
            </div>
         </div>
      </aside>

      {/* Main Container */}
      <div className="flex-1 flex flex-col min-w-0 relative bg-white">
        {/* Runner Header */}
        <div className="bg-white border-b border-slate-100 px-6 h-16 flex justify-between items-center shrink-0 z-10">
           <div className="flex items-center gap-4">
              <button 
                onClick={() => setIsMatrixOpen(!isMatrixOpen)} 
                className="lg:hidden p-2 bg-slate-50 text-slate-400 rounded-xl"
              >
                <LayoutGrid size={20} />
              </button>
              <div className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase shadow-sm">ITEM {currentQIndex + 1} / {questions.length}</div>
              {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
           </div>
           <button onClick={() => confirm("Terminate assessment session?") && setView('setup')} className="p-2 bg-slate-50 text-slate-300 rounded-xl hover:text-rose-500 transition-colors"><X size={24} /></button>
        </div>

        {/* Assessment Area */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/20">
           {currentQ && (
           <div className="w-full max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-slate-100 shadow-xl shadow-slate-100 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-sky-500 shadow-[0_0_15px_rgba(14,165,233,0.5)]"></div>
                <span className="text-[9px] font-black text-sky-500 uppercase tracking-[0.3em] mb-6 block">{currentQ.data.category}</span>
                <h3 className="text-xl md:text-3xl font-black text-slate-900 leading-snug tracking-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
              </div>

              {currentQ.data.questionImage && !imgError && (
                <div className="w-full bg-white rounded-[3rem] p-6 border border-slate-100 shadow-sm flex justify-center group overflow-hidden">
                   <img src={getProxiedImageUrl(currentQ.data.questionImage)} className="max-h-[35vh] md:max-h-[45vh] object-contain mix-blend-multiply transition-transform duration-700 hover:scale-105" onError={() => setImgError(true)} alt="Clinical Diagram" />
                </div>
              )}

              <div className="grid gap-4">
                 {currentQ.options.map((opt, i) => {
                   const isSelected = currentQ.userAnswer === opt;
                   const isCorrect = opt === currentQ.correctOption;
                   const showFeedback = (mode === 'practice' && !!currentQ.userAnswer) || view === 'review';

                   let style = "bg-white border-2 border-slate-100 text-slate-600 shadow-sm";
                   if (isSelected) style = "border-sky-500 bg-sky-50/30 text-slate-900 shadow-md ring-4 ring-sky-50";

                   if (showFeedback) {
                     if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-emerald-50 ring-4 ring-emerald-50";
                     else if (isSelected) style = "border-rose-500 bg-rose-50 text-rose-900 shadow-rose-50 ring-4 ring-rose-50";
                     else style = "opacity-30 grayscale";
                   }
                   return (
                     <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-6 rounded-[2rem] text-left font-bold text-lg transition-all flex items-start gap-6 active:scale-[0.98] ${style}`}>
                       <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs shrink-0 font-black ${isSelected ? 'bg-sky-500 text-white shadow-lg shadow-sky-200' : 'bg-slate-50 text-slate-400'}`}>{String.fromCharCode(65 + i)}</div>
                       <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                     </button>
                   );
                 })}
              </div>

              {((mode === 'practice' && !!currentQ.userAnswer) || view === 'review') && currentQ.data.explanation && (
                <div className="bg-white border-2 border-slate-100 p-8 rounded-[3.5rem] space-y-4 animate-fade-up shadow-xl shadow-slate-100">
                  <div className="flex items-center gap-3 text-[#d4af37] font-black text-[10px] uppercase tracking-[0.4em] border-b border-slate-100 pb-4">
                    <ShieldCheck size={16} /> Clinical Rationale
                  </div>
                  <p className="text-base text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                </div>
              )}
           </div>
           )}
        </div>

        {/* Bottom Bar Controls */}
        <div className="bg-white border-t border-slate-100 p-6 h-28 flex justify-between items-center gap-6 shrink-0 shadow-[0_-10px_30px_rgba(0,0,0,0.02)] pb-safe px-8">
           <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-sky-500 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronLeft size={32} /></button>
           <button onClick={() => currentQIndex === questions.length - 1 ? setView('results') : setCurrentQIndex(prev => prev + 1)} className={`flex-1 h-16 rounded-[1.5rem] font-black uppercase text-xs tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 text-white shadow-emerald-100' : 'bg-slate-900 text-white shadow-slate-100'}`}>{currentQIndex === questions.length - 1 ? 'Terminate Protocol' : 'Forward Analysis'}</button>
           <button onClick={() => setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1))} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-sky-500 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronRight size={32} /></button>
        </div>
      </div>

      {/* Mobile Registry Grid */}
      {isMatrixOpen && (
        <div className="fixed inset-0 z-[150] lg:hidden animate-in fade-in duration-300">
           <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsMatrixOpen(false)}></div>
           <div className="absolute bottom-0 left-0 right-0 bg-white rounded-t-[3rem] p-8 max-h-[80vh] overflow-y-auto custom-scrollbar animate-in slide-in-from-bottom duration-500 shadow-3xl border-t border-slate-100">
              <div className="flex justify-between items-center mb-8 border-b pb-4">
                 <h4 className="font-black uppercase text-xs text-slate-800 tracking-widest">Assessment Matrix</h4>
                 <button onClick={() => setIsMatrixOpen(false)} className="p-3 bg-slate-100 rounded-2xl text-slate-400"><X size={20} /></button>
              </div>
              <div className="grid grid-cols-5 gap-3 pb-20">
                 {questions.map((_, i) => (
                   <button 
                    key={i} 
                    onClick={() => { setCurrentQIndex(i); setIsMatrixOpen(false); }}
                    className={`h-14 rounded-2xl text-xs font-black border-2 transition-all flex items-center justify-center ${currentQIndex === i ? 'bg-sky-500 border-sky-400 text-white shadow-lg' : questions[i].userAnswer ? 'bg-slate-100 border-slate-200 text-slate-300' : 'bg-white border-slate-50 text-slate-500'}`}
                   >
                     {i + 1}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      {/* Final Results View */}
      {view === 'results' && (
        <div className="fixed inset-0 z-[200] bg-white/90 backdrop-blur-xl flex items-center justify-center p-4 animate-in zoom-in-95 duration-500">
           <div className="w-full max-w-sm bg-white rounded-[4rem] shadow-3xl overflow-hidden text-center flex flex-col border border-slate-100">
              <div className="bg-slate-900 p-14 text-white relative">
                 <div className="w-24 h-24 bg-sky-500 rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-2xl rotate-3 border-4 border-white/20">
                    <Trophy size={48} className="text-white" />
                 </div>
                 <h2 className="text-7xl font-black mb-2">{questions.length > 0 ? (questions.filter(q => q.userAnswer === q.correctOption).length / questions.length * 100).toFixed(0) : 0}%</h2>
                 <p className="text-[10px] font-black uppercase text-sky-400 tracking-[0.5em]">Session Proficiency Index</p>
              </div>
              <div className="p-10 space-y-8 bg-white">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="bg-emerald-50 p-5 rounded-3xl border border-emerald-100">
                      <div className="text-2xl font-black text-emerald-600">{questions.filter(q => q.userAnswer === q.correctOption).length}</div>
                      <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Validated</div>
                    </div>
                    <div className="bg-rose-50 p-5 rounded-3xl border border-rose-100">
                      <div className="text-2xl font-black text-rose-600">{questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</div>
                      <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Anomalies</div>
                    </div>
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => { setView('review'); setCurrentQIndex(0); }} className="py-6 bg-slate-50 border border-slate-200 text-slate-600 rounded-[2rem] font-black uppercase text-[10px] tracking-widest active:scale-95 transition-all">Review Mode</button>
                    <button onClick={() => setView('setup')} className="py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-[10px] tracking-widest shadow-xl active:scale-95 transition-all">Restart</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

