import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  Trophy, RotateCw, CheckCircle2, AlertCircle, 
  Eye, Timer, Check, Activity, ShieldCheck, LayoutGrid, Zap, Info, Image as ImageIcon, Flame, History
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=800&fit=contain&n=-1`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isMatrixOpen, setIsMatrixOpen] = useState(false);

  // نظام الأخطاء المستمر
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_vault');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_vault', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (mode === 'mistakes') {
      pool = data.filter(q => mistakesVault.includes(q.id));
    } else {
      if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
      if (showImagesOnly) pool = pool.filter(q => q.questionImage || q.answerImage);
    }
    return pool.length;
  }, [data, selectedCategories, showImagesOnly, mode, mistakesVault]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
    else if (maxPossible === 0 && questionCount !== 0) setQuestionCount(0);
  }, [maxPossible]);

  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(prev => prev <= 1 ? (handleFinish(), 0) : prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  const startQuiz = (selectedMode: 'exam' | 'practice' | 'mistakes') => {
    setMode(selectedMode);
    let pool = data;
    if (selectedMode === 'mistakes') {
      pool = data.filter(q => mistakesVault.includes(q.id));
    } else {
      if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
      if (showImagesOnly) pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) return alert("No questions match current criteria.");

    const count = selectedMode === 'mistakes' ? pool.length : Math.min(questionCount, pool.length);
    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, count);

    const preparedQuestions = shuffledPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];
      if (finalOptions.length < 4) {
        const categoryPool = data.filter(item => item.category === q.category && item.answerText !== q.answerText).map(item => item.answerText);
        const smartDistractors = Array.from(new Set(categoryPool)).sort(() => Math.random() - 0.5).slice(0, 4 - finalOptions.length);
        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...smartDistractors])).slice(0, 4);
        if (finalOptions.length < 4) {
           const fallbackDistractors = data.filter(item => item.answerText !== q.answerText).map(item => item.answerText).sort(() => Math.random() - 0.5).slice(0, 4 - finalOptions.length);
           finalOptions = [...finalOptions, ...fallbackDistractors];
        }
      }
      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60);
    setView('playing');
  };

  const handleFinish = () => {
    const wrongAnswers = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption);
    const newMistakeIds = Array.from(new Set([...mistakesVault, ...wrongAnswers.map(q => q.id)]));

    // إزالة الأسئلة التي تم حلها صح في وضع الأخطاء
    if (mode === 'mistakes') {
       const correctIds = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
       const remainingMistakes = newMistakeIds.filter(id => !correctIds.includes(id));
       setMistakesVault(remainingMistakes);
    } else {
       setMistakesVault(newMistakeIds);
    }

    setView('results');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-white flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-4xl grid lg:grid-cols-5 gap-8 my-8 animate-in fade-in duration-700">

           <div className="lg:col-span-3 space-y-8">
              <div className="bg-rose-600 rounded-[3rem] p-10 text-white relative overflow-hidden shadow-2xl">
                 <div className="relative z-10 space-y-2">
                   <h2 className="text-4xl font-black tracking-tighter uppercase leading-none italic">SURVIVAL<br/><span className="text-white/80 not-italic">PROTOCOL</span></h2>
                   <p className="text-[9px] font-black text-rose-200 uppercase tracking-[0.5em]">Clinical Assessment v.4.8</p>
                 </div>
                 <Activity className="absolute -top-10 -right-10 text-white/10" size={240} />
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-rose-500 bg-rose-50 text-rose-600 ring-8 ring-rose-50 shadow-lg' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Timed Exam</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-rose-600 bg-rose-50/50 text-rose-600 ring-8 ring-rose-50 shadow-lg' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Practice Mode</span>
                  </button>
              </div>

              {mistakesVault.length > 0 && (
                <button 
                  onClick={() => startQuiz('mistakes')}
                  className="w-full p-8 bg-slate-900 rounded-[2.5rem] text-white flex items-center justify-between group overflow-hidden relative shadow-2xl hover:scale-[1.01] transition-all"
                >
                  <div className="flex items-center gap-6 relative z-10">
                    <div className="w-14 h-14 bg-rose-600 rounded-2xl flex items-center justify-center shadow-lg group-hover:rotate-12 transition-transform">
                      <History size={28} />
                    </div>
                    <div className="text-left">
                      <h4 className="text-xl font-black uppercase tracking-tight">Mistakes Pharmacy</h4>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Re-evaluate {mistakesVault.length} anomaly cases</p>
                    </div>
                  </div>
                  <ChevronRight size={32} className="text-slate-700 group-hover:translate-x-2 transition-transform" />
                  <Flame className="absolute -right-4 bottom-0 text-white/5" size={120} />
                </button>
              )}

              <div className="bg-white rounded-[3rem] p-10 border border-slate-100 shadow-xl space-y-8">
                 <div className="flex justify-between items-center px-2">
                    <div className="flex flex-col">
                       <span className="text-xs font-black text-slate-800 uppercase tracking-widest">Anatomy Systems</span>
                       <span className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Focus Filter</span>
                    </div>
                    <button onClick={() => setShowImagesOnly(!showImagesOnly)} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all flex items-center gap-2 border ${showImagesOnly ? 'bg-rose-600 text-white border-rose-600 shadow-md shadow-rose-100' : 'bg-slate-50 text-slate-400 border-transparent hover:bg-slate-100'}`}><ImageIcon size={14} /> Visual Atlas</button>
                 </div>
                 <div className="grid sm:grid-cols-2 gap-3 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                    {categories.map(cat => (
                      <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`flex items-center gap-4 p-4 rounded-2xl transition-all text-left border-2 ${selectedCategories.includes(cat) ? 'bg-rose-50 border-rose-200 text-rose-700' : 'bg-white border-slate-50 hover:border-slate-200'}`}>
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${selectedCategories.includes(cat) ? 'bg-rose-600 border-rose-600 text-white shadow-md' : 'bg-white border-slate-200'}`}>{selectedCategories.includes(cat) && <Check size={12} strokeWidth={4} />}</div>
                        <span className="text-[11px] font-bold truncate uppercase">{cat}</span>
                      </button>
                    ))}
                 </div>
              </div>
           </div>

           <div className="lg:col-span-2 space-y-8">
              <div className="bg-slate-50 rounded-[3rem] p-10 border border-slate-200 shadow-inner flex flex-col gap-10 sticky top-10">
                 <div className="space-y-6">
                    <div className="flex justify-between items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                       <span>Batch Volume</span>
                       <span className="text-rose-600 bg-white px-3 py-1 rounded-full shadow-sm">{questionCount} Qs</span>
                    </div>
                    <input type="range" min="1" max={maxPossible || 1} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-rose-600 h-2 bg-white border border-slate-200 rounded-full appearance-none shadow-sm cursor-pointer" />
                 </div>

                 <div className="bg-white rounded-[2rem] p-8 border border-slate-200 shadow-sm space-y-6">
                    <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest border-b pb-4">Session Info</h4>
                    <div className="space-y-4">
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-400 uppercase">MODE:</span>
                          <span className="text-[10px] font-black text-slate-700 uppercase bg-slate-100 px-3 py-1 rounded-lg">{mode}</span>
                       </div>
                       <div className="flex items-center justify-between">
                          <span className="text-[10px] font-bold text-slate-400 uppercase">VAULT:</span>
                          <span className="text-[10px] font-black text-rose-600 bg-rose-50 px-3 py-1 rounded-lg">{questionCount} UNITS</span>
                       </div>
                    </div>
                 </div>

                 <button onClick={() => startQuiz(mode)} className="w-full py-8 bg-rose-600 text-white rounded-[2.5rem] font-black uppercase text-base tracking-[0.4em] shadow-2xl shadow-rose-200 hover:bg-rose-700 hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-4">
                    <Zap size={24} /> LAUNCH EXAM
                 </button>
              </div>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden select-none lg:flex-row">

      <aside className="hidden lg:flex flex-col w-72 bg-slate-50 border-r border-rose-50 shrink-0 p-6 overflow-y-auto custom-scrollbar">
         <div className="space-y-6">
            <div className="flex items-center justify-between border-b border-slate-200 pb-4">
               <h3 className="font-black text-[10px] uppercase text-slate-400 tracking-[0.2em] flex items-center gap-2"><LayoutGrid size={14} /> Matrix Map</h3>
               <span className="text-[10px] font-black text-rose-600 bg-white border border-slate-200 px-3 py-1 rounded-lg shadow-sm">{questions.length} Items</span>
            </div>
            <div className="grid grid-cols-4 gap-2">
               {questions.map((_, i) => (
                 <button key={i} onClick={() => setCurrentQIndex(i)} className={`h-12 rounded-xl text-xs font-black transition-all flex items-center justify-center border-2 shadow-sm ${currentQIndex === i ? 'bg-rose-600 border-rose-500 text-white ring-4 ring-rose-50 z-10 scale-110 shadow-lg' : questions[i].userAnswer ? 'bg-slate-200 border-slate-300 text-slate-500 opacity-80' : 'bg-white border-white text-slate-300 hover:border-rose-100 hover:text-rose-500'}`}>{i + 1}</button>
               ))}
            </div>
         </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 relative">
        <div className="bg-white border-b border-rose-50 px-6 h-16 flex justify-between items-center shrink-0 z-10">
           <div className="flex items-center gap-4">
              <button onClick={() => setIsMatrixOpen(!isMatrixOpen)} className="lg:hidden p-2 bg-slate-50 text-slate-400 rounded-xl"><LayoutGrid size={20} /></button>
              <div className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase shadow-sm">ITEM {currentQIndex + 1} / {questions.length}</div>
              {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-500 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
           </div>
           <button onClick={() => confirm("Exit assessment?") && setView('setup')} className="p-2 bg-slate-50 text-slate-300 rounded-xl hover:text-rose-500 transition-colors"><X size={24} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/10">
           {currentQ && (
           <div className="w-full max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-rose-50 shadow-xl shadow-rose-50/50 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-rose-600 shadow-[0_0_15px_rgba(225,29,72,0.5)]"></div>
                <span className="text-[9px] font-black text-rose-500 uppercase tracking-[0.3em] mb-6 block">{currentQ.data.category}</span>
                <h3 className="text-xl md:text-3xl font-black text-slate-900 leading-snug tracking-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
              </div>

              {currentQ.data.questionImage && !imgError && (
                <div className="w-full bg-white rounded-[3rem] p-6 border border-slate-100 shadow-sm flex justify-center group overflow-hidden">
                   <img src={getProxiedImageUrl(currentQ.data.questionImage)} className="max-h-[35vh] md:max-h-[45vh] object-contain mix-blend-multiply transition-transform duration-700 hover:scale-105" onError={() => setImgError(true)} alt="Medical Illustration" />
                </div>
              )}

              <div className="grid gap-4">
                 {currentQ.options.map((opt, i) => {
                   const isSelected = currentQ.userAnswer === opt;
                   const isCorrect = opt === currentQ.correctOption;
                   const showFeedback = ((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) || view === 'review';
                   let style = "bg-white border-2 border-slate-100 text-slate-600 shadow-sm";
                   if (isSelected) style = "border-rose-500 bg-rose-50/30 text-slate-900 shadow-md ring-4 ring-rose-50";
                   if (showFeedback) {
                     if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-emerald-50 ring-4 ring-emerald-50";
                     else if (isSelected) style = "border-rose-600 bg-rose-50 text-rose-900 shadow-rose-50 ring-4 ring-rose-50";
                     else style = "opacity-30 grayscale";
                   }
                   return (
                     <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-6 rounded-[2rem] text-left font-bold text-lg transition-all flex items-start gap-6 active:scale-[0.98] ${style}`}>
                       <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs shrink-0 font-black ${isSelected ? 'bg-rose-600 text-white shadow-lg shadow-rose-200' : 'bg-slate-50 text-slate-400'}`}>{String.fromCharCode(65 + i)}</div>
                       <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                     </button>
                   );
                 })}
              </div>

              {(((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) || view === 'review') && currentQ.data.explanation && (
                <div className="bg-white border-2 border-rose-50 p-8 rounded-[3.5rem] space-y-4 animate-fade-up shadow-xl shadow-rose-100/20">
                  <div className="flex items-center gap-3 text-rose-600 font-black text-[10px] uppercase tracking-[0.4em] border-b border-rose-50 pb-4">
                    <ShieldCheck size={16} /> Technical Analysis
                  </div>
                  <p className="text-base text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                </div>
              )}
           </div>
           )}
        </div>

        <div className="bg-white border-t border-slate-100 p-6 h-28 flex justify-between items-center gap-6 shrink-0 shadow-[0_-10px_30px_rgba(0,0,0,0.02)] pb-safe px-8">
           <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronLeft size={32} /></button>
           <button onClick={() => currentQIndex === questions.length - 1 ? handleFinish() : setCurrentQIndex(prev => prev + 1)} className={`flex-1 h-16 rounded-[1.5rem] font-black uppercase text-xs tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-rose-700 text-white shadow-rose-100' : 'bg-slate-900 text-white shadow-slate-100'}`}>{currentQIndex === questions.length - 1 ? 'End Session' : 'Next Item'}</button>
           <button onClick={() => setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1))} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronRight size={32} /></button>
        </div>
      </div>

      {isMatrixOpen && (
        <div className="fixed inset-0 z-[150] lg:hidden animate-in fade-in duration-300">
           <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsMatrixOpen(false)}></div>
           <div className="absolute bottom-0 left-0 right-0 bg-white rounded-t-[3rem] p-8 max-h-[80vh] overflow-y-auto custom-scrollbar animate-in slide-in-from-bottom duration-500 shadow-3xl border-t border-slate-100">
              <div className="flex justify-between items-center mb-8 border-b pb-4">
                 <h4 className="font-black uppercase text-xs text-slate-800 tracking-widest">Question Registry</h4>
                 <button onClick={() => setIsMatrixOpen(false)} className="p-3 bg-slate-100 rounded-2xl text-slate-400"><X size={20} /></button>
              </div>
              <div className="grid grid-cols-5 gap-3 pb-20">
                 {questions.map((_, i) => (
                   <button key={i} onClick={() => { setCurrentQIndex(i); setIsMatrixOpen(false); }} className={`h-14 rounded-2xl text-xs font-black border-2 transition-all flex items-center justify-center ${currentQIndex === i ? 'bg-rose-600 border-rose-500 text-white shadow-lg' : questions[i].userAnswer ? 'bg-slate-100 border-slate-200 text-slate-300' : 'bg-white border-slate-50 text-slate-500'}`}>{i + 1}</button>
                 ))}
              </div>
           </div>
        </div>
      )}

      {view === 'results' && (
        <div className="fixed inset-0 z-[200] bg-white/90 backdrop-blur-xl flex items-center justify-center p-4 animate-in zoom-in-95 duration-500">
           <div className="w-full max-w-sm bg-white rounded-[4rem] shadow-3xl overflow-hidden text-center flex flex-col border border-slate-100">
              <div className="bg-slate-900 p-14 text-white relative">
                 <div className="w-24 h-24 bg-rose-600 rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-2xl rotate-3 border-4 border-white/20"><Trophy size={48} className="text-white" /></div>
                 <h2 className="text-7xl font-black mb-2">{questions.length > 0 ? (questions.filter(q => q.userAnswer === q.correctOption).length / questions.length * 100).toFixed(0) : 0}%</h2>
                 <p className="text-[10px] font-black uppercase text-rose-400 tracking-[0.5em]">Clinical Reliability Index</p>
              </div>
              <div className="p-10 space-y-8 bg-white">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="bg-emerald-50 p-5 rounded-3xl border border-emerald-100"><div className="text-2xl font-black text-emerald-600">{questions.filter(q => q.userAnswer === q.correctOption).length}</div><div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Validated</div></div>
                    <div className="bg-rose-50 p-5 rounded-3xl border border-rose-100"><div className="text-2xl font-black text-rose-600">{questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</div><div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Anomaly</div></div>
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => { setView('review'); setCurrentQIndex(0); }} className="py-6 bg-slate-50 border border-slate-200 text-slate-600 rounded-[2rem] font-black uppercase text-[10px] tracking-widest active:scale-95 transition-all">Review</button>
                    <button onClick={() => setView('setup')} className="py-6 bg-rose-600 text-white rounded-[2rem] font-black uppercase text-[10px] tracking-widest shadow-xl active:scale-95 transition-all">Restart</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, RotateCw, X, ChevronLeft, ChevronRight, Volume2, BookOpen, Check, LayoutGrid, Image as ImageIcon } from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=800&fit=contain&n=-1`;
};

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [deck, setDeck] = useState<Question[]>(data);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);

  const { speak, cancel, hasSupport } = useSpeech();

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  useEffect(() => {
    let filtered = data;
    if (selectedCategories.length > 0) {
      filtered = data.filter(q => selectedCategories.includes(q.category || 'General'));
    }
    if (showImagesOnly) {
      filtered = filtered.filter(q => q.questionImage || q.answerImage);
    }
    setDeck(filtered);
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [data, selectedCategories, showImagesOnly]);

  const flipCard = useCallback(() => {
    if (!isAnimating) {
      setIsAnimating(true);
      setIsFlipped(prev => !prev);
      cancel();
      setTimeout(() => setIsAnimating(false), 300);
    }
  }, [isAnimating, cancel]);

  const currentCard = deck[currentIndex];

  return (
    <div className="flex flex-col h-full w-full max-w-2xl mx-auto px-2 pb-safe bg-white overflow-hidden">

      <div className="flex justify-between items-center px-2 py-4 shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-rose-50 border border-rose-100 px-4 py-1.5 rounded-full font-black text-[10px] text-rose-400 tracking-widest uppercase">
            UNIT {currentIndex + 1} / {deck.length}
          </div>
          <button 
            onClick={() => setIsFilterOpen(true)}
            className={`px-4 py-1.5 rounded-full font-black text-[10px] uppercase tracking-widest transition-all border shadow-sm flex items-center gap-2 ${selectedCategories.length > 0 || showImagesOnly ? 'bg-rose-600 text-white border-rose-600' : 'bg-white border-slate-200 text-slate-500'}`}
          >
            <LayoutGrid size={12} /> {showImagesOnly ? 'ATLAS' : (selectedCategories.length || 'ALL')}
          </button>
        </div>
        <button 
          onClick={() => setDeck([...deck].sort(() => Math.random() - 0.5))} 
          className="p-2.5 bg-rose-50 border border-rose-100 rounded-xl text-rose-400 hover:text-rose-600 transition-all"
        >
          <Shuffle size={16} />
        </button>
      </div>

      <div className="flex-1 relative perspective-1000 my-2 group">
        {deck.length > 0 && currentCard ? (
          <div 
            className={`w-full h-full relative transform-style-3d transition-transform duration-700 ease-out ${isFlipped ? 'rotate-y-180' : ''}`}
            onClick={flipCard}
          >
            <div className="absolute inset-0 w-full h-full bg-white rounded-[3rem] shadow-2xl border border-rose-50 backface-hidden flex flex-col overflow-hidden">
              <div className="flex-1 p-8 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <div className="mb-6 w-full flex justify-center bg-rose-50/30 p-6 rounded-[2.5rem] border border-rose-50 shadow-inner">
                    <img 
                      src={getProxiedImageUrl(currentCard.questionImage)} 
                      className="max-h-[35vh] w-auto object-contain rounded-xl mix-blend-multiply"
                      onError={() => setImgError(true)}
                      alt="Query Illustration"
                    />
                  </div>
                )}
                <span className="text-[9px] font-black text-rose-500 uppercase tracking-[0.3em] mb-4">Scientific Query</span>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 leading-snug" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
              </div>
              <div className="h-14 bg-rose-50/50 flex items-center justify-center gap-3">
                 <div className="w-1.5 h-1.5 bg-rose-600 rounded-full animate-pulse"></div>
                 <span className="text-[8px] font-black text-rose-400 uppercase tracking-[0.4em]">Tap for Rationale</span>
              </div>
            </div>

            <div className="absolute inset-0 w-full h-full bg-rose-50 rounded-[3rem] shadow-inner backface-hidden rotate-y-180 border border-rose-100 flex flex-col overflow-hidden">
              <div className="flex-1 p-10 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                <span className="text-[9px] font-black text-[#d4af37] uppercase tracking-[0.4em] mb-6">Medical Validation</span>
                <div className="text-2xl md:text-3xl font-black text-slate-900 leading-tight mb-8" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />

                {currentCard.explanation && (
                  <div className="bg-white p-6 rounded-[2rem] border border-rose-50 text-slate-500 text-xs md:text-sm leading-relaxed max-w-md shadow-sm italic" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                )}

                <div className="mt-8">
                   {hasSupport && (
                     <button onClick={(e) => { e.stopPropagation(); speak(currentCard.answerText, 'a'); }} className="p-5 bg-rose-600 hover:bg-rose-700 rounded-full text-white shadow-xl shadow-rose-100 active:scale-90 transition-all border-4 border-white">
                       <Volume2 size={24} />
                     </button>
                   )}
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-rose-200 border-4 border-dashed border-rose-50 rounded-[3rem]">
            <Filter size={48} className="mb-4 opacity-20" />
            <p className="font-black uppercase tracking-widest text-xs">Registry Empty</p>
          </div>
        )}
      </div>

      <div className="flex items-center gap-4 p-4 shrink-0 pb-12">
        <button onClick={() => { setIsFlipped(false); setTimeout(() => setCurrentIndex(prev => Math.max(0, prev - 1)), 50); }} disabled={currentIndex === 0} className="h-16 w-16 rounded-3xl bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 active:scale-95 disabled:opacity-30 transition-all shadow-sm">
          <ChevronLeft size={32} />
        </button>
        <button onClick={flipCard} className="flex-1 h-16 rounded-3xl bg-rose-600 text-white font-black uppercase text-xs tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3">
          {isFlipped ? <BookOpen size={18} /> : <RotateCw size={18} />} {isFlipped ? 'Show Query' : 'Analyze'}
        </button>
        <button onClick={() => { setIsFlipped(false); setTimeout(() => setCurrentIndex(prev => Math.min(deck.length - 1, prev + 1)), 50); }} disabled={currentIndex === deck.length - 1} className="h-16 w-16 rounded-3xl bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 active:scale-95 disabled:opacity-30 transition-all shadow-sm">
          <ChevronRight size={32} />
        </button>
      </div>

      {isFilterOpen && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
           <div className="w-full max-w-2xl bg-white rounded-t-[3rem] sm:rounded-[4rem] shadow-3xl border-t border-slate-100 overflow-hidden animate-in slide-in-from-bottom duration-500">
              <div className="p-8 border-b border-rose-50 flex justify-between items-center bg-white">
                 <div className="flex flex-col">
                    <h3 className="font-black text-slate-800 uppercase text-xs tracking-[0.3em]">Atlas Parameters</h3>
                    <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">Configure focus</p>
                 </div>
                 <button onClick={() => setIsFilterOpen(false)} className="p-3 bg-slate-50 hover:bg-slate-100 rounded-2xl text-slate-400 transition-all"><X size={20} /></button>
              </div>
              <div className="p-6 max-h-[60vh] overflow-y-auto custom-scrollbar">
                 <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    <button 
                      onClick={() => setShowImagesOnly(!showImagesOnly)}
                      className={`col-span-full flex items-center justify-between p-6 rounded-3xl transition-all border-2 mb-2 ${showImagesOnly ? 'bg-rose-50 border-rose-600 ring-4 ring-rose-50' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}
                    >
                      <div className="flex items-center gap-4">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center shadow-sm ${showImagesOnly ? 'bg-rose-600 text-white' : 'bg-white text-slate-400'}`}><ImageIcon size={22} /></div>
                        <div className="flex flex-col text-left"><span className="text-sm font-black text-slate-800 uppercase tracking-widest">Visual Atlas</span><span className="text-[9px] font-bold text-slate-400 uppercase">Diagrams only</span></div>
                      </div>
                      <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${showImagesOnly ? 'bg-rose-600 border-rose-600' : 'border-slate-300'}`}>{showImagesOnly && <Check size={14} className="text-white" strokeWidth={4} />}</div>
                    </button>
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
                        className={`flex items-center gap-4 p-5 rounded-3xl transition-all text-left border-2 ${selectedCategories.includes(cat) ? 'bg-rose-50 border-rose-200 ring-4 ring-rose-50' : 'bg-white border-slate-50 hover:border-slate-200'}`}
                      >
                        <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shadow-sm transition-all ${selectedCategories.includes(cat) ? 'bg-rose-600 text-white' : 'bg-slate-100 text-slate-400'}`}><BookOpen size={18} /></div>
                        <div className="flex flex-col overflow-hidden"><span className="text-xs font-black text-slate-700 uppercase tracking-tight truncate">{cat}</span><span className="text-[9px] font-bold text-slate-400 uppercase">Targeted</span></div>
                      </button>
                    ))}
