import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, Download, Upload, ShieldCheck, BookText, 
  Filter, ArrowUpDown, X, ChevronDown, Check, Highlighter,
  Volume2, VolumeX, Edit3, Type as TypeIcon
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
  onImport: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onEdit?: (id: string) => void;
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport, onImport, onEdit }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');
  const [isFilterMenuOpen, setIsFilterMenuOpen] = useState(false);

  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  const escapeRegExp = (string: string) => {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${escapeRegExp(term)})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;
    if (selectedCategory !== 'All') {
      result = result.filter(q => (q.category || 'General') === selectedCategory);
    }
    if (search.trim()) {
      const terms = search.toLowerCase().split(/\s+/).filter(Boolean);
      result = result.filter(q => {
        const qText = stripHtml(q.questionText).toLowerCase();
        const aText = stripHtml(q.answerText).toLowerCase();
        return terms.every(term => qText.includes(term) || aText.includes(term));
      });
    }
    if (sortOrder === 'asc') {
      result = [...result].sort((a, b) => stripHtml(a.questionText).localeCompare(stripHtml(b.questionText)));
    } else if (sortOrder === 'desc') {
      result = [...result].sort((a, b) => stripHtml(b.questionText).localeCompare(stripHtml(a.questionText)));
    }
    return result;
  }, [data, selectedCategory, search, sortOrder]);

  useEffect(() => {
    setCurrentPage(1);
  }, [search, selectedCategory, sortOrder]);

  useEffect(() => {
    return () => cancel();
  }, [currentPage, cancel]);

  const handleAudio = (e: React.MouseEvent, text: string, id: string) => {
    e.stopPropagation();
    if (isSpeaking && speakingId === id) cancel();
    else speak(text, id);
  };

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-32">
      {/* Search Header */}
      <div className="bg-rose-600 rounded-[2.5rem] p-8 md:p-12 mb-8 text-white relative overflow-hidden shadow-2xl shadow-rose-100 mt-6">
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-6">
          <div className="space-y-2">
            <h2 className="text-3xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">Anatomical<br/><span className="text-white/80 not-italic">Terminology</span></h2>
            <p className="text-[10px] font-black text-rose-200 uppercase tracking-[0.4em]">Searchable Knowledge Base v.2025</p>
          </div>

          <div className="relative group">
            <input 
              type="text" 
              placeholder="Search terms, systems, or definitions..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-14 pr-14 py-5 rounded-2xl bg-white/10 backdrop-blur-md border border-white/20 text-white placeholder:text-rose-200 outline-none focus:bg-white focus:text-slate-900 focus:ring-4 focus:ring-rose-400/30 transition-all text-lg font-bold"
            />
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-rose-200 group-focus-within:text-rose-500 transition-colors" size={24} />
            {search && (
              <button onClick={() => setSearch('')} className="absolute right-5 top-1/2 -translate-y-1/2 p-2 hover:bg-rose-500/20 rounded-full text-rose-200 transition-colors">
                <X size={20} />
              </button>
            )}
          </div>

          <div className="flex flex-wrap items-center gap-4">
            <div className="flex items-center gap-2 bg-black/20 px-4 py-2 rounded-full border border-white/10">
              <TypeIcon size={14} className="text-rose-300" />
              <span className="text-[10px] font-black uppercase tracking-widest">{processedData.length} Terms Found</span>
            </div>
            <div className="flex gap-2">
              <button onClick={onExport} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-xl border border-white/10 transition-colors"><Download size={16} /></button>
              <label className="p-2.5 bg-white/10 hover:bg-white/20 rounded-xl border border-white/10 transition-colors cursor-pointer"><Upload size={16} /><input type="file" className="hidden" accept=".json" onChange={onImport} /></label>
            </div>
          </div>
        </div>
      </div>

      {/* Action Bar */}
      <div className="flex gap-3 mb-8 sticky top-2 z-40">
        <div className="relative flex-1">
          <button 
            onClick={() => setIsFilterMenuOpen(!isFilterMenuOpen)}
            className={`w-full flex items-center justify-between px-6 py-4 bg-white border-2 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg transition-all ${selectedCategory !== 'All' ? 'border-rose-600 text-rose-600' : 'border-slate-100 text-slate-400'}`}
          >
            <span className="flex items-center gap-2 truncate">
              <Filter size={14} />
              <span className="truncate">{selectedCategory}</span>
            </span>
            <ChevronDown size={14} className={`transition-transform ${isFilterMenuOpen ? 'rotate-180' : ''}`} />
          </button>
          {isFilterMenuOpen && (
            <>
              <div className="fixed inset-0 z-10" onClick={() => setIsFilterMenuOpen(false)}></div>
              <div className="absolute top-full left-0 mt-3 w-full bg-white border border-slate-100 rounded-[2rem] shadow-3xl z-20 max-h-[60vh] overflow-y-auto custom-scrollbar p-4 animate-in slide-in-from-top-2 duration-300">
                {categories.map(cat => (
                  <button
                    key={cat}
                    onClick={() => { setSelectedCategory(cat); setIsFilterMenuOpen(false); }}
                    className={`w-full text-left px-5 py-3.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center justify-between mb-1 ${selectedCategory === cat ? 'bg-rose-50 text-rose-600' : 'text-slate-400 hover:bg-slate-50'}`}
                  >
                    {cat}
                    {selectedCategory === cat && <Check size={14} strokeWidth={4} />}
                  </button>
                ))}
              </div>
            </>
          )}
        </div>

        <button 
          onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
          className={`flex items-center justify-center gap-3 px-8 rounded-2xl font-black text-xs uppercase tracking-widest border-2 transition-all shadow-lg ${sortOrder !== 'default' ? 'bg-rose-600 text-white border-rose-600' : 'bg-white text-slate-400 border-slate-100'}`}
        >
          <ArrowUpDown size={14} />
          <span className="hidden sm:inline">{sortOrder === 'default' ? 'A-Z' : sortOrder === 'asc' ? 'Z-A' : 'Default'}</span>
        </button>
      </div>

      {/* Index Entries */}
      <div className="space-y-4">
        {processedData.length === 0 ? (
          <div className="text-center py-24 bg-slate-50/50 rounded-[3rem] border-2 border-dashed border-slate-200">
            <Search size={64} className="mx-auto text-slate-200 mb-6" />
            <p className="text-slate-400 font-black uppercase tracking-[0.3em] text-xs">No records matching query</p>
          </div>
        ) : (
          currentData.map((q) => (
            <div key={q.id} className="bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all duration-300 overflow-hidden flex flex-col md:flex-row group">
              {q.questionImage && (
                <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-6 shrink-0 overflow-hidden">
                  <img src={q.questionImage} alt="Reference" className="max-w-full max-h-full object-contain mix-blend-multiply transition-transform duration-500 group-hover:scale-110" loading="lazy" />
                </div>
              )}

              <div className="p-8 flex-1 flex flex-col gap-6">
                <div className="flex items-start justify-between gap-4">
                  <div className="flex flex-wrap items-center gap-2">
                    <span className="text-[9px] font-black uppercase text-rose-500 bg-rose-50 px-3 py-1 rounded-full border border-rose-100 tracking-widest">
                        {q.category}
                    </span>
                    {hasSupport && (
                      <button 
                        onClick={(e) => handleAudio(e, stripHtml(`${q.questionText}. Answer: ${q.answerText}`), q.id)}
                        className={`p-2 rounded-xl transition-all ${isSpeaking && speakingId === q.id ? 'bg-rose-600 text-white animate-pulse shadow-lg shadow-rose-200' : 'bg-slate-50 text-slate-400 hover:bg-rose-50 hover:text-rose-600'}`}
                      >
                        {isSpeaking && speakingId === q.id ? <VolumeX size={16} /> : <Volume2 size={16} />}
                      </button>
                    )}
                  </div>
                  {onEdit && (
                    <button onClick={() => onEdit(q.id)} className="p-2 text-slate-300 hover:text-sky-500 transition-colors"><Edit3 size={16} /></button>
                  )}
                </div>

                <div className="space-y-4">
                  <h3 
                    className="text-xl md:text-2xl font-black text-slate-800 leading-tight tracking-tight"
                    dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, search) }}
                  />
                  <div className="relative pl-6">
                    <div className="absolute left-0 top-0 bottom-0 w-1.5 bg-rose-500/20 rounded-full"></div>
                    <p 
                      className="text-base md:text-lg font-bold text-slate-500 leading-relaxed italic"
                      dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, search) }}
                    />
                  </div>
                </div>

                {q.explanation && (
                  <div className="bg-rose-50/30 p-5 rounded-2xl border border-rose-100/50 text-xs md:text-sm text-slate-400 leading-relaxed">
                    <span className="font-black text-rose-400 text-[9px] uppercase tracking-widest block mb-2 underline underline-offset-4">Analysis Note</span>
                    <span dangerouslySetInnerHTML={{ __html: highlightText(q.explanation, search) }} />
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-3 mt-12 mb-20">
          <button 
            onClick={() => { cancel(); setCurrentPage(prev => Math.max(1, prev - 1)); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
            disabled={currentPage === 1}
            className="h-14 px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] tracking-widest disabled:opacity-20 hover:bg-slate-50 transition-all shadow-md active:scale-95"
          >
            Previous
          </button>
          <div className="h-14 px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-[0.2em] shadow-xl">
            {currentPage} / {totalPages}
          </div>
          <button 
            onClick={() => { cancel(); setCurrentPage(prev => Math.min(totalPages, prev + 1)); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
            disabled={currentPage === totalPages}
            className="h-14 px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] tracking-widest disabled:opacity-20 hover:bg-slate-50 transition-all shadow-md active:scale-95"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

