import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  Trophy, RotateCw, AlertTriangle, 
  Eye, Timer, Check, Activity, ShieldCheck, LayoutGrid, Zap, Info, Image as ImageIcon, Flame, History, Heart
} from 'lucide-react';

const getProxiedImageUrl = (url: string) => {
  if (!url) return '';
  return `https://wsrv.nl/?url=${encodeURIComponent(url)}&w=800&fit=contain&n=-1`;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isMatrixOpen, setIsMatrixOpen] = useState(false);

  // نظام الأخطاء (Visible Mistakes Store)
  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (mode === 'mistakes') {
      pool = data.filter(q => mistakesVault.includes(q.id));
    } else {
      if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
      if (showImagesOnly) pool = pool.filter(q => q.questionImage || q.answerImage);
    }
    return pool.length;
  }, [data, selectedCategories, showImagesOnly, mode, mistakesVault]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
  }, [maxPossible]);

  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(prev => prev <= 1 ? (handleFinish(), 0) : prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  const startQuiz = (selectedMode: 'exam' | 'practice' | 'mistakes') => {
    let pool = data;
    if (selectedMode === 'mistakes') {
      pool = data.filter(q => mistakesVault.includes(q.id));
    } else {
      if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
      if (showImagesOnly) pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("System Registry: No matches found for this configuration.");
      return;
    }

    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, selectedMode === 'mistakes' ? pool.length : Math.min(questionCount, pool.length));

    const preparedQuestions = shuffledPool.map(q => {
      // Smart options generation
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);
        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors])).slice(0, 4);
        if (finalOptions.length < 4) {
           const generic = data.filter(item => item.answerText !== q.answerText).map(i => i.answerText).sort(() => Math.random() - 0.5).slice(0, 4-finalOptions.length);
           finalOptions = [...finalOptions, ...generic];
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setMode(selectedMode);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60);
    setView('playing');
  };

  const handleFinish = () => {
    // تحديث مخزن الأخطاء
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);

    setMistakesVault(prev => {
      // إضافة الأخطاء الجديدة
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      // إزالة ما تم حله صح في هذا الوضع تحديداً أو عموماً
      return added.filter(id => !correctOnes.includes(id));
    });

    setView('results');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-white flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-4xl grid lg:grid-cols-5 gap-8 my-8 animate-in fade-in duration-700">

           {/* Primary Controls */}
           <div className="lg:col-span-3 space-y-6">
              <div className="bg-rose-600 rounded-[3rem] p-10 text-white relative overflow-hidden shadow-2xl">
                 <div className="relative z-10 space-y-2">
                   <h2 className="text-4xl font-black tracking-tighter uppercase leading-none italic">SURVIVAL<br/><span className="text-rose-200 not-italic">EXAM SYSTEM</span></h2>
                   <p className="text-[10px] font-black text-rose-300 uppercase tracking-[0.4em]">Clinical Reliability Engine v.5.0</p>
                 </div>
                 <Activity className="absolute -top-10 -right-10 text-white/10" size={240} />
              </div>

              {/* Mode Selection */}
              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-rose-500 bg-rose-50 text-rose-600 ring-8 ring-rose-50 shadow-lg' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Formal Exam</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-rose-500 bg-rose-50 text-rose-600 ring-8 ring-rose-50 shadow-lg' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Clinical Review</span>
                  </button>
              </div>

              {/* MISTAKES SYSTEM (Visible Hub) */}
