                    <span className="text-xs font-black text-slate-800 uppercase tracking-widest flex items-center gap-2"><LayoutGrid size={16} className="text-rose-600"/> Physiological Systems</span>
                    <button onClick={() => setShowImagesOnly(!showImagesOnly)} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all flex items-center gap-2 border ${showImagesOnly ? 'bg-rose-600 text-white border-rose-600' : 'bg-slate-50 text-slate-400 border-transparent hover:bg-slate-100'}`}><ImageIcon size={14} /> Atlas Only</button>
                 </div>
                 <div className="grid sm:grid-cols-2 gap-3 max-h-[250px] overflow-y-auto custom-scrollbar pr-2">
                    {categories.map(cat => (
                      <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`flex items-center gap-4 p-4 rounded-2xl transition-all text-left border-2 ${selectedCategories.includes(cat) ? 'bg-rose-50 border-rose-200 text-rose-700' : 'bg-white border-slate-50 hover:border-slate-200'}`}>
                        <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${selectedCategories.includes(cat) ? 'bg-rose-600 border-rose-600 text-white' : 'bg-white border-slate-200'}`}>{selectedCategories.includes(cat) && <Check size={12} strokeWidth={4} />}</div>
