                    <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest border-b pb-4">Protocol Summary</h4>
                    <div className="space-y-4">
                       <div className="flex items-center justify-between"><span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Mode</span><span className="text-[10px] font-black text-rose-600 uppercase bg-rose-50 px-3 py-1 rounded-lg">{mode}</span></div>
                       <div className="flex items-center justify-between"><span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Load</span><span className="text-[10px] font-black text-slate-700 uppercase bg-slate-100 px-3 py-1 rounded-lg">{questionCount} Items</span></div>
