               <span className="text-[10px] font-black text-rose-600 bg-white border border-slate-200 px-3 py-1 rounded-lg shadow-sm">{questions.length}</span>
            </div>
            <div className="grid grid-cols-4 gap-2">
               {questions.map((_, i) => (
                 <button key={i} onClick={() => setCurrentQIndex(i)} className={`h-12 rounded-xl text-xs font-black transition-all flex items-center justify-center border-2 shadow-sm ${currentQIndex === i ? 'bg-rose-600 border-rose-500 text-white ring-4 ring-rose-100 z-10 scale-110 shadow-lg' : questions[i].userAnswer ? 'bg-slate-200 border-slate-300 text-slate-500 opacity-60' : 'bg-white border-white text-slate-300 hover:border-rose-100 hover:text-rose-600'}`}>{i + 1}</button>
               ))}
            </div>
