      </aside>

      <div className="flex-1 flex flex-col min-w-0 relative bg-white">
        {/* Mobile Header Runner */}
        <div className="bg-white border-b border-rose-50 px-6 h-16 flex justify-between items-center shrink-0 z-10 shadow-sm">
           <div className="flex items-center gap-4">
              <button onClick={() => setIsMatrixOpen(!isMatrixOpen)} className="lg:hidden p-2 bg-rose-50 text-rose-600 rounded-xl"><LayoutGrid size={20} /></button>
              <div className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase">ITEM {currentQIndex + 1} / {questions.length}</div>
              {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-600 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
           </div>
           <button onClick={() => confirm("Terminate assessment session?") && setView('setup')} className="p-2 bg-slate-50 text-slate-300 rounded-xl hover:text-rose-600 transition-colors"><X size={24} /></button>
