              <div className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-rose-50 shadow-xl shadow-rose-50 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-rose-600 shadow-[0_0_15px_rgba(225,29,72,0.5)]"></div>
                <span className="text-[9px] font-black text-rose-500 uppercase tracking-[0.3em] mb-6 block">{currentQ.data.category}</span>
                <h3 className="text-xl md:text-3xl font-black text-slate-900 leading-snug tracking-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
              </div>

              {currentQ.data.questionImage && !imgError && (
                <div className="w-full bg-white rounded-[3rem] p-6 border border-slate-100 shadow-sm flex justify-center group overflow-hidden">
                   <img src={getProxiedImageUrl(currentQ.data.questionImage)} className="max-h-[35vh] md:max-h-[45vh] object-contain mix-blend-multiply transition-transform duration-700 hover:scale-105" onError={() => setImgError(true)} alt="Clinical Diagram" />
                </div>
              )}

              <div className="grid gap-4">
                 {currentQ.options.map((opt, i) => {
                   const isSelected = currentQ.userAnswer === opt;
                   const isCorrect = opt === currentQ.correctOption;
                   const showFeedback = ((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) || view === 'review';

                   let style = "bg-white border-2 border-slate-100 text-slate-600 shadow-sm";
                   if (isSelected) style = "border-rose-500 bg-rose-50/50 text-slate-900 shadow-md ring-4 ring-rose-100";

                   if (showFeedback) {
                     if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-emerald-50 ring-4 ring-emerald-50";
                     else if (isSelected) style = "border-rose-600 bg-rose-50 text-rose-900 shadow-rose-100 ring-4 ring-rose-100";
                     else style = "opacity-30 grayscale";
                   }
                   return (
                     <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-6 rounded-[2rem] text-left font-bold text-lg transition-all flex items-start gap-6 active:scale-[0.98] ${style}`}>
                       <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs shrink-0 font-black ${isSelected ? 'bg-rose-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}>{String.fromCharCode(65 + i)}</div>
                       <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                     </button>
                   );
                 })}
              </div>

              {((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) && (
                <div className="bg-white border-2 border-rose-50 p-8 rounded-[3.5rem] space-y-4 animate-fade-up shadow-xl shadow-rose-50">
                  <div className="flex items-center gap-3 text-rose-600 font-black text-[10px] uppercase tracking-[0.4em] border-b border-rose-50 pb-4">
                    <ShieldCheck size={16} /> Clinical Rationale
                  </div>
                  <p className="text-base text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                </div>
              )}
           </div>
           )}
        </div>

        {/* Navigation Bar */}
        <div className="bg-white border-t border-slate-100 p-6 h-28 flex justify-between items-center gap-6 shrink-0 shadow-lg pb-safe px-8">
           <button onClick={() => setCurrentQIndex(prev => Math.max(0, prev - 1))} disabled={currentQIndex === 0} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronLeft size={32} /></button>
           <button onClick={() => currentQIndex === questions.length - 1 ? handleFinish() : setCurrentQIndex(prev => prev + 1)} className={`flex-1 h-16 rounded-[1.5rem] font-black uppercase text-xs tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-rose-700 text-white shadow-rose-200' : 'bg-slate-900 text-white shadow-slate-100'}`}>{currentQIndex === questions.length - 1 ? 'TERMINATE PROTOCOL' : 'FORWARD ANALYSIS'}</button>
           <button onClick={() => setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1))} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronRight size={32} /></button>
        </div>
      </div>

      {/* Mobile Matrix Registry */}
      {isMatrixOpen && (
        <div className="fixed inset-0 z-[150] lg:hidden animate-in fade-in duration-300">
           <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setIsMatrixOpen(false)}></div>
           <div className="absolute bottom-0 left-0 right-0 bg-white rounded-t-[3rem] p-8 max-h-[80vh] overflow-y-auto custom-scrollbar animate-in slide-in-from-bottom duration-500 shadow-3xl border-t border-rose-50">
              <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
                 <h4 className="font-black uppercase text-xs text-slate-800 tracking-widest">Question Registry Matrix</h4>
                 <button onClick={() => setIsMatrixOpen(false)} className="p-3 bg-rose-50 rounded-2xl text-rose-600"><X size={20} /></button>
              </div>
              <div className="grid grid-cols-5 gap-3 pb-20">
                 {questions.map((_, i) => (
                   <button 
                    key={i} 
                    onClick={() => { setCurrentQIndex(i); setIsMatrixOpen(false); }}
                    className={`h-14 rounded-2xl text-xs font-black border-2 transition-all flex items-center justify-center ${currentQIndex === i ? 'bg-rose-600 border-rose-500 text-white shadow-lg' : questions[i].userAnswer ? 'bg-rose-50 border-rose-100 text-rose-400' : 'bg-white border-slate-100 text-slate-300'}`}
                   >
                     {i + 1}
                   </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      {/* Final Performance Indices */}
      {view === 'results' && (
        <div className="fixed inset-0 z-[200] bg-slate-950/90 backdrop-blur-xl flex items-center justify-center p-4 animate-in zoom-in-95 duration-500">
           <div className="w-full max-w-sm bg-white rounded-[4rem] shadow-3xl overflow-hidden text-center flex flex-col border border-rose-50">
              <div className="bg-slate-900 p-14 text-white relative">
                 <div className="w-24 h-24 bg-rose-600 rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-2xl rotate-3 border-4 border-white/20">
                    <Trophy size={48} className="text-white" />
                 </div>
                 <h2 className="text-7xl font-black mb-2">{questions.length > 0 ? (questions.filter(q => q.userAnswer === q.correctOption).length / questions.length * 100).toFixed(0) : 0}%</h2>
                 <p className="text-[10px] font-black uppercase text-rose-400 tracking-[0.5em]">Clinical Performance Index</p>
              </div>
              <div className="p-10 space-y-8 bg-white">
                 <div className="grid grid-cols-2 gap-4">
                    <div className="bg-emerald-50 p-5 rounded-3xl border border-emerald-100">
                      <div className="text-2xl font-black text-emerald-600">{questions.filter(q => q.userAnswer === q.correctOption).length}</div>
                      <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Validated</div>
                    </div>
                    <div className="bg-rose-50 p-5 rounded-3xl border border-rose-100">
                      <div className="text-2xl font-black text-rose-600">{questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length}</div>
                      <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Anomaly</div>
                    </div>
                 </div>
                 <div className="flex flex-col gap-3">
                    <button onClick={() => { setView('review'); setCurrentQIndex(0); }} className="py-5 bg-slate-50 border border-slate-200 text-slate-600 rounded-[2rem] font-black uppercase text-[10px] tracking-widest active:scale-95 transition-all">Review Findings</button>
                    <button onClick={() => setView('setup')} className="py-6 bg-rose-600 text-white rounded-[2rem] font-black uppercase text-[10px] tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"><RotateCw size={16} /> RESTART SESSION</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Quiz;

import React, { useState, useMemo, useEffect } from 'react';
import { Question } from '../types';
import { 
  Search, Download, Upload, ShieldCheck, BookText, 
  Filter, ArrowUpDown, X, ChevronDown, Check, Highlighter,
  Volume2, VolumeX, Edit3, Type as TypeIcon, AlertTriangle
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
  onImport: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onEdit?: (id: string) => void;
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport, onImport, onEdit }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');
  const [isFilterMenuOpen, setIsFilterMenuOpen] = useState(false);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);

  const { speak, cancel, isSpeaking, speakingId, hasSupport } = useSpeech();

  // جلب الأخطاء من الـ LocalStorage
  const mistakesVault = useMemo(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  }, []);

  const stripHtml = (html: string) => {
    const tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;
    if (showMistakesOnly) {
      result = result.filter(q => mistakesVault.includes(q.id));
    }
    if (selectedCategory !== 'All') {
      result = result.filter(q => (q.category || 'General') === selectedCategory);
    }
    if (search.trim()) {
      const terms = search.toLowerCase().split(/\s+/).filter(Boolean);
      result = result.filter(q => {
        const qText = stripHtml(q.questionText).toLowerCase();
        const aText = stripHtml(q.answerText).toLowerCase();
        return terms.every(term => qText.includes(term) || aText.includes(term));
      });
    }
    if (sortOrder === 'asc') {
      result = [...result].sort((a, b) => stripHtml(a.questionText).localeCompare(stripHtml(b.questionText)));
    } else if (sortOrder === 'desc') {
      result = [...result].sort((a, b) => stripHtml(b.questionText).localeCompare(stripHtml(a.questionText)));
    }
    return result;
  }, [data, selectedCategory, search, sortOrder, showMistakesOnly, mistakesVault]);

  useEffect(() => {
    setCurrentPage(1);
  }, [search, selectedCategory, sortOrder, showMistakesOnly]);

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-32">
      <div className="bg-rose-600 rounded-[2.5rem] p-8 md:p-12 mb-8 text-white relative overflow-hidden shadow-2xl mt-6">
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-6">
          <div className="space-y-2">
            <h2 className="text-3xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">Global Knowledge<br/><span className="text-white/80 not-italic">Index</span></h2>
            <p className="text-[10px] font-black text-rose-200 uppercase tracking-[0.4em]">Medical Registry v.2025</p>
          </div>

          <div className="relative group">
            <input 
              type="text" 
              placeholder="Search definitions or systems..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-14 pr-14 py-5 rounded-2xl bg-white/10 backdrop-blur-md border border-white/20 text-white placeholder:text-rose-200 outline-none focus:bg-white focus:text-slate-900 transition-all text-lg font-bold"
            />
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-rose-200 group-focus-within:text-rose-500 transition-colors" size={24} />
          </div>

          <div className="flex flex-wrap items-center gap-4">
            <button 
              onClick={() => setShowMistakesOnly(!showMistakesOnly)}
              className={`flex items-center gap-2 px-4 py-2 rounded-full border transition-all ${showMistakesOnly ? 'bg-white text-rose-600 border-white' : 'bg-black/20 text-rose-200 border-white/10'}`}
            >
              <AlertTriangle size={14} />
              <span className="text-[10px] font-black uppercase">{mistakesVault.length} Anomaly Records</span>
            </button>
            <div className="flex gap-2">
              <button onClick={onExport} className="p-2.5 bg-white/10 hover:bg-white/20 rounded-xl border border-white/10 transition-colors"><Download size={16} /></button>
            </div>
          </div>
        </div>
      </div>

      <div className="flex gap-3 mb-8 sticky top-2 z-40">
        <div className="relative flex-1">
          <button 
            onClick={() => setIsFilterMenuOpen(!isFilterMenuOpen)}
            className={`w-full flex items-center justify-between px-6 py-4 bg-white border-2 rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg transition-all ${selectedCategory !== 'All' ? 'border-rose-600 text-rose-600' : 'border-slate-100 text-slate-400'}`}
          >
            <span className="flex items-center gap-2 truncate"><Filter size={14} />{selectedCategory}</span>
            <ChevronDown size={14} className={`transition-transform ${isFilterMenuOpen ? 'rotate-180' : ''}`} />
          </button>
          {isFilterMenuOpen && (
            <div className="absolute top-full left-0 mt-3 w-full bg-white border border-slate-100 rounded-[2rem] shadow-3xl z-20 max-h-[60vh] overflow-y-auto custom-scrollbar p-4 animate-in slide-in-from-top-2 duration-300">
              {categories.map(cat => (
                <button key={cat} onClick={() => { setSelectedCategory(cat); setIsFilterMenuOpen(false); }} className={`w-full text-left px-5 py-3.5 rounded-xl text-xs font-black uppercase transition-all mb-1 ${selectedCategory === cat ? 'bg-rose-50 text-rose-600' : 'text-slate-400 hover:bg-slate-50'}`}>{cat}</button>
              ))}
            </div>
          )}
        </div>
        <button 
          onClick={() => setSortOrder(prev => prev === 'default' ? 'asc' : prev === 'asc' ? 'desc' : 'default')}
          className={`flex items-center justify-center gap-3 px-8 rounded-2xl font-black text-xs uppercase border-2 transition-all shadow-lg ${sortOrder !== 'default' ? 'bg-rose-600 text-white border-rose-600' : 'bg-white text-slate-400 border-slate-100'}`}
        >
          <ArrowUpDown size={14} />
          <span className="hidden sm:inline">A-Z Sorting</span>
        </button>
      </div>

      <div className="space-y-4">
        {processedData.length === 0 ? (
          <div className="text-center py-24 bg-slate-50 rounded-[3rem] border-2 border-dashed border-slate-100">
            <Search size={64} className="mx-auto text-slate-200 mb-6" />
            <p className="text-slate-400 font-black uppercase tracking-widest text-xs">No matching medical records</p>
          </div>
        ) : (
          currentData.map((q) => (
            <div key={q.id} className="bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all overflow-hidden flex flex-col md:flex-row">
              {q.questionImage && (
                <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-6 shrink-0 overflow-hidden">
                   <img src={q.questionImage} alt="Diagram" className="max-w-full max-h-full object-contain mix-blend-multiply" loading="lazy" />
                </div>
              )}
              <div className="p-8 flex-1">
                <div className="flex items-center justify-between mb-4">
                  <span className="text-[9px] font-black uppercase text-rose-600 bg-rose-50 px-3 py-1 rounded-full border border-rose-100">{q.category}</span>
                  {mistakesVault.includes(q.id) && <AlertTriangle size={14} className="text-rose-500 animate-pulse" />}
                </div>
                <h3 className="text-xl font-black text-slate-800 leading-tight mb-4" dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, search) }} />
                <div className="relative pl-6 border-l-4 border-rose-100">
                  <p className="text-base font-bold text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, search) }} />
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-3 mt-12 mb-20">
          <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="h-14 px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Prev</button>
          <div className="h-14 px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-widest shadow-xl">{currentPage} / {totalPages}</div>
          <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="h-14 px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Next</button>
        </div>
      )}
    </div>
  );
};

export default QuestionList;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  Trophy, RotateCw, AlertTriangle, 
  Eye, Timer, Check, Activity, ShieldCheck, LayoutGrid, Zap, Info, Image as ImageIcon, Flame, History, Heart
} from 'lucide-react';

// وظيفة داخلية لإصلاح الروابط التالفة دون تدخل خارجي
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  // إذا كان الرابط يحتوي على رابطين متداخلين (مشكلة شائعة في Quizlet)
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    return url.substring(url.lastIndexOf('http'));
  }
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isMatrixOpen, setIsMatrixOpen] = useState(false);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category || 'General'))).sort(), [data]);

  const maxPossible = useMemo(() => {
    let pool = data;
    if (mode === 'mistakes') {
      pool = data.filter(q => mistakesVault.includes(q.id));
    } else {
      if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
      if (showImagesOnly) pool = pool.filter(q => q.questionImage || q.answerImage);
    }
    return pool.length;
  }, [data, selectedCategories, showImagesOnly, mode, mistakesVault]);

  useEffect(() => {
    if (questionCount > maxPossible && maxPossible > 0) setQuestionCount(maxPossible);
  }, [maxPossible, questionCount]);

  useEffect(() => {
    let timer: number;
    if (view === 'playing' && mode === 'exam' && timeLeft > 0) {
      timer = window.setInterval(() => setTimeLeft(prev => prev <= 1 ? (handleFinish(), 0) : prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [view, mode, timeLeft]);

  const startQuiz = (selectedMode: 'exam' | 'practice' | 'mistakes') => {
    let pool = data;
    if (selectedMode === 'mistakes') {
      pool = data.filter(q => mistakesVault.includes(q.id));
    } else {
      if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));
      if (showImagesOnly) pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) return;

    const count = selectedMode === 'mistakes' ? pool.length : Math.min(questionCount, pool.length);
    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, count);

    const preparedQuestions = shuffledPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);
        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors])).slice(0, 4);
      }
      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setMode(selectedMode);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60);
    setView('playing');
    setImgError(false);
  };

  const handleFinish = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-white flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-4xl grid lg:grid-cols-5 gap-8 my-8 animate-fade-up">
           <div className="lg:col-span-3 space-y-6">
              <div className="bg-rose-600 rounded-[3rem] p-10 text-white relative overflow-hidden shadow-2xl pulse-red">
                 <div className="relative z-10 space-y-2">
                   <h2 className="text-4xl font-black tracking-tighter uppercase leading-none italic">SURVIVAL<br/><span className="text-rose-200 not-italic">EXAM SYSTEM</span></h2>
                   <p className="text-[10px] font-black text-rose-300 uppercase tracking-[0.4em]">Clinical Engine v.6.0</p>
                 </div>
                 <Activity className="absolute -top-10 -right-10 text-white/10" size={240} />
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-rose-500 bg-rose-50 text-rose-600 ring-8 ring-rose-50 shadow-lg' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Formal Exam</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-rose-500 bg-rose-50 text-rose-600 ring-8 ring-rose-50 shadow-lg' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Clinical Review</span>
                  </button>
              </div>

              <div className={`p-8 rounded-[3rem] border-2 transition-all relative overflow-hidden group ${mistakesVault.length > 0 ? 'bg-slate-900 border-slate-900 shadow-2xl scale-[1.02]' : 'bg-slate-50 border-slate-100 opacity-60'}`}>
                 <div className="flex justify-between items-center relative z-10">
                    <div className="flex items-center gap-5">
                       <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg transition-transform group-hover:rotate-12 ${mistakesVault.length > 0 ? 'bg-rose-600 text-white' : 'bg-slate-200 text-slate-400'}`}>
                          <AlertTriangle size={28} />
                       </div>
                       <div className="text-left">
                          <h4 className={`text-xl font-black uppercase tracking-tight ${mistakesVault.length > 0 ? 'text-white' : 'text-slate-400'}`}>Mistakes Vault</h4>
                          <p className={`text-[10px] font-bold uppercase tracking-widest ${mistakesVault.length > 0 ? 'text-rose-400' : 'text-slate-400'}`}>{mistakesVault.length} Anomaly Records</p>
                       </div>
                    </div>
                    {mistakesVault.length > 0 && (
                       <button onClick={() => startQuiz('mistakes')} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl text-white transition-all backdrop-blur-md">
                          <History size={24} />
                       </button>
                    )}
                 </div>
              </div>
           </div>

           <div className="lg:col-span-2 space-y-6">
              <div className="bg-slate-50 rounded-[3rem] p-10 border border-slate-200 shadow-inner flex flex-col gap-10 sticky top-10">
                 <div className="space-y-6">
                    <div className="flex justify-between items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                       <span>Session Depth</span>
                       <span className="text-rose-600 bg-white px-3 py-1 rounded-full shadow-sm">{questionCount} UNITS</span>
                    </div>
                    <input type="range" min="1" max={maxPossible || 1} value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-rose-600 h-2 bg-white border border-slate-200 rounded-full appearance-none shadow-sm cursor-pointer" />
                 </div>
                 <button onClick={() => startQuiz(mode)} className="w-full py-8 bg-rose-600 text-white rounded-[2.5rem] font-black uppercase text-base tracking-[0.4em] shadow-2xl shadow-rose-200 hover:bg-rose-700 hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-4">
                    <Zap size={24} /> INITIALIZE
                 </button>
              </div>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden select-none lg:flex-row">
      <aside className="hidden lg:flex flex-col w-72 bg-slate-50 border-r border-rose-50 shrink-0 p-6 overflow-y-auto custom-scrollbar">
         <div className="space-y-6">
            <div className="flex items-center justify-between border-b border-slate-200 pb-4">
               <h3 className="font-black text-[10px] uppercase text-slate-400 tracking-[0.2em] flex items-center gap-2"><LayoutGrid size={14} /> Matrix Map</h3>
               <span className="text-[10px] font-black text-rose-600 bg-white border border-slate-200 px-3 py-1 rounded-lg shadow-sm">{questions.length}</span>
            </div>
            <div className="grid grid-cols-4 gap-2">
               {questions.map((_, i) => (
                 <button key={i} onClick={() => { setCurrentQIndex(i); setImgError(false); }} className={`h-12 rounded-xl text-xs font-black transition-all flex items-center justify-center border-2 shadow-sm ${currentQIndex === i ? 'bg-rose-600 border-rose-500 text-white ring-4 ring-rose-100 z-10 scale-110 shadow-lg' : questions[i].userAnswer ? 'bg-slate-200 border-slate-300 text-slate-500 opacity-60' : 'bg-white border-white text-slate-300 hover:border-rose-100 hover:text-rose-600'}`}>{i + 1}</button>
               ))}
            </div>
         </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 relative bg-white">
        <div className="bg-white border-b border-rose-50 px-6 h-16 flex justify-between items-center shrink-0 z-10 shadow-sm">
           <div className="flex items-center gap-4">
              <button onClick={() => setIsMatrixOpen(!isMatrixOpen)} className="lg:hidden p-2 bg-rose-50 text-rose-600 rounded-xl"><LayoutGrid size={20} /></button>
              <div className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase">ITEM {currentQIndex + 1} / {questions.length}</div>
              {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-600 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
           </div>
           <button onClick={() => confirm("Exit Session?") && setView('setup')} className="p-2 bg-slate-50 text-slate-300 rounded-xl hover:text-rose-600 transition-colors"><X size={24} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/10">
           {currentQ && (
           <div className="w-full max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
              <div className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-rose-50 shadow-xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-rose-600 shadow-[0_0_15px_rgba(225,29,72,0.5)]"></div>
                <span className="text-[9px] font-black text-rose-500 uppercase tracking-[0.3em] mb-6 block">{currentQ.data.category}</span>
                <h3 className="text-xl md:text-3xl font-black text-slate-900 leading-snug tracking-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
              </div>

              {currentQ.data.questionImage && !imgError && (
                <div className="w-full bg-white rounded-[3rem] p-4 border border-rose-50 shadow-inner flex justify-center group overflow-hidden bg-slate-50/50">
                   <img 
                    src={cleanImageUrl(currentQ.data.questionImage)} 
                    className="max-h-[35vh] md:max-h-[45vh] object-contain transition-transform duration-700 hover:scale-105 rounded-2xl" 
                    onError={() => setImgError(true)} 
                    alt="Anatomical Illustration" 
                   />
                </div>
              )}

              <div className="grid gap-4">
                 {currentQ.options.map((opt, i) => {
                   const isSelected = currentQ.userAnswer === opt;
                   const isCorrect = opt === currentQ.correctOption;
                   const showFeedback = ((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) || view === 'review';

                   let style = "bg-white border-2 border-slate-100 text-slate-600 shadow-sm";
                   if (isSelected) style = "border-rose-500 bg-rose-50/50 text-slate-900 shadow-md ring-4 ring-rose-100";

                   if (showFeedback) {
                     if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-emerald-50 ring-4 ring-emerald-50";
                     else if (isSelected) style = "border-rose-600 bg-rose-50 text-rose-900 shadow-rose-100 ring-4 ring-rose-100";
                     else style = "opacity-30 grayscale";
                   }
                   return (
                     <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-6 rounded-[2rem] text-left font-bold text-lg transition-all flex items-start gap-6 active:scale-[0.98] ${style}`}>
                       <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs shrink-0 font-black ${isSelected ? 'bg-rose-600 text-white shadow-lg' : 'bg-slate-50 text-slate-400'}`}>{String.fromCharCode(65 + i)}</div>
                       <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                     </button>
                   );
                 })}
              </div>

              {((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) && (
                <div className="bg-white border-2 border-rose-50 p-8 rounded-[3.5rem] space-y-4 animate-fade-up shadow-xl">
                  <div className="flex items-center gap-3 text-rose-600 font-black text-[10px] uppercase tracking-[0.4em] border-b border-rose-50 pb-4">
                    <ShieldCheck size={16} /> Clinical Analysis
                  </div>
                  <p className="text-base text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || 'No further analysis recorded.' }} />
                </div>
              )}
           </div>
           )}
        </div>

        <div className="bg-white border-t border-slate-100 p-6 h-28 flex justify-between items-center gap-6 shrink-0 shadow-lg pb-safe px-8">
           <button onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} disabled={currentQIndex === 0} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronLeft size={32} /></button>
           <button onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} className={`flex-1 h-16 rounded-[1.5rem] font-black uppercase text-xs tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-rose-700 text-white shadow-rose-200' : 'bg-slate-900 text-white shadow-slate-100'}`}>{currentQIndex === questions.length - 1 ? 'TERMINATE SESSION' : 'NEXT ITEM'}</button>
           <button onClick={() => { setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1)); setImgError(false); }} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 active:scale-95 disabled:opacity-20 transition-all shadow-sm"><ChevronRight size={32} /></button>
        </div>
      </div>
    </div>
  );
};

