// وظيفة تنظيف الروابط
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    return url.substring(url.lastIndexOf('http'));
  }
  return url;
};

interface QuestionListProps {
  data: Question[];
  onExport: () => void;
  onImport: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onEdit?: (id: string) => void;
}

const ITEMS_PER_PAGE = 25;

const QuestionList: React.FC<QuestionListProps> = ({ data, onExport, onImport, onEdit }) => {
  const [search, setSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [sortOrder, setSortOrder] = useState<'default' | 'asc' | 'desc'>('default');
  const [isFilterMenuOpen, setIsFilterMenuOpen] = useState(false);
  const [showMistakesOnly, setShowMistakesOnly] = useState(false);

  const mistakesVault = useMemo(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  }, []);

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    let highlightedText = text;
    terms.forEach(term => {
      const regex = new RegExp(`(${term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})(?![^<]*>)`, 'gi');
      highlightedText = highlightedText.replace(regex, '<mark class="bg-rose-100 text-rose-700 rounded-sm px-0.5 font-bold">$1</mark>');
    });
    return highlightedText;
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category || 'General'));
    return ['All', ...Array.from(cats).sort()];
  }, [data]);

  const processedData = useMemo(() => {
    let result = data;
    if (showMistakesOnly) result = result.filter(q => mistakesVault.includes(q.id));
    if (selectedCategory !== 'All') result = result.filter(q => (q.category || 'General') === selectedCategory);
    if (search.trim()) {
      const term = search.toLowerCase();
      result = result.filter(q => q.questionText.toLowerCase().includes(term) || q.answerText.toLowerCase().includes(term));
    }
    if (sortOrder === 'asc') result = [...result].sort((a, b) => a.questionText.localeCompare(b.questionText));
    else if (sortOrder === 'desc') result = [...result].sort((a, b) => b.questionText.localeCompare(a.questionText));
    return result;
  }, [data, selectedCategory, search, sortOrder, showMistakesOnly, mistakesVault]);

  const totalPages = Math.ceil(processedData.length / ITEMS_PER_PAGE);
  const currentData = processedData.slice((currentPage - 1) * ITEMS_PER_PAGE, currentPage * ITEMS_PER_PAGE);

  return (
    <div className="max-w-5xl mx-auto w-full px-4 pb-32">
      <div className="bg-rose-600 rounded-[2.5rem] p-8 md:p-12 mb-8 text-white relative overflow-hidden shadow-2xl mt-6">
        <BookText size={180} className="absolute -right-10 -top-10 opacity-10" />
        <div className="relative z-10 space-y-6">
          <div className="space-y-2">
            <h2 className="text-3xl md:text-5xl font-black tracking-tighter uppercase italic leading-none">Global Atlas<br/><span className="text-white/80 not-italic">Index</span></h2>
            <p className="text-[10px] font-black text-rose-200 uppercase tracking-[0.4em]">Integrated Registry v.6.0</p>
          </div>

          <div className="relative group">
            <input 
              type="text" 
              placeholder="Search anatomy terms..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-14 pr-14 py-5 rounded-2xl bg-white/10 backdrop-blur-md border border-white/20 text-white placeholder:text-rose-200 outline-none focus:bg-white focus:text-slate-900 transition-all text-lg font-bold"
            />
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-rose-200 group-focus-within:text-rose-500 transition-colors" size={24} />
          </div>

          <button 
            onClick={() => setShowMistakesOnly(!showMistakesOnly)}
            className={`flex items-center gap-2 px-4 py-2 rounded-full border transition-all ${showMistakesOnly ? 'bg-white text-rose-600 border-white shadow-lg' : 'bg-black/20 text-rose-200 border-white/10'}`}
          >
            <AlertTriangle size={14} />
            <span className="text-[10px] font-black uppercase">{mistakesVault.length} Anomaly Records</span>
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {currentData.map((q) => (
          <div key={q.id} className="bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:scale-[1.01] transition-all overflow-hidden flex flex-col md:flex-row">
            {q.questionImage && (
              <div className="w-full md:w-56 h-48 md:h-auto bg-slate-50 border-b md:border-b-0 md:border-r border-slate-100 flex items-center justify-center p-4 shrink-0 overflow-hidden">
                 <img src={cleanImageUrl(q.questionImage)} alt="Diagram" className="max-w-full max-h-full object-contain rounded-lg" loading="lazy" />
              </div>
            )}
            <div className="p-8 flex-1">
              <div className="flex items-center justify-between mb-4">
                <span className="text-[9px] font-black uppercase text-rose-600 bg-rose-50 px-3 py-1 rounded-full border border-rose-100">{q.category}</span>
                {mistakesVault.includes(q.id) && <AlertTriangle size={14} className="text-rose-500 animate-pulse" />}
              </div>
              <h3 className="text-xl font-black text-slate-800 leading-tight mb-4" dangerouslySetInnerHTML={{ __html: highlightText(q.questionText, search) }} />
              <div className="relative pl-6 border-l-4 border-rose-100">
                <p className="text-base font-bold text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: highlightText(q.answerText, search) }} />
              </div>
            </div>
          </div>
        ))}
      </div>

      {totalPages > 1 && (
        <div className="flex justify-center items-center gap-3 mt-12 mb-20">
          <button onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1} className="h-14 px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Prev</button>
          <div className="h-14 px-8 rounded-2xl bg-slate-900 text-white flex items-center font-black text-[10px] tracking-widest shadow-xl">{currentPage} / {totalPages}</div>
          <button onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))} disabled={currentPage === totalPages} className="h-14 px-8 rounded-2xl bg-white border border-slate-200 text-slate-400 font-black uppercase text-[10px] disabled:opacity-20 transition-all shadow-md">Next</button>
        </div>
      )}
    </div>
  );
};

