import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import InteractiveAtlas from './components/InteractiveAtlas';
import { AppMode, Question } from './types';

// استيراد كافة الفصول لضمان عدم ضياع الأسئلة
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';

import { Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));
  }, [userVault]);

  // دمج كافة البيانات من كل المصادر ومعالجة التكرار
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    userVault.forEach(q => {
        uniqueQuestions.push(q);
        seenIds.add(q.id);
    });

    const systemSources = [...ch1, ...ch3, ...ch4, ...ch6, ...ch7, ...ch8, ...ch9, ...ch10, ...ch11];
    systemSources.forEach(q => {
        if (!seenIds.has(q.id)) {
            uniqueQuestions.push(q);
            seenIds.add(q.id);
        }
    });
    return uniqueQuestions;
  }, [userVault]);

  const categories = useMemo(() => Array.from(new Set(allQuestions.map(q => q.category))).sort(), [allQuestions]);

  const handleEditRequest = (id: string) => {
    setEditingId(id);
    setCurrentMode(AppMode.BUILDER);
  };

  const handleSaveQuestion = (question: Question) => {
    setUserVault(prev => {
        const existingIndex = prev.findIndex(q => q.id === question.id);
        if (existingIndex >= 0) {
            const newVault = [...prev];
            newVault[existingIndex] = question;
            return newVault;
        } else return [question, ...prev];
    });
    setEditingId(null);
    setCurrentMode(AppMode.LIST);
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col bg-slate-50 font-sans text-slate-900 overflow-hidden fixed inset-0">
      <Header currentMode={currentMode} onModeChange={(m) => { setCurrentMode(m); setEditingId(null); }} />

      <main className="flex-1 relative overflow-hidden flex flex-col w-full max-w-7xl mx-auto">
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full animate-in fade-in duration-500">
            <Flashcards data={allQuestions} onEdit={handleEditRequest} />
          </div>
        )}

        {currentMode === AppMode.ATLAS && (
          <div className="flex-1 h-full animate-in slide-in-from-right duration-500">
            <InteractiveAtlas data={allQuestions} />
          </div>
        )}

        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full animate-in zoom-in-95 duration-500">
            <Quiz data={allQuestions} onEdit={handleEditRequest} />
          </div>
        )}

        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto px-3 py-4 custom-scrollbar">
            <QuestionList 
              data={allQuestions} 
              onExport={() => {}} 
              onImport={() => {}} 
              onEdit={handleEditRequest} 
            />
            <div className="flex justify-center p-12">
               <button onClick={() => confirm("Reset all changes?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors">
                 <Trash2 size={12} className="inline mr-1" /> Factory Reset Vault
               </button>
            </div>
          </div>
        )}

        {currentMode === AppMode.BUILDER && (
          <div className="flex-1 h-full overflow-y-auto custom-scrollbar">
            <QuestionBuilder allQuestions={allQuestions} editingId={editingId} onSave={handleSaveQuestion} onCancel={() => { setEditingId(null); setCurrentMode(AppMode.LIST); }} existingCategories={categories} />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, RotateCw, X, ChevronLeft, ChevronRight, BookOpen, Check, LayoutGrid, Image as ImageIcon } from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) return url.substring(url.lastIndexOf('http'));
  return url;
};

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [shuffledIndices, setShuffledIndices] = useState<number[]>([]);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category))).sort(), [data]);

  const filteredData = useMemo(() => {
    let result = data;
    if (selectedCategories.length > 0) result = result.filter(q => selectedCategories.includes(q.category));
    if (showImagesOnly) result = result.filter(q => q.questionImage || q.answerImage);
    return result;
  }, [data, selectedCategories, showImagesOnly]);

  useEffect(() => {
    setShuffledIndices(Array.from({ length: filteredData.length }, (_, i) => i));
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [filteredData]);

  const currentCard = filteredData[shuffledIndices[currentIndex]];

  return (
    <div className="flex flex-col h-full w-full max-w-2xl mx-auto px-2 pb-safe bg-white overflow-hidden relative">
      {/* Navigation & Filters */}
      <div className="flex justify-between items-center px-2 py-4 shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-rose-50 border border-rose-100 px-4 py-1.5 rounded-full font-black text-[10px] text-rose-500 tracking-widest uppercase">
            UNIT {currentIndex + 1} / {filteredData.length}
          </div>
          <button 
            onClick={() => setIsFilterOpen(true)}
            className={`px-4 py-1.5 rounded-full font-black text-[10px] uppercase tracking-widest transition-all border shadow-sm flex items-center gap-2 ${selectedCategories.length > 0 || showImagesOnly ? 'bg-rose-600 text-white border-rose-600' : 'bg-white text-slate-500'}`}
          >
            <Filter size={12} /> Filter
          </button>
        </div>
        <button onClick={() => setShuffledIndices([...shuffledIndices].sort(() => Math.random() - 0.5))} className="p-2.5 bg-rose-50 border border-rose-100 rounded-xl text-rose-400 hover:text-rose-600 transition-all">
          <Shuffle size={16} />
        </button>
      </div>

      {/* Card Content */}
      <div className="flex-1 relative perspective-1000 my-2 group">
        {currentCard ? (
          <div className={`w-full h-full relative transform-style-3d transition-transform duration-700 ease-out ${isFlipped ? 'rotate-y-180' : ''}`} onClick={() => setIsFlipped(!isFlipped)}>
            {/* Front */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-[3rem] shadow-2xl border border-rose-50 backface-hidden flex flex-col overflow-hidden">
              <div className="flex-1 p-8 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <div className="mb-6 w-full flex justify-center bg-rose-50/30 p-4 rounded-[2.5rem] border border-rose-50 shadow-inner">
                    <img src={cleanImageUrl(currentCard.questionImage)} className="max-h-[30vh] w-auto object-contain rounded-xl mix-blend-multiply" onError={() => setImgError(true)} alt="Anatomy" />
                  </div>
                )}
                <span className="text-[9px] font-black text-rose-500 uppercase tracking-[0.3em] mb-4">{currentCard.category}</span>
                <h2 className="text-xl md:text-2xl font-black text-slate-800 leading-snug" dangerouslySetInnerHTML={{ __html: currentCard.questionText }} />
              </div>
            </div>

            {/* Back */}
            <div className="absolute inset-0 w-full h-full bg-rose-50 rounded-[3rem] shadow-inner backface-hidden rotate-y-180 border border-rose-100 flex flex-col overflow-hidden">
              <div className="flex-1 p-10 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                <span className="text-[9px] font-black text-[#d4af37] uppercase tracking-[0.4em] mb-6">Medical Validation</span>
                <div className="text-2xl md:text-3xl font-black text-slate-900 leading-tight mb-8" dangerouslySetInnerHTML={{ __html: currentCard.answerText }} />
                {currentCard.explanation && (
                  <div className="bg-white p-6 rounded-[2rem] border border-rose-50 text-slate-500 text-xs leading-relaxed max-w-md shadow-sm italic" dangerouslySetInnerHTML={{ __html: currentCard.explanation }} />
                )}
              </div>
            </div>
          </div>
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center text-rose-200 border-4 border-dashed border-rose-50 rounded-[3rem]">
            <p className="font-black uppercase tracking-widest text-xs">Selection Empty</p>
          </div>
        )}
      </div>

      {/* Controller */}
      <div className="flex items-center gap-4 p-4 shrink-0 pb-12">
        <button onClick={() => { setIsFlipped(false); setImgError(false); setCurrentIndex(prev => Math.max(0, prev - 1)); }} disabled={currentIndex === 0} className="h-16 w-16 rounded-3xl bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 disabled:opacity-30 transition-all shadow-sm"><ChevronLeft size={32} /></button>
        <button onClick={() => setIsFlipped(!isFlipped)} className="flex-1 h-16 rounded-3xl bg-rose-600 text-white font-black uppercase text-xs tracking-[0.3em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3">{isFlipped ? <BookOpen size={18} /> : <RotateCw size={18} />} Analyze</button>
        <button onClick={() => { setIsFlipped(false); setImgError(false); setCurrentIndex(prev => Math.min(filteredData.length - 1, prev + 1)); }} disabled={currentIndex === filteredData.length - 1} className="h-16 w-16 rounded-3xl bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 disabled:opacity-30 transition-all shadow-sm"><ChevronRight size={32} /></button>
      </div>

      {/* Filter Modal */}
      {isFilterOpen && (
        <div className="fixed inset-0 z-[150] animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm" onClick={() => setIsFilterOpen(false)}></div>
          <div className="absolute bottom-0 left-0 right-0 bg-white rounded-t-[3rem] p-8 max-h-[80vh] overflow-y-auto custom-scrollbar animate-in slide-in-from-bottom duration-500 shadow-3xl">
             <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
                <h3 className="font-black uppercase text-xs text-slate-800 tracking-widest">Global Atlas Filters</h3>
                <button onClick={() => setIsFilterOpen(false)} className="p-3 bg-rose-50 rounded-2xl text-rose-600"><X size={20} /></button>
             </div>

             <div className="space-y-8">
                <button onClick={() => setShowImagesOnly(!showImagesOnly)} className={`w-full p-5 rounded-[1.5rem] font-black uppercase text-xs tracking-widest flex items-center justify-between transition-all border-2 ${showImagesOnly ? 'bg-rose-600 text-white border-rose-600' : 'bg-slate-50 border-slate-100 text-slate-400'}`}><span>Visual Diagrams Only</span> <ImageIcon size={18} /></button>

                <div className="space-y-4">
                   <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] px-2">Medical Systems</h4>
                   <div className="grid gap-2">
                      {categories.map(cat => (
                        <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`w-full text-left p-4 rounded-xl text-[11px] font-bold uppercase transition-all flex items-center justify-between border-2 ${selectedCategories.includes(cat) ? 'bg-rose-50 border-rose-500 text-rose-700' : 'bg-white border-slate-50 text-slate-400 hover:border-slate-200'}`}><span>{cat}</span> {selectedCategories.includes(cat) && <Check size={14} strokeWidth={4} />}</button>
                      ))}
                   </div>
                </div>

                <button onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setIsFilterOpen(false); }} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest mt-4">Reset All Records</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

