import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import QuestionBuilder from './components/QuestionBuilder';
import InteractiveAtlas from './components/InteractiveAtlas';
import { AppMode, Question } from './types';

// استيراد كافة الفصول المتاحة
import { questions as ch1 } from './hooks/data_ch1';
import { questions as ch2 } from './hooks/data_ch2';
import { questions as ch3 } from './hooks/data_ch3';
import { questions as ch4 } from './hooks/data_ch4';
import { questions as ch5 } from './hooks/data_ch5';
import { questions as ch6 } from './hooks/data_ch6';
import { questions as ch7 } from './hooks/data_ch7';
import { questions as ch8 } from './hooks/data_ch8';
import { questions as ch9 } from './hooks/data_ch9';
import { questions as ch10 } from './hooks/data_ch10';
import { questions as ch11 } from './hooks/data_ch11';
import { questions as rawData } from './hooks/data';

import { Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [editingId, setEditingId] = useState<string | null>(null);

  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v5', JSON.stringify(userVault));
  }, [userVault]);

  // محرك الدمج النهائي - يضمن الوصول إلى 1100+ سؤال
  const allQuestions = useMemo(() => {
    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    // 1. الأولوية لتعديلات المستخدم
    userVault.forEach(q => {
        uniqueQuestions.push(q);
        seenIds.add(q.id);
    });

    // 2. دمج كافة الفصول الرسمية
    const sources = [
        ...ch1, ...ch2, ...ch3, ...ch4, ...ch5, ...ch6, 
        ...ch7, ...ch8, ...ch9, ...ch10, ...ch11, ...rawData
    ];

    sources.forEach(q => {
        if (!seenIds.has(q.id)) {
            // معالجة الخيارات المفقودة لضمان جاهزية الاختبار
            const finalQ = {
              ...q,
              options: (q.options && q.options.length >= 4) 
                ? q.options 
                : Array.from(new Set([q.answerText, 'Option A', 'Option B', 'Option C', 'Option D'])).slice(0, 4)
            };
            uniqueQuestions.push(finalQ);
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  const handleEditRequest = (id: string) => {
    setEditingId(id);
    setCurrentMode(AppMode.BUILDER);
  };

  const handleSaveQuestion = (question: Question) => {
    setUserVault(prev => {
        const existingIndex = prev.findIndex(q => q.id === question.id);
        if (existingIndex >= 0) {
            const newVault = [...prev];
            newVault[existingIndex] = question;
            return newVault;
        } else return [question, ...prev];
    });
    setEditingId(null);
    setCurrentMode(AppMode.LIST);
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col bg-slate-50 font-sans text-slate-900 overflow-hidden fixed inset-0">
      <Header currentMode={currentMode} onModeChange={(m) => { setCurrentMode(m); setEditingId(null); }} />

      <main className="flex-1 relative overflow-hidden flex flex-col w-full max-w-7xl mx-auto">
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full animate-in fade-in duration-500">
            <Flashcards data={allQuestions} onEdit={handleEditRequest} />
          </div>
        )}

        {currentMode === AppMode.ATLAS && (
          <div className="flex-1 h-full animate-in slide-in-from-right duration-500">
            <InteractiveAtlas data={allQuestions} />
          </div>
        )}

        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full animate-in zoom-in-95 duration-500">
            <Quiz data={allQuestions} onEdit={handleEditRequest} />
          </div>
        )}

        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto px-3 py-4 custom-scrollbar">
            <QuestionList 
              data={allQuestions} 
              onExport={() => {}} 
              onImport={() => {}} 
              onEdit={handleEditRequest} 
            />
            <div className="flex justify-center p-12">
               <button onClick={() => confirm("Reset all records?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors">
                 <Trash2 size={12} className="inline mr-1" /> Factory Reset Anatomy Vault
               </button>
            </div>
          </div>
        )}

        {currentMode === AppMode.BUILDER && (
          <div className="flex-1 h-full overflow-y-auto custom-scrollbar">
            <QuestionBuilder allQuestions={allQuestions} editingId={editingId} onSave={handleSaveQuestion} onCancel={() => { setEditingId(null); setCurrentMode(AppMode.LIST); }} existingCategories={[]} />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  RotateCw, AlertTriangle, 
  Eye, Timer, Activity, ShieldCheck, LayoutGrid, Zap, Image as ImageIcon, History
} from 'lucide-react';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) return url.substring(url.lastIndexOf('http'));
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category))).sort(), [data]);

  const startQuiz = (selectedMode: 'exam' | 'practice' | 'mistakes') => {
    let pool = data;
    if (selectedMode === 'mistakes') pool = data.filter(q => mistakesVault.includes(q.id));
    else if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));

    if (pool.length === 0) return;

    const count = selectedMode === 'mistakes' ? pool.length : Math.min(questionCount, pool.length);
    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, count);

    const preparedQuestions = shuffledPool.map(q => {
      // منطق استرجاع الخيارات المفقودة
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);
        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors])).slice(0, 4);
        // تأكيد وجود 4 خيارات
        while(finalOptions.length < 4) finalOptions.push(`Option ${finalOptions.length + 1}`);
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setMode(selectedMode);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60);
    setView('playing');
    setImgError(false);
  };

  const handleFinish = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-white flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-4xl grid lg:grid-cols-5 gap-8 my-8 animate-fade-up">
           <div className="lg:col-span-3 space-y-6">
              <div className="bg-rose-600 rounded-[3rem] p-10 text-white relative overflow-hidden shadow-2xl pulse-red">
                 <div className="relative z-10 space-y-2">
                   <h2 className="text-4xl font-black tracking-tighter uppercase leading-none italic">GRAND<br/><span className="text-rose-200 not-italic">ATLAS EXAM</span></h2>
                   <p className="text-[10px] font-black text-rose-300 uppercase tracking-[0.4em]">Integrated Registry v.11.0 • 1100+ Units</p>
                 </div>
                 <Activity className="absolute -top-10 -right-10 text-white/10" size={240} />
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'exam' ? 'border-rose-500 bg-rose-50 text-rose-600 ring-8 ring-rose-50' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Timer size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Formal Exam</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 ${mode === 'practice' ? 'border-rose-500 bg-rose-50 text-rose-600 ring-8 ring-rose-50' : 'border-slate-100 text-slate-400 bg-slate-50'}`}>
                    <Eye size={24} /> 
                    <span className="font-black text-xs uppercase tracking-widest">Clinical Review</span>
                  </button>
              </div>

              <div className={`p-8 rounded-[3rem] border-2 transition-all relative overflow-hidden group ${mistakesVault.length > 0 ? 'bg-slate-900 border-slate-900 shadow-2xl scale-[1.02]' : 'bg-slate-50 border-slate-100 opacity-60'}`}>
                 <div className="flex justify-between items-center relative z-10">
                    <div className="flex items-center gap-5">
                       <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg ${mistakesVault.length > 0 ? 'bg-rose-600 text-white' : 'bg-slate-200 text-slate-400'}`}>
                          <AlertTriangle size={28} />
                       </div>
                       <div className="text-left">
                          <h4 className={`text-xl font-black uppercase tracking-tight ${mistakesVault.length > 0 ? 'text-white' : 'text-slate-400'}`}>Anomaly Vault</h4>
                          <p className={`text-[10px] font-bold uppercase tracking-widest ${mistakesVault.length > 0 ? 'text-rose-400' : 'text-slate-400'}`}>{mistakesVault.length} Registered Errors</p>
                       </div>
                    </div>
                    {mistakesVault.length > 0 && (
                       <button onClick={() => startQuiz('mistakes')} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl text-white transition-all backdrop-blur-md">
                          <History size={24} />
                       </button>
                    )}
                 </div>
              </div>
           </div>

           <div className="lg:col-span-2 space-y-6">
              <div className="bg-slate-50 rounded-[3rem] p-10 border border-slate-200 shadow-inner flex flex-col gap-10 sticky top-10">
                 <div className="space-y-6">
                    <div className="flex justify-between items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                       <span>Batch Size</span>
                       <span className="text-rose-600 bg-white px-3 py-1 rounded-full shadow-sm">{questionCount}</span>
                    </div>
                    <input type="range" min="5" max="100" step="5" value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-rose-600 h-2 bg-white border border-slate-200 rounded-full appearance-none cursor-pointer" />
                 </div>

                 <div className="space-y-4">
                    <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Target Systems</h4>
                    <div className="max-h-48 overflow-y-auto custom-scrollbar space-y-1">
                       {categories.map(cat => (
                         <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`w-full text-left p-3 rounded-xl text-[10px] font-bold uppercase transition-all ${selectedCategories.includes(cat) ? 'bg-rose-600 text-white shadow-md' : 'bg-white border border-slate-100 text-slate-400'}`}>{cat}</button>
                       ))}
                    </div>
                 </div>

                 <button onClick={() => startQuiz(mode)} className="w-full py-6 bg-rose-600 text-white rounded-[2rem] font-black uppercase text-sm tracking-[0.4em] shadow-xl hover:bg-rose-700 transition-all flex items-center justify-center gap-4">
                    <Zap size={20} /> LAUNCH
                 </button>
              </div>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden select-none lg:flex-row">
      <aside className="hidden lg:flex flex-col w-72 bg-slate-50 border-r border-rose-50 shrink-0 p-6 overflow-y-auto custom-scrollbar">
         <div className="space-y-6">
            <div className="flex items-center justify-between border-b border-slate-200 pb-4">
               <h3 className="font-black text-[10px] uppercase text-slate-400 tracking-[0.2em] flex items-center gap-2"><LayoutGrid size={14} /> Matrix Map</h3>
               <span className="text-[10px] font-black text-rose-600 bg-white border border-slate-200 px-3 py-1 rounded-lg">{questions.length}</span>
            </div>
            <div className="grid grid-cols-4 gap-2">
               {questions.map((_, i) => (
                 <button key={i} onClick={() => { setCurrentQIndex(i); setImgError(false); }} className={`h-10 rounded-xl text-[10px] font-black transition-all flex items-center justify-center border-2 ${currentQIndex === i ? 'bg-rose-600 border-rose-500 text-white shadow-lg' : questions[i].userAnswer ? 'bg-slate-200 border-slate-300 text-slate-500' : 'bg-white border-white text-slate-300 hover:text-rose-600'}`}>{i + 1}</button>
               ))}
            </div>
         </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 relative bg-white">
        <div className="bg-white border-b border-rose-50 px-6 h-16 flex justify-between items-center shrink-0 z-10">
           <div className="flex items-center gap-4">
              <div className="bg-slate-900 text-white text-[10px] px-4 py-1.5 rounded-full font-black tracking-widest uppercase">NODE {currentQIndex + 1} / {questions.length}</div>
              {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-600 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
           </div>
           <button onClick={() => confirm("Abort Session?") && setView('setup')} className="p-2 text-slate-300 hover:text-rose-600 transition-colors"><X size={24} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar bg-slate-50/10">
           {currentQ && (
           <div className="w-full max-w-2xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
              <div className="bg-white p-8 md:p-12 rounded-[3rem] border border-rose-50 shadow-xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-1.5 h-full bg-rose-600"></div>
                <span className="text-[9px] font-black text-rose-500 uppercase tracking-[0.3em] mb-6 block">{currentQ.data.category}</span>
                <h3 className="text-xl md:text-2xl font-black text-slate-900 leading-snug tracking-tight" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
              </div>

              {currentQ.data.questionImage && !imgError && (
                <div className="w-full bg-white rounded-[2.5rem] p-4 border border-rose-50 shadow-inner flex justify-center group overflow-hidden">
                   <img src={cleanImageUrl(currentQ.data.questionImage)} className="max-h-[35vh] md:max-h-[45vh] object-contain transition-transform duration-700 hover:scale-105 rounded-xl" onError={() => setImgError(true)} alt="Clinical Visualization" />
                </div>
              )}

              <div className="grid gap-4">
                 {currentQ.options.map((opt, i) => {
                   const isSelected = currentQ.userAnswer === opt;
                   const isCorrect = opt === currentQ.correctOption;
                   const showFeedback = ((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) || view === 'review';

                   let style = "bg-white border-2 border-slate-100 text-slate-600";
                   if (isSelected) style = "border-rose-500 bg-rose-50/50 text-slate-900 shadow-md ring-4 ring-rose-100";

                   if (showFeedback) {
                     if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-emerald-50";
                     else if (isSelected) style = "border-rose-600 bg-rose-50 text-rose-900";
                     else style = "opacity-30 grayscale";
                   }
                   return (
                     <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-6 rounded-[2rem] text-left font-bold text-lg transition-all flex items-start gap-6 active:scale-[0.98] ${style}`}>
                       <div className={`w-8 h-8 rounded-xl flex items-center justify-center text-xs shrink-0 font-black ${isSelected ? 'bg-rose-600 text-white' : 'bg-slate-50 text-slate-400'}`}>{String.fromCharCode(65 + i)}</div>
                       <span className="mt-0.5 leading-snug" dangerouslySetInnerHTML={{ __html: opt }} />
                     </button>
                   );
                 })}
              </div>

              {((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) && (
                <div className="bg-white border-2 border-rose-50 p-8 rounded-[3rem] space-y-4 animate-fade-up shadow-xl">
                  <div className="flex items-center gap-3 text-rose-600 font-black text-[10px] uppercase tracking-[0.4em] border-b border-rose-50 pb-4">
                    <ShieldCheck size={16} /> Clinical Validation
                  </div>
                  <p className="text-base text-slate-500 leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || 'No further analysis available.' }} />
                </div>
              )}
           </div>
           )}
        </div>

        <div className="bg-white border-t border-slate-100 p-6 h-28 flex justify-between items-center gap-6 shrink-0 shadow-lg px-8">
           <button onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} disabled={currentQIndex === 0} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 disabled:opacity-20 transition-all"><ChevronLeft size={32} /></button>
           <button onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} className={`flex-1 h-16 rounded-[1.5rem] font-black uppercase text-xs tracking-[0.3em] shadow-xl transition-all ${currentQIndex === questions.length - 1 ? 'bg-rose-700 text-white' : 'bg-slate-900 text-white'}`}>{currentQIndex === questions.length - 1 ? 'FINISH SESSION' : 'NEXT NODE'}</button>
           <button onClick={() => { setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1)); setImgError(false); }} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-300 hover:text-rose-600 disabled:opacity-20 transition-all"><ChevronRight size={32} /></button>
        </div>
      </div>
    </div>
  );
};

