import React, { useState, useEffect, useMemo } from 'react';
import { Question } from '../types';
import { Shuffle, Filter, RotateCw, X, ChevronLeft, ChevronRight, BookOpen, Check, Image as ImageIcon } from 'lucide-react';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) return url.substring(url.lastIndexOf('http'));
  return url;
};

interface FlashcardsProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Flashcards: React.FC<FlashcardsProps> = ({ data, onEdit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [imgError, setImgError] = useState(false);
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [shuffledIndices, setShuffledIndices] = useState<number[]>([]);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category))).sort(), [data]);

  const filteredData = useMemo(() => {
    let result = data;
    if (selectedCategories.length > 0) result = result.filter(q => selectedCategories.includes(q.category));
    if (showImagesOnly) result = result.filter(q => q.questionImage || q.answerImage);
    return result;
  }, [data, selectedCategories, showImagesOnly]);

  useEffect(() => {
    setShuffledIndices(Array.from({ length: filteredData.length }, (_, i) => i));
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [filteredData]);

  const currentCard = filteredData[shuffledIndices[currentIndex]];

  return (
    <div className="flex flex-col h-full w-full max-w-2xl mx-auto px-4 pb-safe bg-slate-50/50 overflow-hidden relative">
      {/* Dynamic Navigation */}
      <div className="flex justify-between items-center py-6 shrink-0">
        <div className="flex items-center gap-3">
          <div className="bg-white border border-slate-200 shadow-sm px-4 py-2 rounded-2xl font-black text-[10px] text-slate-500 tracking-widest uppercase flex items-center gap-2">
            <span className="w-1.5 h-1.5 bg-rose-600 rounded-full animate-pulse"></span>
            UNIT {currentIndex + 1} / {filteredData.length}
          </div>
          <button 
            onClick={() => setIsFilterOpen(true)}
            className={`px-4 py-2 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all border shadow-sm flex items-center gap-2 ${selectedCategories.length > 0 || showImagesOnly ? 'bg-rose-600 text-white border-rose-600' : 'bg-white text-slate-500 border-slate-200'}`}
          >
            <Filter size={12} /> Filter
          </button>
        </div>
        <button onClick={() => setShuffledIndices([...shuffledIndices].sort(() => Math.random() - 0.5))} className="p-3 bg-white border border-slate-200 rounded-2xl text-slate-400 hover:text-rose-600 hover:border-rose-200 transition-all shadow-sm">
          <Shuffle size={16} />
        </button>
      </div>

      {/* Card Content */}
      <div className="flex-1 relative perspective-1000 my-2">
        {currentCard ? (
          <div className={`w-full h-full relative transform-style-3d transition-transform duration-700 ease-[cubic-bezier(0.4,0,0.2,1)] ${isFlipped ? 'rotate-y-180' : ''}`} onClick={() => setIsFlipped(!isFlipped)}>
            {/* Front */}
            <div className="absolute inset-0 w-full h-full bg-white rounded-[3rem] shadow-2xl border border-slate-100 backface-hidden flex flex-col overflow-hidden">
              <div className="flex-1 p-8 md:p-12 flex flex-col items-center justify-center text-center overflow-y-auto custom-scrollbar">
                {currentCard.questionImage && !imgError && (
                  <div className="mb-8 w-full flex justify-center bg-slate-50 p-6 rounded-[2.5rem] border border-slate-100 shadow-inner">
                    <img src={cleanImageUrl(currentCard.questionImage)} className="max-h-[30vh] w-auto object-contain rounded-xl" onError={() => setImgError(true)} alt="Study Image" />
                  </div>
                )}
