            <p className="font-black uppercase tracking-widest text-xs">Registry Empty</p>
          </div>
        )}
      </div>

      {/* Modern Controller */}
      <div className="flex items-center gap-4 p-6 shrink-0 pb-12">
        <button onClick={() => { setIsFlipped(false); setImgError(false); setCurrentIndex(prev => Math.max(0, prev - 1)); }} disabled={currentIndex === 0} className="h-16 w-16 rounded-3xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-rose-600 disabled:opacity-30 transition-all shadow-md active:scale-95"><ChevronLeft size={32} /></button>
        <button onClick={() => setIsFlipped(!isFlipped)} className="flex-1 h-16 rounded-3xl bg-rose-600 text-white font-black uppercase text-xs tracking-[0.3em] shadow-xl hover:bg-rose-700 active:scale-95 transition-all flex items-center justify-center gap-3">
          {isFlipped ? <BookOpen size={20} /> : <RotateCw size={20} />} 
          {isFlipped ? 'CONTINUE' : 'ANALYZE'}
        </button>
        <button onClick={() => { setIsFlipped(false); setImgError(false); setCurrentIndex(prev => Math.min(filteredData.length - 1, prev + 1)); }} disabled={currentIndex === filteredData.length - 1} className="h-16 w-16 rounded-3xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-rose-600 disabled:opacity-30 transition-all shadow-md active:scale-95"><ChevronRight size={32} /></button>
      </div>

      {/* Filter Modal */}
      {isFilterOpen && (
        <div className="fixed inset-0 z-[150] animate-in fade-in duration-300">
          <div className="absolute inset-0 bg-slate-950/80 backdrop-blur-md" onClick={() => setIsFilterOpen(false)}></div>
          <div className="absolute bottom-0 left-0 right-0 bg-white rounded-t-[3rem] p-10 max-h-[85vh] overflow-y-auto custom-scrollbar animate-in slide-in-from-bottom duration-500 shadow-3xl border-t border-rose-100">
             <div className="flex justify-between items-center mb-10 pb-6 border-b border-slate-100">
                <h3 className="font-black uppercase text-sm text-slate-800 tracking-widest flex items-center gap-2">
                  <div className="w-1.5 h-6 bg-rose-600 rounded-full"></div> System Filters
                </h3>
                <button onClick={() => setIsFilterOpen(false)} className="p-4 bg-rose-50 rounded-2xl text-rose-600 transition-colors hover:bg-rose-100"><X size={24} /></button>
             </div>

             <div className="space-y-10">
                <button onClick={() => setShowImagesOnly(!showImagesOnly)} className={`w-full p-6 rounded-[2rem] font-black uppercase text-xs tracking-widest flex items-center justify-between transition-all border-2 ${showImagesOnly ? 'bg-rose-600 text-white border-rose-600 shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-400'}`}>
                  <span>Clinical Visuals Only</span> <ImageIcon size={20} />
                </button>

                <div className="space-y-4">
                   <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] px-2 flex items-center gap-2">Anatomical Subsets <div className="h-px flex-1 bg-slate-100"></div></h4>
                   <div className="grid gap-3">
                      {categories.map(cat => (
                        <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`w-full text-left p-5 rounded-2xl text-[11px] font-bold uppercase transition-all flex items-center justify-between border-2 ${selectedCategories.includes(cat) ? 'bg-rose-50 border-rose-500 text-rose-700 shadow-sm' : 'bg-white border-slate-100 text-slate-400 hover:border-slate-200'}`}>
                          <span className="truncate pr-4">{cat}</span> 
                          {selectedCategories.includes(cat) && <Check size={16} strokeWidth={4} />}
                        </button>
                      ))}
                   </div>
                </div>

                <button onClick={() => { setSelectedCategories([]); setShowImagesOnly(false); setIsFilterOpen(false); }} className="w-full py-6 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest mt-6 shadow-xl hover:bg-rose-600 transition-colors">Clear All Filters</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

