import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  AlertTriangle, Eye, Timer, Activity, 
  ShieldCheck, LayoutGrid, Zap, History
} from 'lucide-react';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) return url.substring(url.lastIndexOf('http'));
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category))).sort(), [data]);

  const startQuiz = (selectedMode: 'exam' | 'practice' | 'mistakes') => {
    let pool = data;
    if (selectedMode === 'mistakes') pool = data.filter(q => mistakesVault.includes(q.id));
    else if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));

    if (pool.length === 0) {
      alert("OT Warning: No questions found for this selection!");
      return;
    }

    const count = selectedMode === 'mistakes' ? pool.length : Math.min(questionCount, pool.length);
    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, count);

    const preparedQuestions = shuffledPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);
        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors])).slice(0, 4);
        while(finalOptions.length < 4) finalOptions.push(`OT Distractor ${finalOptions.length + 1}`);
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setMode(selectedMode);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60);
    setView('playing');
    setImgError(false);
  };

  const handleFinish = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-50 flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-4xl grid lg:grid-cols-5 gap-8 my-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
           <div className="lg:col-span-3 space-y-6">
              <div className="bg-rose-600 rounded-[3rem] p-10 text-white relative overflow-hidden shadow-2xl">
                 <div className="relative z-10 space-y-4">
                   <div className="flex items-center gap-3">
                     <span className="px-3 py-1 bg-white/20 rounded-full text-[10px] font-black uppercase tracking-widest border border-white/30">Registry Active</span>
                     <span className="text-[#d4af37] font-black italic">OT EDITION</span>
                   </div>
                   <h2 className="text-4xl md:text-5xl font-black tracking-tighter uppercase leading-none italic">GRAND<br/><span className="text-rose-200 not-italic">MEDICAL EVAL</span></h2>
                   <p className="text-[10px] font-bold text-rose-300 uppercase tracking-[0.4em]">{data.length}+ CLINICAL UNITS SYNCED</p>
                 </div>
                 <span className="absolute -bottom-10 -right-10 text-white/5 font-black text-[200px] leading-none italic select-none">OT</span>
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => setMode('exam')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 shadow-sm ${mode === 'exam' ? 'border-rose-500 bg-white text-rose-600 ring-4 ring-rose-100' : 'border-slate-200 text-slate-400 bg-white hover:border-rose-200'}`}>
                    <Timer size={24} /> 
                    <span className="font-black text-[10px] uppercase tracking-widest">OT Exam Mode</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 shadow-sm ${mode === 'practice' ? 'border-[#d4af37] bg-white text-[#d4af37] ring-4 ring-amber-50' : 'border-slate-200 text-slate-400 bg-white hover:border-amber-200'}`}>
                    <Eye size={24} /> 
                    <span className="font-black text-[10px] uppercase tracking-widest">Study Review</span>
                  </button>
              </div>

              <div className={`p-8 rounded-[2.5rem] border-2 transition-all relative overflow-hidden group shadow-lg ${mistakesVault.length > 0 ? 'bg-slate-900 border-slate-900 scale-[1.01]' : 'bg-white border-slate-100 opacity-60'}`}>
                 <div className="flex justify-between items-center relative z-10">
                    <div className="flex items-center gap-5">
                       <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-lg ${mistakesVault.length > 0 ? 'bg-rose-600 text-white' : 'bg-slate-100 text-slate-300'}`}>
                          <AlertTriangle size={28} />
                       </div>
                       <div className="text-left">
                          <h4 className={`text-xl font-black uppercase tracking-tight ${mistakesVault.length > 0 ? 'text-white' : 'text-slate-400'}`}>Anomaly Vault</h4>
                          <p className={`text-[9px] font-bold uppercase tracking-widest ${mistakesVault.length > 0 ? 'text-rose-400' : 'text-slate-400'}`}>{mistakesVault.length} Registered Errors</p>
                       </div>
                    </div>
                    {mistakesVault.length > 0 && (
                       <button onClick={() => startQuiz('mistakes')} className="p-4 bg-white/10 hover:bg-white/20 rounded-2xl text-white transition-all backdrop-blur-md">
                          <History size={24} />
                       </button>
                    )}
                 </div>
              </div>
           </div>

           <div className="lg:col-span-2 space-y-6">
              <div className="bg-white rounded-[3rem] p-10 border border-slate-200 shadow-xl flex flex-col gap-10 sticky top-10">
                 <div className="space-y-6">
                    <div className="flex justify-between items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                       <span>Simulation Size</span>
                       <span className="text-rose-600 bg-rose-50 px-3 py-1 rounded-full font-black">{questionCount} Qs</span>
                    </div>
                    <input type="range" min="5" max="200" step="5" value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-rose-600 h-1.5 bg-slate-100 rounded-full appearance-none cursor-pointer" />
                 </div>

                 <div className="space-y-4">
                    <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-widest px-1">Target OT Systems</h4>
                    <div className="max-h-48 overflow-y-auto custom-scrollbar space-y-1 bg-slate-50 p-2 rounded-2xl border border-slate-100">
                       {categories.map(cat => (
                         <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`w-full text-left p-3 rounded-xl text-[10px] font-bold transition-all ${selectedCategories.includes(cat) ? 'bg-rose-600 text-white shadow-md' : 'bg-white border border-slate-200 text-slate-500 hover:border-rose-300'}`}>{cat}</button>
                       ))}
                    </div>
                 </div>

                 <button onClick={() => startQuiz(mode)} className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-xs tracking-[0.4em] shadow-xl hover:bg-rose-600 transition-all flex items-center justify-center gap-4 active:scale-95 group">
                    <Zap size={18} className="group-hover:animate-bounce text-[#d4af37]" /> INITIALIZE OT SESSION
                 </button>
              </div>
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-slate-50 overflow-hidden select-none lg:flex-row">
      <aside className="hidden lg:flex flex-col w-72 bg-white border-r-2 border-rose-50 shrink-0 p-6 overflow-y-auto custom-scrollbar shadow-inner">
         <div className="space-y-6">
            <div className="flex items-center justify-between border-b border-slate-100 pb-4">
               <h3 className="font-black text-[10px] uppercase text-slate-400 tracking-[0.2em] flex items-center gap-2"><LayoutGrid size={14} /> OT Matrix</h3>
               <span className="text-[10px] font-black text-[#d4af37] bg-slate-50 border border-slate-100 px-3 py-1 rounded-lg">{questions.length} Units</span>
            </div>
            <div className="grid grid-cols-4 gap-2">
               {questions.map((_, i) => (
                 <button key={i} onClick={() => { setCurrentQIndex(i); setImgError(false); }} className={`h-10 rounded-xl text-[10px] font-black transition-all flex items-center justify-center border-2 ${currentQIndex === i ? 'bg-rose-600 border-rose-500 text-white shadow-md' : questions[i].userAnswer ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : 'bg-white border-slate-100 text-slate-300 hover:border-rose-200 hover:text-rose-500'}`}>{i + 1}</button>
               ))}
            </div>
         </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 relative">
        <div className="bg-white border-b border-slate-200 px-6 h-16 flex justify-between items-center shrink-0 z-10 shadow-sm">
           <div className="flex items-center gap-4">
              <div className="bg-slate-900 text-white text-[10px] px-4 py-2 rounded-xl font-black tracking-widest uppercase flex items-center gap-2">
                <span className="text-[#d4af37]">OT NODE</span> {currentQIndex + 1} / {questions.length}
              </div>
              {mode === 'exam' && <div className={`flex items-center gap-2 font-mono font-black text-sm ${timeLeft < 60 ? 'text-rose-600 animate-pulse' : 'text-slate-400'}`}><Clock size={16} /> {formatTime(timeLeft)}</div>}
           </div>
           <button onClick={() => confirm("OT Security: End current simulation?") && setView('setup')} className="p-2 text-slate-300 hover:text-rose-600 transition-colors bg-slate-50 rounded-xl"><X size={24} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-12 custom-scrollbar bg-[#f1f5f9]/30">
           {currentQ && (
           <div className="w-full max-w-2xl mx-auto space-y-8 pb-24">
              <div className="bg-white p-10 md:p-14 rounded-[3rem] border border-slate-200 shadow-xl relative overflow-hidden">
                <div className="absolute top-0 left-0 w-2 h-full bg-[#d4af37]"></div>
                <div className="flex justify-between items-center mb-8">
                  <span className="text-[9px] font-black text-rose-500 uppercase tracking-[0.4em]">{currentQ.data.category}</span>
                  <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest">OT-ID: {currentQ.id}</span>
                </div>
                <h3 className="text-xl md:text-3xl font-black text-slate-900 leading-snug tracking-tighter italic" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
              </div>

              {currentQ.data.questionImage && !imgError && (
                <div className="w-full bg-white rounded-[2.5rem] p-6 border-2 border-slate-100 shadow-inner flex justify-center group overflow-hidden relative">
                   <div className="absolute top-4 right-4 text-[8px] font-black text-slate-300 uppercase tracking-widest bg-slate-50 px-2 py-1 rounded">OT VISUAL REFERENCE</div>
                   <img src={cleanImageUrl(currentQ.data.questionImage)} className="max-h-[40vh] md:max-h-[50vh] object-contain transition-transform duration-1000 hover:scale-[1.05] rounded-lg" onError={() => setImgError(true)} alt="Clinical Image" />
                </div>
              )}

              <div className="grid gap-4">
                 {currentQ.options.map((opt, i) => {
                   const isSelected = currentQ.userAnswer === opt;
                   const isCorrect = opt === currentQ.correctOption;
                   const showFeedback = ((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) || view === 'review';

                   let style = "bg-white border-2 border-slate-200 text-slate-600 hover:border-rose-400";
                   if (isSelected) style = "border-rose-500 bg-rose-50 text-slate-900 shadow-md ring-4 ring-rose-100";

                   if (showFeedback) {
                     if (isCorrect) style = "border-emerald-500 bg-emerald-50 text-emerald-900 shadow-emerald-50";
                     else if (isSelected) style = "border-rose-600 bg-rose-50 text-rose-900";
                     else style = "opacity-30 grayscale border-slate-100";
                   }
                   return (
                     <button key={i} onClick={() => !showFeedback && setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} className={`w-full p-8 rounded-[2rem] text-left font-bold text-lg transition-all flex items-start gap-8 active:scale-[0.98] ${style}`}>
                       <div className={`w-10 h-10 rounded-2xl flex items-center justify-center text-sm shrink-0 font-black ${isSelected ? 'bg-rose-600 text-white' : 'bg-slate-100 text-slate-400'}`}>{String.fromCharCode(65 + i)}</div>
                       <span className="mt-1.5 leading-snug tracking-tight" dangerouslySetInnerHTML={{ __html: opt }} />
                     </button>
                   );
                 })}
              </div>

              {((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) && (
                <div className="bg-white border border-[#d4af37]/30 p-10 rounded-[3rem] space-y-6 animate-in slide-in-from-top-4 duration-500 shadow-2xl border-t-8 border-t-[#d4af37]">
                  <div className="flex items-center justify-between border-b border-slate-100 pb-4">
                    <div className="flex items-center gap-3 text-[#d4af37] font-black text-[11px] uppercase tracking-[0.4em]">
                      <ShieldCheck size={18} /> OT Medical Validation
                    </div>
                    {currentQ.userAnswer === currentQ.correctOption ? 
                      <span className="text-[10px] font-black text-emerald-500 uppercase bg-emerald-50 px-3 py-1 rounded-full">Correct Match</span> :
                      <span className="text-[10px] font-black text-rose-500 uppercase bg-rose-50 px-3 py-1 rounded-full">Discrepancy Detected</span>
                    }
                  </div>
                  <p className="text-lg text-slate-600 font-medium leading-relaxed italic" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || 'Anatomical records confirm this finding. Review the structural components for deeper integration.' }} />
                </div>
              )}
           </div>
           )}
        </div>

        <div className="bg-white border-t-2 border-slate-100 p-6 h-28 flex justify-between items-center gap-6 shrink-0 shadow-[0_-10px_30px_rgba(0,0,0,0.03)] px-8 z-[20]">
           <button onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} disabled={currentQIndex === 0} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-400 hover:text-rose-600 disabled:opacity-20 transition-all shadow-sm"><ChevronLeft size={32} /></button>
           <button onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} className={`flex-1 h-16 rounded-[1.5rem] font-black uppercase text-xs tracking-[0.4em] shadow-xl transition-all active:scale-95 ${currentQIndex === questions.length - 1 ? 'bg-rose-700 text-white' : 'bg-slate-900 text-white hover:bg-rose-600'}`}>{currentQIndex === questions.length - 1 ? 'COMMIT SEQUENCE' : 'ADVANCE OT NODE'}</button>
           <button onClick={() => { setCurrentQIndex(prev => Math.min(questions.length - 1, prev + 1)); setImgError(false); }} disabled={currentQIndex === questions.length - 1} className="h-16 w-16 rounded-[1.5rem] bg-slate-50 border border-slate-200 flex items-center justify-center text-slate-400 hover:text-rose-600 disabled:opacity-20 transition-all shadow-sm"><ChevronRight size={32} /></button>
        </div>
      </div>
    </div>
  );
};

export default Quiz;

