import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  AlertTriangle, Eye, Timer, Activity, 
  ShieldCheck, LayoutGrid, Zap, History, Star
} from 'lucide-react';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) return url.substring(url.lastIndexOf('http'));
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  const categories = useMemo(() => Array.from(new Set(data.map(q => q.category))).sort(), [data]);

  const startQuiz = (selectedMode: 'exam' | 'practice' | 'mistakes') => {
    let pool = data;
    if (selectedMode === 'mistakes') pool = data.filter(q => mistakesVault.includes(q.id));
    else if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));

    if (pool.length === 0) {
      alert("OT Vault: Selection resulted in zero units. Adjust filters.");
      return;
    }

    const count = selectedMode === 'mistakes' ? pool.length : Math.min(questionCount, pool.length);
    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, count);

    const preparedQuestions = shuffledPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);
        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors])).slice(0, 4);
        while(finalOptions.length < 4) finalOptions.push(`OT Option ${finalOptions.length + 1}`);
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setMode(selectedMode);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60);
    setView('playing');
    setImgError(false);
  };

  const handleFinish = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-50 flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-5xl grid lg:grid-cols-6 gap-10 my-8 animate-in fade-in slide-in-from-bottom-6 duration-1000">

           {/* Branding Card */}
           <div className="lg:col-span-4 space-y-8">
              <div className="bg-slate-950 rounded-[4rem] p-12 md:p-16 text-white relative overflow-hidden shadow-[0_40px_80px_rgba(0,0,0,0.25)] group">
                 <div className="absolute top-0 right-0 p-12 text-[#d4af37]/5 -rotate-12 group-hover:rotate-0 transition-transform duration-1000">
                    <Star size={300} strokeWidth={1} />
                 </div>

                 <div className="relative z-10 space-y-8">
                   <div className="flex items-center gap-4">
                     <span className="px-5 py-1.5 bg-rose-600 rounded-full text-[10px] font-black uppercase tracking-[0.3em] shadow-lg shadow-rose-600/20">Clinical Suite</span>
                     <div className="h-px w-12 bg-slate-800"></div>
                     <span className="ot-gold-text text-sm italic tracking-widest">CERTIFIED REGISTRY</span>
                   </div>

                   <div className="space-y-2">
                     <h2 className="text-4xl md:text-6xl font-black tracking-tighter uppercase leading-none">
                       ANATOMY <span className="text-slate-500">&</span><br/>
                       PHYSIOLOGY <span className="ot-gold-text italic">OT</span>
                     </h2>
                     <p className="text-xs md:text-sm font-bold text-slate-400 tracking-[0.2em] max-w-md leading-relaxed">
                       Access the world's most comprehensive anatomical data vault. 1100+ Nodes analyzed and verified.
                     </p>
                   </div>

                   <div className="flex items-center gap-10 pt-4">
                      <div className="flex flex-col">
                        <span className="text-[28px] font-black text-white leading-none">1,100+</span>
                        <span className="text-[10px] font-black text-rose-500 uppercase tracking-widest mt-1">Study Units</span>
                      </div>
                      <div className="h-8 w-px bg-slate-800"></div>
                      <div className="flex flex-col">
                        <span className="text-[28px] font-black text-white leading-none">12.0</span>
                        <span className="text-[10px] font-black text-rose-500 uppercase tracking-widest mt-1">Engine Version</span>
                      </div>
                   </div>
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                  <button onClick={() => setMode('exam')} className={`p-10 rounded-[3rem] border-2 transition-all flex flex-col items-center gap-4 shadow-xl group ${mode === 'exam' ? 'border-rose-500 bg-white ring-8 ring-rose-50' : 'border-slate-200 bg-white text-slate-300 hover:border-rose-200'}`}>
                    <Timer size={32} className={mode === 'exam' ? 'text-rose-600' : ''} /> 
                    <span className={`font-black text-xs uppercase tracking-[0.3em] ${mode === 'exam' ? 'text-slate-900' : ''}`}>STRICT EXAM</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-10 rounded-[3rem] border-2 transition-all flex flex-col items-center gap-4 shadow-xl group ${mode === 'practice' ? 'border-[#d4af37] bg-white ring-8 ring-amber-50' : 'border-slate-200 bg-white text-slate-300 hover:border-amber-200'}`}>
                    <Eye size={32} className={mode === 'practice' ? 'text-[#d4af37]' : ''} /> 
                    <span className={`font-black text-xs uppercase tracking-[0.3em] ${mode === 'practice' ? 'text-slate-900' : ''}`}>FREE PRACTICE</span>
                  </button>
              </div>
           </div>

           {/* Setup Sidebar */}
           <div className="lg:col-span-2 space-y-8">
              <div className="bg-white rounded-[3.5rem] p-10 border border-slate-200 shadow-2xl flex flex-col gap-10 sticky top-10">
                 <div className="space-y-6">
                    <div className="flex justify-between items-center text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">
                       <span>Batch Magnitude</span>
                       <span className="text-rose-600 bg-rose-50 px-3 py-1 rounded-lg border border-rose-100 font-black">{questionCount} Qs</span>
                    </div>
                    <input type="range" min="5" max="250" step="5" value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-rose-600 h-2 bg-slate-100 rounded-full appearance-none cursor-pointer" />
                 </div>

                 <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em] px-1 flex items-center gap-2">
                      <LayoutGrid size={14} /> Systems Filter
                    </h4>
                    <div className="max-h-64 overflow-y-auto custom-scrollbar space-y-1.5 bg-slate-50 p-3 rounded-[2rem] border border-slate-100">
                       {categories.map(cat => (
                         <button key={cat} onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} className={`w-full text-left px-4 py-3.5 rounded-xl text-[10px] font-black uppercase transition-all border-2 flex justify-between items-center ${selectedCategories.includes(cat) ? 'bg-white border-rose-500 text-rose-600 shadow-sm' : 'bg-white border-transparent text-slate-400 hover:bg-slate-100'}`}>
                           <span className="truncate pr-2">{cat}</span>
                           {selectedCategories.includes(cat) && <ShieldCheck size={14} />}
                         </button>
                       ))}
                    </div>
                 </div>

                 <button onClick={() => startQuiz(mode)} className="w-full py-7 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-sm tracking-[0.4em] shadow-2xl hover:bg-rose-600 transition-all flex items-center justify-center gap-4 active:scale-95 group overflow-hidden relative">
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                    <Zap size={22} className="text-[#d4af37]" /> INITIALIZE
                 </button>
              </div>

              {mistakesVault.length > 0 && (
                <button 
                  onClick={() => startQuiz('mistakes')}
                  className="w-full p-8 bg-rose-50 border-2 border-rose-100 rounded-[2.5rem] flex items-center justify-between group hover:bg-rose-100 transition-all shadow-lg"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-rose-600 rounded-2xl flex items-center justify-center text-white shadow-lg group-hover:rotate-12 transition-transform">
                      <AlertTriangle size={24} />
                    </div>
                    <div className="text-left leading-none">
                      <span className="text-xs font-black text-rose-700 uppercase tracking-widest block mb-1">MISTAKE VAULT</span>
                      <span className="text-xl font-black text-slate-900">{mistakesVault.length} Units</span>
                    </div>
                  </div>
                  <ChevronRight size={24} className="text-rose-300" />
                </button>
              )}
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden select-none lg:flex-row">
      {/* Sidebar Progress */}
      <aside className="hidden lg:flex flex-col w-72 bg-slate-50 border-r-2 border-slate-100 shrink-0 p-8 overflow-y-auto custom-scrollbar">
         <div className="space-y-8">
            <div className="flex items-center justify-between border-b border-slate-200 pb-5">
               <h3 className="font-black text-[11px] uppercase text-slate-500 tracking-[0.3em] flex items-center gap-2">
                 <LayoutGrid size={16} /> Matrix Map
               </h3>
               <span className="text-[10px] font-black text-[#d4af37] bg-slate-900 px-3 py-1 rounded-lg shadow-lg shadow-slate-900/20">{questions.length} Units</span>
            </div>
            <div className="grid grid-cols-4 gap-2.5">
               {questions.map((_, i) => (
                 <button key={i} onClick={() => { setCurrentQIndex(i); setImgError(false); }} className={`h-11 rounded-xl text-[10px] font-black transition-all flex items-center justify-center border-2 ${currentQIndex === i ? 'bg-rose-600 border-rose-500 text-white shadow-xl scale-110 z-10' : questions[i].userAnswer ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : 'bg-white border-white text-slate-300 hover:border-rose-200 hover:text-rose-500'}`}>{i + 1}</button>
               ))}
            </div>
         </div>
      </aside>

      {/* Main Examination Area */}
      <div className="flex-1 flex flex-col min-w-0 relative bg-white">
        <div className="bg-white border-b-2 border-slate-100 px-8 h-20 flex justify-between items-center shrink-0 z-10">
           <div className="flex items-center gap-6">
              <div className="flex flex-col">
                <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest mb-1">Anatomy & Physiology OT</span>
                <div className="flex items-center gap-3">
                  <div className="bg-slate-900 text-white text-[11px] px-5 py-2 rounded-xl font-black tracking-widest uppercase flex items-center gap-2">
                    NODE {currentQIndex + 1} <span className="text-[#d4af37]">/ {questions.length}</span>
                  </div>
                  {mode === 'exam' && (
                    <div className={`flex items-center gap-2 font-mono font-black text-lg ${timeLeft < 60 ? 'text-rose-600 animate-pulse' : 'text-slate-400'}`}>
                      <Clock size={20} /> {formatTime(timeLeft)}
                    </div>
                  )}
                </div>
              </div>
           </div>
           <button onClick={() => confirm("OT Protocol: Abort current examination?") && setView('setup')} className="p-3 text-slate-300 hover:text-rose-600 transition-all bg-slate-50 rounded-2xl hover:shadow-lg"><X size={28} /></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-14 custom-scrollbar bg-[#f8fafc]">
           {currentQ && (
           <div className="w-full max-w-3xl mx-auto space-y-10 pb-32">
              <div className="bg-white p-12 md:p-16 rounded-[4rem] border-2 border-slate-100 shadow-[0_50px_100px_rgba(0,0,0,0.06)] relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-2.5 h-full bg-[#d4af37]"></div>
                <div className="flex justify-between items-center mb-10">
                  <span className="text-[10px] font-black text-rose-500 uppercase tracking-[0.5em] bg-rose-50 px-4 py-1.5 rounded-full border border-rose-100">{currentQ.data.category}</span>
                  <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest font-mono">NODE-ID: {currentQ.id}</span>
                </div>
                <h3 className="text-2xl md:text-4xl font-black text-slate-900 leading-tight tracking-tighter italic" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
              </div>

