                </div>
              )}

              <div className="grid gap-5">
                 {currentQ.options.map((opt, i) => {
                   const isSelected = currentQ.userAnswer === opt;
                   const isCorrect = opt === currentQ.correctOption;
                   const showFeedback = ((mode === 'practice' || mode === 'mistakes') && !!currentQ.userAnswer) || view === 'review';

                   let style = "bg-white border-2 border-slate-200 text-slate-700 hover:border-rose-400 hover:shadow-xl";
                   if (isSelected) style = "border-rose-600 bg-rose-50 text-slate-900 shadow-2xl ring-8 ring-rose-50";

