        const existingIndex = prev.findIndex(q => q.id === question.id);
        if (existingIndex >= 0) {
            const newVault = [...prev];
            newVault[existingIndex] = question;
            return newVault;
        } else return [question, ...prev];
    });
    setEditingId(null);
    setCurrentMode(AppMode.LIST);
  };

  return (
    <div className="h-[100dvh] w-full flex flex-col bg-slate-50 font-sans text-slate-900 overflow-hidden fixed inset-0">
      {isHeaderVisible && (
        <Header currentMode={currentMode} onModeChange={(m) => { setCurrentMode(m); setEditingId(null); }} />
      )}

      <main className={`flex-1 relative overflow-hidden flex flex-col w-full mx-auto ${isHeaderVisible ? 'max-w-7xl' : 'max-w-full'}`}>
        {currentMode === AppMode.FLASHCARDS && (
          <div className="flex-1 h-full animate-in fade-in duration-500">
            <Flashcards data={allQuestions} onEdit={handleEditRequest} />
          </div>
        )}

        {currentMode === AppMode.ATLAS && (
          <div className="flex-1 h-full animate-in slide-in-from-right duration-500">
            <InteractiveAtlas data={allQuestions} />
          </div>
        )}

        {currentMode === AppMode.QUIZ && (
          <div className="flex-1 h-full animate-in zoom-in-95 duration-500">
            <Quiz 
              data={allQuestions} 
              onEdit={handleEditRequest} 
              toggleHeader={setIsHeaderVisible} 
            />
          </div>
        )}

        {currentMode === AppMode.LIST && (
          <div className="flex-1 h-full overflow-y-auto px-3 py-4 custom-scrollbar">
            <QuestionList 
              data={allQuestions} 
              onExport={() => {}} 
              onImport={() => {}} 
              onEdit={handleEditRequest} 
            />
            <div className="flex justify-center p-12">
               <button onClick={() => confirm("Reset all records?") && setUserVault([])} className="text-[10px] font-black text-rose-300 uppercase tracking-widest hover:text-rose-500 transition-colors">
                 <Trash2 size={12} className="inline mr-1" /> Factory Reset Anatomy Vault
               </button>
            </div>
          </div>
        )}

        {currentMode === AppMode.BUILDER && (
          <div className="flex-1 h-full overflow-y-auto custom-scrollbar">
            <QuestionBuilder allQuestions={allQuestions} editingId={editingId} onSave={handleSaveQuestion} onCancel={() => { setEditingId(null); setCurrentMode(AppMode.LIST); }} existingCategories={[]} />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  AlertTriangle, Eye, Timer, Activity, 
  ShieldCheck, LayoutGrid, Zap, History, Star,
  Search, CheckCircle2, RotateCcw
} from 'lucide-react';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) return url.substring(url.lastIndexOf('http'));
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('practice');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [searchCat, setSearchCat] = useState('');

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  // استعادة الهيدر عند الخروج من مكون الاختبار
  useEffect(() => {
    return () => {
      toggleHeader?.(true);
    };
  }, []);

  const categories = useMemo(() => {
    const allCats = Array.from(new Set(data.map(q => q.category))).sort();
    if (!searchCat.trim()) return allCats;
    return allCats.filter(c => c.toLowerCase().includes(searchCat.toLowerCase()));
  }, [data, searchCat]);

  // حساب العدد المتوفر بناءً على الفلاتر الحالية
  const availablePoolSize = useMemo(() => {
    if (mode === 'mistakes') return mistakesVault.length;
    let pool = data;
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }
    return pool.length;
  }, [data, selectedCategories, mode, mistakesVault]);

  const getCategoryCount = (cat: string) => data.filter(q => q.category === cat).length;

  const startQuiz = (selectedMode: 'exam' | 'practice' | 'mistakes') => {
    let pool = data;
    if (selectedMode === 'mistakes') pool = data.filter(q => mistakesVault.includes(q.id));
    else if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));

    if (pool.length === 0) {
      alert("OT Vault: Selection resulted in zero units. Adjust filters.");
      return;
    }

    const count = selectedMode === 'mistakes' ? pool.length : Math.min(questionCount, pool.length);
    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, count);

    const preparedQuestions = shuffledPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);
        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors])).slice(0, 4);
        while(finalOptions.length < 4) finalOptions.push(`OT Option ${finalOptions.length + 1}`);
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setMode(selectedMode);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60);
    setView('playing');
    setImgError(false);

    // إخفاء الهيدر للدخول في وضع التركيز الكامل
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true); // إعادة إظهار الهيدر في النتائج
  };

  const exitQuiz = () => {
    if (confirm("OT Protocol: Abort current examination?")) {
      setView('setup');
      toggleHeader?.(true);
    }
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-50 flex flex-col items-center p-4 overflow-y-auto custom-scrollbar pb-32">
        <div className="w-full max-w-6xl grid lg:grid-cols-6 gap-8 my-4 animate-in fade-in slide-in-from-bottom-6 duration-1000">

           {/* Branding Card */}
           <div className="lg:col-span-4 space-y-6">
              <div className="bg-slate-950 rounded-[3rem] p-10 md:p-14 text-white relative overflow-hidden shadow-[0_40px_80px_rgba(0,0,0,0.25)] group">
                 <div className="absolute top-0 right-0 p-12 text-[#d4af37]/5 -rotate-12 group-hover:rotate-0 transition-transform duration-1000">
                    <Star size={300} strokeWidth={1} />
                 </div>

                 <div className="relative z-10 space-y-6">
                   <div className="flex items-center gap-4">
                     <span className="px-4 py-1.5 bg-rose-600 rounded-full text-[9px] font-black uppercase tracking-[0.3em] shadow-lg shadow-rose-600/20">Clinical Suite</span>
                     <div className="h-px w-10 bg-slate-800"></div>
                     <span className="ot-gold-text text-xs italic tracking-widest">CERTIFIED REGISTRY</span>
                   </div>

                   <div className="space-y-2">
                     <h2 className="text-4xl md:text-5xl font-black tracking-tighter uppercase leading-none">
                       ANATOMY <span className="text-slate-500">&</span><br/>
                       PHYSIOLOGY <span className="ot-gold-text italic">OT</span>
                     </h2>
                     <p className="text-xs md:text-sm font-bold text-slate-400 tracking-[0.2em] max-w-md leading-relaxed">
                       Access the world's most comprehensive anatomical data vault. 1100+ Nodes analyzed and verified.
                     </p>
                   </div>

                   <div className="flex items-center gap-10 pt-2">
                      <div className="flex flex-col">
                        <span className="text-2xl font-black text-white leading-none">1,100+</span>
                        <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest mt-1">Study Units</span>
                      </div>
                      <div className="h-8 w-px bg-slate-800"></div>
                      <div className="flex flex-col">
                        <span className="text-2xl font-black text-white leading-none">12.0</span>
                        <span className="text-[9px] font-black text-rose-500 uppercase tracking-widest mt-1">Engine Version</span>
                      </div>
                   </div>
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-5">
                  <button onClick={() => setMode('exam')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 shadow-lg group active:scale-95 ${mode === 'exam' ? 'border-rose-500 bg-white ring-4 ring-rose-50 shadow-rose-100' : 'border-slate-200 bg-white text-slate-300 hover:border-rose-200'}`}>
                    <Timer size={28} className={mode === 'exam' ? 'text-rose-600' : ''} /> 
                    <span className={`font-black text-[10px] uppercase tracking-[0.3em] ${mode === 'exam' ? 'text-slate-900' : ''}`}>STRICT EXAM</span>
                  </button>
                  <button onClick={() => setMode('practice')} className={`p-8 rounded-[2.5rem] border-2 transition-all flex flex-col items-center gap-3 shadow-lg group active:scale-95 ${mode === 'practice' ? 'border-[#d4af37] bg-white ring-4 ring-amber-50 shadow-amber-100' : 'border-slate-200 bg-white text-slate-300 hover:border-amber-200'}`}>
                    <Eye size={28} className={mode === 'practice' ? 'text-[#d4af37]' : ''} /> 
                    <span className={`font-black text-[10px] uppercase tracking-[0.3em] ${mode === 'practice' ? 'text-slate-900' : ''}`}>FREE PRACTICE</span>
                  </button>
              </div>
           </div>

           {/* Setup Sidebar */}
           <div className="lg:col-span-2 space-y-6">
              <div className="bg-white rounded-[3rem] p-8 border border-slate-200 shadow-xl flex flex-col gap-8 sticky top-6">

                 <div className="space-y-4">
                    <div className="flex justify-between items-center text-[9px] font-black text-slate-400 uppercase tracking-[0.3em]">
                       <span>Batch Magnitude</span>
                       <span className="text-rose-600 bg-rose-50 px-2 py-1 rounded-md border border-rose-100 font-black">{questionCount} Qs</span>
                    </div>
                    <input type="range" min="5" max="250" step="5" value={questionCount} onChange={e => setQuestionCount(parseInt(e.target.value))} className="w-full accent-rose-600 h-1.5 bg-slate-100 rounded-full appearance-none cursor-pointer" />
                 </div>

                 <div className="space-y-3 flex-1 flex flex-col min-h-0">
                    <div className="flex items-center justify-between">
                      <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] flex items-center gap-2">
                        <LayoutGrid size={12} /> Systems Filter
                      </h4>
                      <div className="flex gap-2">
                        <button onClick={() => setSelectedCategories([...categories])} className="text-[8px] font-bold text-blue-500 uppercase tracking-widest hover:bg-blue-50 px-2 py-1 rounded">All</button>
                        <button onClick={() => setSelectedCategories([])} className="text-[8px] font-bold text-slate-400 uppercase tracking-widest hover:bg-slate-100 px-2 py-1 rounded">None</button>
                      </div>
                    </div>

                    <div className="relative group">
                      <input 
                        type="text" 
                        placeholder="Search Chapter..." 
                        value={searchCat}
                        onChange={e => setSearchCat(e.target.value)}
                        className="w-full pl-9 pr-3 py-2.5 rounded-xl bg-slate-50 border border-slate-200 text-xs font-bold text-slate-700 focus:border-rose-500 outline-none transition-all placeholder:text-slate-300"
                      />
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={14} />
                    </div>

                    <div className="h-60 overflow-y-auto custom-scrollbar space-y-1.5 bg-slate-50/50 p-2 rounded-2xl border border-slate-100">
                       {categories.length > 0 ? categories.map(cat => {
                         const isSelected = selectedCategories.includes(cat);
                         const count = getCategoryCount(cat);
                         return (
                           <button 
                            key={cat} 
                            onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} 
                            className={`w-full text-left px-3 py-3 rounded-xl transition-all border flex justify-between items-center group ${isSelected ? 'bg-white border-rose-500 shadow-sm' : 'bg-transparent border-transparent hover:bg-white hover:border-slate-200'}`}
                           >
                             <div className="flex flex-col min-w-0 pr-2">
                               <span className={`text-[10px] font-bold uppercase truncate ${isSelected ? 'text-slate-800' : 'text-slate-400'}`}>{cat}</span>
                               <span className="text-[8px] font-bold text-slate-300 tracking-wider">{count} Nodes</span>
                             </div>
                             <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center shrink-0 transition-colors ${isSelected ? 'border-rose-500 bg-rose-50 text-rose-600' : 'border-slate-200 text-transparent'}`}>
                               <CheckCircle2 size={12} strokeWidth={4} />
                             </div>
                           </button>
                         );
                       }) : (
                         <div className="text-center py-8 text-[10px] font-bold text-slate-300 uppercase tracking-widest">No systems found</div>
                       )}
                    </div>
                 </div>

                 <button onClick={() => startQuiz(mode)} className="w-full py-6 bg-slate-900 text-white rounded-3xl font-black uppercase text-xs tracking-[0.4em] shadow-xl hover:bg-rose-600 transition-all flex items-center justify-center gap-4 active:scale-95 group overflow-hidden relative">
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
                    <div className="flex flex-col items-start leading-none gap-1">
                      <span className="flex items-center gap-2">INITIALIZE <Zap size={14} className="text-[#d4af37]" /></span>
                      <span className="text-[8px] text-slate-400 font-bold">Pool: {availablePoolSize} Units</span>
                    </div>
                 </button>
              </div>

              {mistakesVault.length > 0 && (
                <button 
                  onClick={() => startQuiz('mistakes')}
                  className="w-full p-6 bg-rose-50 border border-rose-100 rounded-[2rem] flex items-center justify-between group hover:bg-rose-100 transition-all shadow-md"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-rose-600 rounded-xl flex items-center justify-center text-white shadow-lg group-hover:rotate-12 transition-transform">
                      <AlertTriangle size={20} />
                    </div>
                    <div className="text-left leading-none">
                      <span className="text-[9px] font-black text-rose-700 uppercase tracking-widest block mb-1">Anomaly Vault</span>
                      <span className="text-lg font-black text-slate-900">{mistakesVault.length} Records</span>
                    </div>
                  </div>
                  <ChevronRight size={20} className="text-rose-300" />
                </button>
              )}
           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50">
        <div className="bg-white rounded-[3rem] p-16 shadow-2xl border border-slate-100 text-center space-y-10 max-w-2xl w-full">
           <div className="relative inline-block">
             <svg className="w-48 h-48 transform -rotate-90">
               <circle cx="96" cy="96" r="88" stroke="#f1f5f9" strokeWidth="12" fill="transparent" />
