           <div className="flex gap-4 pt-4">
             <button onClick={() => setView('setup')} className="flex-1 py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit Portal</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="flex-1 py-3 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Review Answers</button>
           </div>
        </div>
