            </div>
            <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
               <div className="w-3 h-3 bg-slate-200 rounded-sm"></div> Answered
            </div>
            <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
               <div className="w-3 h-3 bg-amber-100 border border-amber-300 rounded-sm"></div> Flagged
            </div>
         </div>
      </aside>

      {/* Main Examination Area */}
      <div className="flex-1 flex flex-col min-w-0 relative h-full">

        {/* Top Bar */}
        <div className="bg-white border-b border-slate-200 px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20">
           <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500"><List /></button>

           <div className="flex items-center gap-4">
              <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline">Anatomy Final</span>
              <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
              <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 rounded-lg ${timeLeft < 300 ? 'text-rose-600' : 'text-slate-700'}`}>
                 <Clock size={16} /> {formatTime(timeLeft)}
              </div>
           </div>

           <button onClick={exitQuiz} className="px-4 py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest">
              Abort Exam
           </button>
        </div>

        {/* Question Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
           <div className="max-w-4xl mx-auto space-y-8 pb-20">
              {/* Question Card */}
              <div className="bg-white p-8 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                <div className="absolute top-0 left-0 w-full h-1.5 bg-blue-600 rounded-t-[1.5rem]"></div>
                <div className="flex justify-between items-start mb-6">
                   <div className="flex items-center gap-3">
                      <span className="text-2xl font-black text-slate-300">Q{currentQIndex + 1}</span>
                      <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[10px] font-bold uppercase tracking-wide">{currentQ?.data.category}</span>
                   </div>
                   <button 
                    onClick={() => setQuestions(prev => {
                       const copy = [...prev];
                       copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                       return copy;
                    })}
                    className={`p-2 rounded-full transition-colors ${currentQ?.isFlagged ? 'text-amber-500 bg-amber-50' : 'text-slate-300 hover:text-slate-500'}`}
                   >
                      <Flag size={20} fill={currentQ?.isFlagged ? "currentColor" : "none"} />
                   </button>
                </div>

                <div className="prose prose-lg max-w-none mb-8">
                   <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                </div>

                {currentQ?.data.questionImage && !imgError && (
                  <div className="mb-8 p-4 border border-slate-100 rounded-xl bg-slate-50 flex justify-center">
                     <img src={cleanImageUrl(currentQ.data.questionImage)} className="max-h-96 object-contain rounded-lg" onError={() => setImgError(true)} alt="Question Reference" />
                  </div>
                )}

                <div className="space-y-3">
                   {currentQ?.options.map((opt, i) => {
                     const isSelected = currentQ.userAnswer === opt;
                     return (
                       <button 
                        key={i} 
                        onClick={() => setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} 
                        className={`w-full text-left p-5 rounded-xl border-2 transition-all flex items-center gap-4 group ${isSelected ? 'border-blue-500 bg-blue-50/50 shadow-sm' : 'border-slate-100 hover:border-slate-300 hover:bg-slate-50'}`}
                       >
                         <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center shrink-0 ${isSelected ? 'border-blue-500 bg-blue-500' : 'border-slate-300 group-hover:border-slate-400'}`}>
                            {isSelected && <div className="w-2 h-2 bg-white rounded-full"></div>}
                         </div>
                         <span className={`text-base font-medium ${isSelected ? 'text-blue-900' : 'text-slate-700'}`} dangerouslySetInnerHTML={{ __html: opt }} />
                       </button>
                     );
                   })}
                </div>
              </div>
           </div>
        </div>

        {/* Footer Navigation */}
        <div className="bg-white border-t border-slate-200 p-4 md:px-8 h-20 flex justify-between items-center shrink-0 z-20">
           <button 
            onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
            disabled={currentQIndex === 0} 
            className="px-6 py-3 rounded-lg border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 disabled:opacity-50 transition-all flex items-center gap-2"
           >
             <ChevronLeft size={16} /> Previous
           </button>

           <div className="hidden md:block text-xs font-bold text-slate-400 uppercase tracking-widest">
              Question {currentQIndex + 1} of {questions.length}
           </div>

           <button 
            onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
            className={`px-8 py-3 rounded-lg font-black text-xs uppercase tracking-widest text-white shadow-md transition-all flex items-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700' : 'bg-blue-600 hover:bg-blue-700'}`}
           >
              {currentQIndex === questions.length - 1 ? 'Submit Assessment' : 'Next Question'} <ChevronRight size={16} />
           </button>
        </div>
      </div>
    </div>
  );
};

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  AlertTriangle, Timer, Activity, 
  ShieldCheck, LayoutGrid, Zap, Star,
  Search, CheckCircle2, FileText, GraduationCap,
  Flag, List, MousePointer2, Image as ImageIcon
} from 'lucide-react';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) return url.substring(url.lastIndexOf('http'));
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [searchCat, setSearchCat] = useState('');
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
    };
  }, []);

  const categories = useMemo(() => {
    const allCats = Array.from(new Set(data.map(q => q.category))).sort();
    if (!searchCat.trim()) return allCats;
    return allCats.filter(c => c.toLowerCase().includes(searchCat.toLowerCase()));
  }, [data, searchCat]);

  const availablePoolSize = useMemo(() => {
    if (mode === 'mistakes') return mistakesVault.length;
    let pool = data;
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }
    return pool.length;
  }, [data, selectedCategories, mode, mistakesVault]);

  const getCategoryCount = (cat: string) => data.filter(q => q.category === cat).length;

  const startQuiz = () => {
    let pool = data;
    if (mode === 'mistakes') pool = data.filter(q => mistakesVault.includes(q.id));
    else if (selectedCategories.length > 0) pool = pool.filter(q => selectedCategories.includes(q.category));

    if (pool.length === 0) {
      alert("System Error: No questions available for the selected criteria.");
      return;
    }

    const count = mode === 'mistakes' ? pool.length : Math.min(questionCount, pool.length);
    const shuffledPool = [...pool].sort(() => Math.random() - 0.5).slice(0, count);

    const preparedQuestions = shuffledPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);
        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors])).slice(0, 4);
        while(finalOptions.length < 4) finalOptions.push(`Option ${finalOptions.length + 1}`);
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    setTimeLeft(preparedQuestions.length * 60); // 1 minute per question standard
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Warning: Ending the exam now will result in a loss of progress. Are you sure?")) {
      setView('setup');
      toggleHeader?.(true);
    }
  };

  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-50 flex flex-col items-center p-4 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-5xl bg-white rounded-[2rem] shadow-xl border border-slate-200 overflow-hidden flex flex-col md:flex-row my-8 animate-in fade-in slide-in-from-bottom-4 duration-700">

           {/* University Portal Sidebar */}
           <div className="md:w-1/3 bg-slate-900 text-white p-10 flex flex-col justify-between relative overflow-hidden">
              <div className="absolute top-0 right-0 p-20 bg-blue-600/10 rounded-full -mr-10 -mt-10 blur-2xl"></div>

              <div className="relative z-10 space-y-6">
                 <div className="flex items-center gap-3 text-blue-400">
                    <GraduationCap size={32} />
                    <span className="font-bold tracking-widest text-xs uppercase">Student Portal</span>
                 </div>

                 <div className="space-y-2">
                    <h1 className="text-3xl font-black leading-tight">Anatomy & Physiology <br/><span className="text-blue-500">Exam Suite</span></h1>
                    <p className="text-slate-400 text-sm leading-relaxed">Official assessment environment. Please configure your examination parameters below.</p>
                 </div>

                 <div className="py-6 border-t border-slate-800 space-y-4">
                    <div className="flex justify-between items-center text-sm">
                       <span className="text-slate-400">Course Code</span>
                       <span className="font-mono font-bold">BIO-201</span>
                    </div>
                    <div className="flex justify-between items-center text-sm">
                       <span className="text-slate-400">Term</span>
                       <span className="font-mono font-bold">Fall 2025</span>
                    </div>
                    <div className="flex justify-between items-center text-sm">
                       <span className="text-slate-400">Status</span>
                       <span className="text-emerald-400 font-bold flex items-center gap-2"><div className="w-2 h-2 bg-emerald-400 rounded-full animate-pulse"></div> Online</span>
                    </div>
                 </div>
              </div>

              <div className="relative z-10">
                 <p className="text-[10px] text-slate-500 uppercase tracking-widest text-center">System v4.2 • Secured</p>
              </div>
           </div>

           {/* Configuration Area */}
           <div className="md:w-2/3 p-10 md:p-14 space-y-8 bg-white">

              <div className="space-y-4">
                 <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest flex items-center gap-2">
                    <CheckCircle2 size={16} className="text-blue-600" /> Select Examination Scope
                 </h3>
                 <div className="bg-slate-50 rounded-2xl p-4 border border-slate-200 h-64 overflow-y-auto custom-scrollbar space-y-1">
                    {categories.length > 0 ? categories.map(cat => {
                       const isSelected = selectedCategories.includes(cat);
                       return (
                         <button 
                          key={cat} 
                          onClick={() => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])} 
                          className={`w-full text-left px-4 py-3 rounded-xl text-xs font-bold transition-all flex justify-between items-center ${isSelected ? 'bg-white shadow-md text-blue-700 border border-blue-100' : 'text-slate-500 hover:bg-slate-100'}`}
                         >
                           <span>{cat}</span>
                           {isSelected && <CheckCircle2 size={14} />}
                         </button>
                       )
                    }) : <div className="text-center p-4 text-slate-400 text-xs">No active courses found</div>}
                 </div>
                 <div className="flex justify-between items-center">
                    <button onClick={() => setSelectedCategories([...categories])} className="text-[10px] font-bold text-blue-600 hover:underline uppercase tracking-wider">Select All Chapters</button>
                    <button onClick={() => setSelectedCategories([])} className="text-[10px] font-bold text-slate-400 hover:text-slate-600 uppercase tracking-wider">Clear Selection</button>
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Question Count</label>
                    <select 
                      value={questionCount} 
                      onChange={(e) => setQuestionCount(Number(e.target.value))}
                      className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-sm text-slate-700 focus:border-blue-500 outline-none"
                    >
                       <option value="10">10 Questions (Quick)</option>
                       <option value="25">25 Questions (Standard)</option>
                       <option value="50">50 Questions (Midterm)</option>
                       <option value="100">100 Questions (Final)</option>
                    </select>
                 </div>
                 <div className="space-y-3">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Exam Mode</label>
                    <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-200">
                       <button onClick={() => setMode('exam')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${mode === 'exam' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-400'}`}>Exam</button>
                       <button onClick={() => setMode('practice')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${mode === 'practice' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-400'}`}>Practice</button>
                    </div>
                 </div>
              </div>

              <div className="pt-4">
                 <button 
                  onClick={startQuiz}
                  className="w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-black text-sm uppercase tracking-[0.2em] shadow-lg shadow-blue-200 transition-all flex items-center justify-center gap-3 active:scale-95"
                 >
                    <FileText size={18} /> Start Examination
                 </button>
                 <p className="text-center mt-4 text-[10px] text-slate-400">
                    By clicking Start, you agree to the academic integrity policy.
                 </p>
              </div>

           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50">
        <div className="bg-white rounded-[2rem] p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8">
           <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-slate-100">
              <span className={`text-3xl font-black ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-2">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <p className="text-slate-500 font-medium text-sm">
                Score: {score} / {questions.length} <br/>
                Grade: {percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}
             </p>
           </div>

           <div className="flex gap-4 pt-4">
             <button onClick={() => setView('setup')} className="flex-1 py-3 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit Portal</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="flex-1 py-3 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Review Answers</button>
           </div>
        </div>
      </div>
    );
  }

  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-8 overflow-y-auto custom-scrollbar">
        <div className="max-w-4xl mx-auto space-y-6 pb-32">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200">Return to Results</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                 </div>
               </div>
               <div className="pl-10 space-y-2 text-sm">
                 <div className="flex justify-between p-3 rounded-lg bg-slate-50">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`}>{q.userAnswer || 'No Selection'}</span>
