                     <span className="font-bold text-emerald-700">{q.correctOption}</span>
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  // Playing View - University Style
  return (
    <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

      {/* Question Navigation Sidebar (Scantron Style) */}
