           <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500"><List /></button>

           <div className="flex items-center gap-4">
              <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline">Anatomy Final</span>
              <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
              <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-3 py-1.5 rounded-lg ${timeLeft < 300 ? 'text-rose-600' : 'text-slate-700'}`}>
                 <Clock size={16} /> {formatTime(timeLeft)}
              </div>
           </div>

           <button onClick={exitQuiz} className="px-4 py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest">
              Abort Exam
           </button>
        </div>

        {/* Question Area */}
        <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
           <div className="max-w-4xl mx-auto space-y-8 pb-20">
              {/* Question Card */}
              <div className="bg-white p-8 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                <div className="absolute top-0 left-0 w-full h-1.5 bg-blue-600 rounded-t-[1.5rem]"></div>
                <div className="flex justify-between items-start mb-6">
                   <div className="flex items-center gap-3">
                      <span className="text-2xl font-black text-slate-300">Q{currentQIndex + 1}</span>
                      <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[10px] font-bold uppercase tracking-wide">{currentQ?.data.category}</span>
                   </div>
                   <button 
                    onClick={() => setQuestions(prev => {
                       const copy = [...prev];
                       copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                       return copy;
                    })}
                    className={`p-2 rounded-full transition-colors ${currentQ?.isFlagged ? 'text-amber-500 bg-amber-50' : 'text-slate-300 hover:text-slate-500'}`}
                   >
                      <Flag size={20} fill={currentQ?.isFlagged ? "currentColor" : "none"} />
                   </button>
                </div>

                <div className="prose prose-lg max-w-none mb-8">
                   <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                </div>

                {currentQ?.data.questionImage && !imgError && (
                  <div className="mb-10 w-full bg-slate-50 rounded-[2rem] border border-slate-200 overflow-hidden flex flex-col">
                     <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                        <ImageIcon size={16} className="text-slate-400" />
                        <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                     </div>
                     <div className="p-6 flex items-center justify-center bg-[#f8fafc]">
                        <img 
                          src={cleanImageUrl(currentQ.data.questionImage)} 
                          className="max-h-[500px] w-auto object-contain transition-all hover:scale-[1.02] duration-500" 
                          onError={() => setImgError(true)} 
                          alt="Question Reference" 
                          referrerPolicy="no-referrer"
                        />
                     </div>
                  </div>
                )}

                <div className="space-y-3">
                   {currentQ?.options.map((opt, i) => {
                     const isSelected = currentQ.userAnswer === opt;
                     return (
                       <button 
                        key={i} 
                        onClick={() => setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} 
                        className={`w-full text-left p-5 rounded-xl border-2 transition-all flex items-center gap-4 group ${isSelected ? 'border-blue-500 bg-blue-50/50 shadow-sm' : 'border-slate-100 hover:border-slate-300 hover:bg-slate-50'}`}
                       >
                         <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center shrink-0 ${isSelected ? 'border-blue-500 bg-blue-500' : 'border-slate-300 group-hover:border-slate-400'}`}>
                            {isSelected && <div className="w-2 h-2 bg-white rounded-full"></div>}
                         </div>
                         <span className={`text-base font-medium ${isSelected ? 'text-blue-900' : 'text-slate-700'}`} dangerouslySetInnerHTML={{ __html: opt }} />
                       </button>
                     );
                   })}
                </div>
              </div>
           </div>
        </div>

        {/* Footer Navigation */}
        <div className="bg-white border-t border-slate-200 p-4 md:px-8 h-20 flex justify-between items-center shrink-0 z-20">
           <button 
            onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
            disabled={currentQIndex === 0} 
            className="px-6 py-3 rounded-lg border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 disabled:opacity-50 transition-all flex items-center gap-2"
           >
             <ChevronLeft size={16} /> Previous
           </button>

           <div className="hidden md:block text-xs font-bold text-slate-400 uppercase tracking-widest">
              Question {currentQIndex + 1} of {questions.length}
           </div>

           <button 
            onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
            className={`px-8 py-3 rounded-lg font-black text-xs uppercase tracking-widest text-white shadow-md transition-all flex items-center gap-2 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700' : 'bg-blue-600 hover:bg-blue-700'}`}
           >
              {currentQIndex === questions.length - 1 ? 'Submit Assessment' : 'Next Question'} <ChevronRight size={16} />
           </button>
        </div>
      </div>
    </div>
  );
};

