import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, Layers, 
  CheckCircle2, FileText, Flag, List, Image as ImageIcon,
  AlertCircle, Shuffle, Filter
} from 'lucide-react';

const cleanImageUrl = (url: string) => {
  if (!url) return '';
  if (url.includes('http') && url.lastIndexOf('http') > 0) return url.substring(url.lastIndexOf('http'));
  return url;
};

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  onEdit?: (id: string) => void;
  toggleHeader?: (visible: boolean) => void;
}

const Quiz: React.FC<QuizProps> = ({ data, onEdit, toggleHeader }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [imgError, setImgError] = useState(false);

  // Setup State matching the screenshot
  const [mode, setMode] = useState<'exam' | 'practice' | 'cards'>('exam');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [questionCount, setQuestionCount] = useState(25);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isShuffle, setIsShuffle] = useState(true);
  const [showDiagramsOnly, setShowDiagramsOnly] = useState(false);

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    const saved = localStorage.getItem('anatomy_mistakes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    return () => {
      toggleHeader?.(true);
    };
  }, []);

  const categories = useMemo(() => {
    return Array.from(new Set(data.map(q => q.category))).sort();
  }, [data]);

  const startSession = () => {
    if (mode === 'cards') {
      alert("Please use the 'Flashcards' tab in the main menu for this mode.");
      return; 
    }

    let pool = data;

    // Filter by Category
    if (selectedCategories.length > 0) {
      pool = pool.filter(q => selectedCategories.includes(q.category));
    }

    // Filter Diagrams
    if (showDiagramsOnly) {
      pool = pool.filter(q => q.questionImage || q.answerImage);
    }

    if (pool.length === 0) {
      alert("No questions found for these settings.");
      return;
    }

    // Shuffle if enabled
    if (isShuffle) {
      pool = [...pool].sort(() => Math.random() - 0.5);
    }

    // Slice count
    const finalPool = pool.slice(0, questionCount);

    const preparedQuestions = finalPool.map(q => {
      let finalOptions = q.options && q.options.length >= 4 ? [...q.options] : [];

      // Fallback generator for missing options
      if (finalOptions.length < 4) {
        const distractors = data
          .filter(item => item.category === q.category && item.answerText !== q.answerText)
          .map(item => item.answerText)
          .sort(() => Math.random() - 0.5)
          .slice(0, 4 - finalOptions.length);

        finalOptions = Array.from(new Set([q.answerText, ...finalOptions, ...distractors]));

        // Final fallback if still not enough
        while(finalOptions.length < 4) {
           finalOptions.push(`Option ${finalOptions.length + 1}`);
        }
      }

      return {
        id: q.id, data: q,
        options: finalOptions.sort(() => Math.random() - 0.5),
        correctOption: q.answerText, userAnswer: null, isFlagged: false
      } as QuizQuestion;
    });

    setQuestions(preparedQuestions);
    setCurrentQIndex(0);
    // Exam mode = 1 min per question, Practice = Unlimited (just tracking)
    setTimeLeft(preparedQuestions.length * 60); 
    setView('playing');
    setImgError(false);
    toggleHeader?.(false);
  };

  const handleFinish = () => {
    const wrongOnes = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).map(q => q.id);
    const correctOnes = questions.filter(q => q.userAnswer === q.correctOption).map(q => q.id);
    setMistakesVault(prev => {
      const added = Array.from(new Set([...prev, ...wrongOnes]));
      return added.filter(id => !correctOnes.includes(id));
    });
    setView('results');
    toggleHeader?.(true);
  };

  const exitQuiz = () => {
    if (confirm("Abort session? Progress will be lost.")) {
      setView('setup');
      toggleHeader?.(true);
    }
  };

  // --- VIEW: SETUP (Matching the Screenshot) ---
  if (view === 'setup') {
    return (
      <div className="h-full bg-slate-100 flex flex-col items-center justify-center p-4 overflow-y-auto">
        <div className="w-full max-w-md bg-white rounded-3xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-300 border border-slate-200">

           {/* Header - Dark Blue */}
           <div className="bg-[#0f172a] p-6 flex justify-between items-center text-white">
              <div className="flex items-center gap-3">
                 <div className="p-2 bg-white/10 rounded-lg">
                    <LayoutGrid size={20} className="text-rose-500" />
                 </div>
                 <h2 className="text-xl font-bold">Assessment Setup</h2>
              </div>
              <div className="text-right">
                 <div className="text-2xl font-black">{data.length}</div>
                 <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">BANK</div>
              </div>
           </div>

           <div className="p-6 space-y-6">

              {/* Mode Selection Cards */}
              <div className="space-y-3">
                 {/* Exam Card */}
                 <button 
                   onClick={() => setMode('exam')}
                   className={`w-full p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'exam' ? 'border-rose-500 bg-rose-50' : 'border-slate-100 hover:border-slate-200'}`}
                 >
                    <Clock size={24} className={mode === 'exam' ? 'text-rose-600' : 'text-slate-400'} />
                    <span className="font-bold text-slate-800 text-sm">Exam</span>
                    <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">TIMED</span>
                 </button>

                 {/* Practice Card */}
                 <button 
                   onClick={() => setMode('practice')}
                   className={`w-full p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'practice' ? 'border-blue-500 bg-blue-50' : 'border-slate-100 hover:border-slate-200'}`}
                 >
                    <Zap size={24} className={mode === 'practice' ? 'text-blue-600' : 'text-slate-400'} />
                    <span className="font-bold text-slate-800 text-sm">Practice</span>
                    <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">INSTANT</span>
                 </button>

                 {/* Cards Card (Visual only, redirects) */}
                 <button 
                   onClick={() => setMode('cards')}
                   className={`w-full p-4 rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-1 ${mode === 'cards' ? 'border-amber-500 bg-amber-50' : 'border-slate-100 hover:border-slate-200'}`}
                 >
                    <Layers size={24} className={mode === 'cards' ? 'text-amber-600' : 'text-slate-400'} />
                    <span className="font-bold text-slate-800 text-sm">Cards</span>
                    <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">MANUAL</span>
                 </button>
              </div>

              {/* Question Bank Select */}
              <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Question Bank</label>
                 <button 
                   onClick={() => {
                     // Toggle All/None for simplicity in this UI
                     if(selectedCategories.length === 0) setSelectedCategories([categories[0]]); 
                     else setSelectedCategories([]);
                   }}
                   className="w-full p-4 bg-white border border-slate-200 rounded-xl flex justify-between items-center shadow-sm hover:border-rose-200 transition-colors"
                 >
                    <div className="flex items-center gap-3">
                       <div className="text-rose-500"><FilterIcon size={18}/></div> 
                       <span className="font-bold text-sm text-slate-700">
                         {selectedCategories.length === 0 ? "All Topics" : "Specific Topics Selected"}
                       </span>
                    </div>
                    <ChevronRight size={18} className="text-slate-400" />
                 </button>
              </div>

              {/* Slider (Red Thumb) */}
              <div className="space-y-4">
                 <div className="flex justify-between items-center px-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Quantity: {questionCount}</label>
                 </div>
                 <input 
                   type="range" 
                   min="5" 
                   max="100" 
                   step="5"
                   value={questionCount}
                   onChange={(e) => setQuestionCount(Number(e.target.value))}
                   className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-[#e11d48]"
                 />
              </div>

              {/* Toggles Row */}
              <div className="flex gap-3">
                 <button 
                   onClick={() => setShowDiagramsOnly(!showDiagramsOnly)}
                   className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${showDiagramsOnly ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200'}`}
                 >
                    <ImageIcon size={14} /> Diagrams
                 </button>
                 <button 
                   onClick={() => setIsShuffle(!isShuffle)}
                   className={`flex-1 py-3 rounded-xl border font-bold text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 transition-all ${isShuffle ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-200'}`}
                 >
                    <Shuffle size={14} /> Shuffle
                 </button>
              </div>

              {/* Start Button - Red */}
              <button 
                onClick={startSession}
                className="w-full py-4 bg-[#e11d48] hover:bg-rose-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-rose-200 transition-transform active:scale-95"
              >
                 Start Session
              </button>

           </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  // --- VIEW: PLAYING (The Exam Interface) ---
  if (view === 'playing') {
    return (
      <div className="h-full flex flex-col bg-[#f8fafc] overflow-hidden select-none lg:flex-row relative">

        {/* Sidebar: Question Palette */}
        <aside className={`fixed inset-y-0 left-0 z-50 w-72 bg-white border-r border-slate-200 transform transition-transform duration-300 lg:relative lg:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} flex flex-col shadow-2xl lg:shadow-none`}>
           <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <h3 className="font-black text-xs uppercase text-slate-600 tracking-widest flex items-center gap-2">
                <LayoutGrid size={14} /> Question Palette
              </h3>
              <button onClick={() => setIsSidebarOpen(false)} className="lg:hidden text-slate-400 hover:text-slate-600"><X size={20} /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-white">
              <div className="grid grid-cols-5 gap-2.5">
                 {questions.map((q, i) => {
                   let statusColor = "bg-white border-slate-200 text-slate-500 hover:border-blue-400";
                   if (currentQIndex === i) statusColor = "bg-blue-600 border-blue-600 text-white ring-2 ring-blue-100 shadow-md";
                   else if (q.isFlagged) statusColor = "bg-amber-50 border-amber-300 text-amber-600";
                   else if (q.userAnswer) statusColor = "bg-slate-100 border-slate-300 text-slate-700";

                   return (
                     <button 
                      key={i} 
                      onClick={() => { setCurrentQIndex(i); setImgError(false); }} 
                      className={`h-10 rounded-lg text-[10px] font-bold border transition-all flex items-center justify-center ${statusColor}`}
                     >
                       {i + 1}
                     </button>
                   );
                 })}
              </div>
           </div>

           <div className="p-6 border-t border-slate-100 bg-slate-50 space-y-3">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-blue-600 rounded"></div> Current
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-slate-200 rounded border border-slate-300"></div> Answered
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase tracking-wider">
                 <div className="w-3 h-3 bg-amber-50 border border-amber-300 rounded"></div> Flagged
              </div>
           </div>
        </aside>

        {/* Main Examination Area */}
        <div className="flex-1 flex flex-col min-w-0 relative h-full">

          {/* Top Bar */}
          <div className="bg-white border-b border-slate-200 px-6 h-16 flex justify-between items-center shrink-0 shadow-sm z-20">
             <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="lg:hidden p-2 text-slate-500 hover:bg-slate-100 rounded-lg"><List /></button>

             <div className="flex items-center gap-6">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider hidden sm:inline flex items-center gap-2">
                  <FileText size={14} /> Anatomy Final
                </span>
                <div className="h-4 w-px bg-slate-200 hidden sm:block"></div>
                {mode === 'exam' && (
                  <div className={`flex items-center gap-2 font-mono font-bold text-sm bg-slate-100 px-4 py-2 rounded-lg border border-slate-200 ${timeLeft < 300 ? 'text-rose-600 bg-rose-50 border-rose-200' : 'text-slate-700'}`}>
                     <Clock size={16} /> {formatTime(timeLeft)}
                  </div>
                )}
             </div>

             <button onClick={exitQuiz} className="px-4 py-2 text-[10px] font-bold bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-100 border border-rose-100 transition-colors uppercase tracking-widest flex items-center gap-2">
                <AlertCircle size={14} /> Abort Exam
             </button>
          </div>

          {/* Question Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar bg-[#f8fafc]">
             <div className="max-w-4xl mx-auto space-y-8 pb-20">
                {/* Question Card */}
                <div className="bg-white p-8 md:p-12 rounded-[1.5rem] border border-slate-200 shadow-sm relative">
                  <div className="absolute top-0 left-0 w-full h-1.5 bg-blue-600 rounded-t-[1.5rem]"></div>

                  <div className="flex justify-between items-start mb-8">
                     <div className="flex items-center gap-3">
                        <span className="text-3xl font-black text-slate-200">Q{currentQIndex + 1}</span>
                        <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-widest border border-slate-200">{currentQ?.data.category}</span>
                     </div>
                     <button 
                      onClick={() => setQuestions(prev => {
                         const copy = [...prev];
                         copy[currentQIndex].isFlagged = !copy[currentQIndex].isFlagged;
                         return copy;
                      })}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-lg transition-colors text-[10px] font-bold uppercase tracking-wider ${currentQ?.isFlagged ? 'text-amber-600 bg-amber-50 border border-amber-200' : 'text-slate-400 hover:bg-slate-50 border border-transparent'}`}
                     >
                        <Flag size={14} fill={currentQ?.isFlagged ? "currentColor" : "none"} /> {currentQ?.isFlagged ? 'Flagged' : 'Flag Question'}
                     </button>
                  </div>

                  <div className="prose prose-lg max-w-none mb-10">
                     <h3 className="text-xl md:text-2xl font-bold text-slate-800 leading-normal" dangerouslySetInnerHTML={{ __html: currentQ?.data.questionText || '' }} />
                  </div>

                  {currentQ?.data.questionImage && !imgError && (
                    <div className="mb-10 w-full bg-slate-50 rounded-2xl border border-slate-200 overflow-hidden flex flex-col group">
                       <div className="p-3 border-b border-slate-200 bg-white flex items-center gap-2">
                          <ImageIcon size={16} className="text-slate-400" />
                          <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Clinical Exhibit</span>
                       </div>
                       <div className="p-8 flex items-center justify-center bg-white relative">
                          <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-h-[500px] w-auto object-contain rounded transition-transform duration-500 group-hover:scale-[1.01]" 
                            onError={() => setImgError(true)} 
                            alt="Question Reference" 
                            referrerPolicy="no-referrer"
                          />
                       </div>
                    </div>
                  )}

                  <div className="space-y-3">
                     {currentQ?.options.map((opt, i) => {
                       const isSelected = currentQ.userAnswer === opt;
                       return (
                         <button 
                          key={i} 
                          onClick={() => setQuestions(prev => { const c = [...prev]; c[currentQIndex].userAnswer = opt; return c; })} 
                          className={`w-full text-left p-5 rounded-xl border-2 transition-all flex items-center gap-5 group ${isSelected ? 'border-blue-500 bg-blue-50/30 shadow-md ring-1 ring-blue-500' : 'border-slate-100 hover:border-slate-300 hover:bg-slate-50'}`}
                         >
                           <div className={`w-8 h-8 rounded-lg border-2 flex items-center justify-center shrink-0 font-bold text-sm ${isSelected ? 'border-blue-500 bg-blue-600 text-white' : 'border-slate-200 text-slate-300 bg-white group-hover:border-slate-300'}`}>
                              {String.fromCharCode(65 + i)}
                           </div>
                           <span className={`text-base font-medium leading-snug ${isSelected ? 'text-blue-900' : 'text-slate-700'}`} dangerouslySetInnerHTML={{ __html: opt }} />
                         </button>
                       );
                     })}
                  </div>
                </div>
             </div>
          </div>

          {/* Footer Navigation */}
          <div className="bg-white border-t border-slate-200 p-4 md:px-10 h-20 flex justify-between items-center shrink-0 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
             <button 
              onClick={() => { setCurrentQIndex(prev => Math.max(0, prev - 1)); setImgError(false); }} 
              disabled={currentQIndex === 0} 
              className="px-6 py-3 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-all flex items-center gap-2"
             >
               <ChevronLeft size={16} /> Previous
             </button>

             <div className="hidden md:block text-xs font-bold text-slate-400 uppercase tracking-widest">
                Question {currentQIndex + 1} of {questions.length}
             </div>

             <button 
              onClick={() => { if(currentQIndex === questions.length - 1) handleFinish(); else { setCurrentQIndex(prev => prev + 1); setImgError(false); } }} 
              className={`px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest text-white shadow-lg transition-all flex items-center gap-2 hover:-translate-y-0.5 active:translate-y-0 ${currentQIndex === questions.length - 1 ? 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
             >
                {currentQIndex === questions.length - 1 ? 'Submit Assessment' : 'Next Question'} <ChevronRight size={16} />
             </button>
          </div>
        </div>
      </div>
    );
  }

  // --- VIEW: RESULTS (Scorecard) ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const percentage = Math.round((score / questions.length) * 100);

    return (
      <div className="h-full flex flex-col items-center justify-center p-8 bg-slate-50">
        <div className="bg-white rounded-[2rem] p-12 shadow-2xl border border-slate-200 text-center max-w-lg w-full space-y-8 animate-in zoom-in-95 duration-500">
           <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 border-8 border-slate-100 relative">
              <svg className="absolute inset-0 w-full h-full -rotate-90" viewBox="0 0 100 100">
                 <circle cx="50" cy="50" r="45" fill="none" stroke="#e2e8f0" strokeWidth="8" />
                 <circle cx="50" cy="50" r="45" fill="none" stroke={percentage >= 70 ? "#10b981" : "#f43f5e"} strokeWidth="8" strokeDasharray="283" strokeDashoffset={283 - (283 * percentage) / 100} className="transition-all duration-1000 ease-out" />
              </svg>
              <span className={`text-4xl font-black relative z-10 ${percentage >= 70 ? 'text-emerald-500' : 'text-rose-500'}`}>{percentage}%</span>
           </div>

           <div className="space-y-3">
             <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Assessment Complete</h2>
             <div className="flex justify-center gap-4 text-sm font-medium text-slate-500">
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Score</span>
                   <span className="text-lg font-bold text-slate-900">{score}/{questions.length}</span>
                </span>
                <span className="flex flex-col items-center p-3 bg-slate-50 rounded-xl min-w-[80px]">
                   <span className="text-xs uppercase tracking-widest text-slate-400">Grade</span>
                   <span className={`text-lg font-bold ${percentage >= 60 ? 'text-emerald-600' : 'text-rose-600'}`}>{percentage >= 90 ? 'A' : percentage >= 80 ? 'B' : percentage >= 70 ? 'C' : percentage >= 60 ? 'D' : 'F'}</span>
                </span>
             </div>
           </div>

           <div className="flex gap-4 pt-6">
             <button onClick={() => setView('setup')} className="flex-1 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest transition-all">Exit Portal</button>
             <button onClick={() => { setView('review'); toggleHeader?.(false); }} className="flex-1 py-4 bg-slate-900 hover:bg-blue-600 text-white rounded-xl font-bold uppercase text-xs tracking-widest transition-all shadow-lg hover:-translate-y-1">Review Answers</button>
           </div>
        </div>
      </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
    return (
      <div className="h-full bg-slate-50 p-8 overflow-y-auto custom-scrollbar">
        <div className="max-w-4xl mx-auto space-y-6 pb-32">
          <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-30">
            <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
               <FileText className="text-slate-400" /> Exam Audit
            </h2>
            <button onClick={() => { setView('results'); toggleHeader?.(true); }} className="px-6 py-2 bg-slate-100 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-200 text-slate-600 transition-colors">Return to Results</button>
          </div>
          {questions.map((q, i) => (
            <div key={i} className={`p-8 rounded-2xl bg-white border-l-4 shadow-sm ${q.userAnswer === q.correctOption ? 'border-l-emerald-500' : 'border-l-rose-500'}`}>
               <div className="flex gap-4 mb-4">
                 <span className="font-mono text-slate-400 font-bold">Q{i+1}.</span>
                 <div className="flex-1 space-y-4">
                   <h3 className="font-bold text-slate-800 text-lg leading-snug" dangerouslySetInnerHTML={{__html: q.data.questionText}} />
                   {q.data.questionImage && (
                      <div className="p-4 bg-slate-50 border border-slate-100 rounded-xl w-fit">
                         <img src={cleanImageUrl(q.data.questionImage)} className="max-h-48 rounded" referrerPolicy="no-referrer" alt="Ref" />
                      </div>
                   )}
                 </div>
               </div>
               <div className="pl-10 space-y-2 text-sm">
                 <div className="flex justify-between p-3 rounded-lg bg-slate-50">
                   <span className="font-bold text-slate-500">Your Answer:</span>
                   <span className={`font-bold ${q.userAnswer === q.correctOption ? 'text-emerald-600' : 'text-rose-600'}`} dangerouslySetInnerHTML={{__html: q.userAnswer || 'No Selection'}} />
                 </div>
                 {q.userAnswer !== q.correctOption && (
                   <div className="flex justify-between p-3 rounded-lg bg-emerald-50 border border-emerald-100">
                     <span className="font-bold text-emerald-700">Correct Answer:</span>
                     <span className="font-bold text-emerald-700" dangerouslySetInnerHTML={{__html: q.correctOption}} />
                   </div>
                 )}
               </div>
            </div>
          ))}
        </div>
      </div>
    )
  }

  return null;
};

