/**
 * @param {string} prompt
 * @param {string} prevSummary
 */
const summarizeThoughts = (prompt, prevSummary) => {
  const thoughts = prompt;
  let header;
  let summary = "";

  if (prevSummary) {
    summary = prevSummary;
  }

  // Extract the header from the prompt (assumes it's the first line)
  const headerMatch = thoughts.match(/^\*\*([A-Za-z ]+)\*\*$/m);
  if (headerMatch) {
    header = headerMatch[1].trim();

    // Extract the content after the header and before the "Thoughts:" marker
    const contentMatch = thoughts.match(/^\*\*([A-Za-z ]+)\*\*\n\n([\s\S]*?)[\s]*Thoughts:$/m);
    if (contentMatch) {
      const extractedContent = contentMatch[2].trim();
      summary += extractedContent;

    } else {
      console.error("Invalid input format: No content found.");
      return prevSummary;
    }
  } else {
    console.error("Invalid input format: No header found.");
    return prevSummary;
  }

  // Prevent repeated headers
  if (prevSummary && prevSummary.includes(`**${header}**`)) {
    return prevSummary;
  }

  // Format the header and the summary
  const formattedSummary = `**${header}**\n\n${summary}`;

  return formattedSummary;
};
```


