        <button onClick={() => { setIsFlipped(false); setImgError(false); setCurrentIndex(prev => Math.min(filteredData.length - 1, prev + 1)); }} disabled={currentIndex === filteredData.length - 1 || filteredData.length === 0} className="h-14 w-14 md:h-16 md:w-16 rounded-3xl bg-white border border-slate-200 flex items-center justify-center text-slate-400 hover:text-rose-600 disabled:opacity-30 transition-all shadow-md active:scale-95"><ChevronRight size={28} /></button>
